358		private static void LoadToMainMenuOnFadeEnd()
359		{
360			GameInput.DisableInput = false;
361			FadeManager instance = FadeManager.Instance;
362			instance.OnFadeEnded = (SDK.FadeManager.OnFadeEnd)Delegate.Remove(instance.OnFadeEnded, new SDK.FadeManager.OnFadeEnd(LoadToMainMenuOnFadeEnd));
