374			}
375			if (fadeOut)
376			{
377				FadeManager.Instance.FadeMusic = true;
378				FadeManager.Instance.FadeAudio = true;
379				FadeManager.Instance.FadeToBlack(SDK.FadeManager.FadeType.AreaTransition, 0.35f);
380				FadeManager instance = FadeManager.Instance;
381				instance.OnFadeEnded = (SDK.FadeManager.OnFadeEnd)Delegate.Combine(instance.OnFadeEnded, new SDK.FadeManager.OnFadeEnd(LoadToMainMenuOnFadeEnd));
382				GameInput.DisableInput = true;
383			}
384			else
385			{
386				LoadToMainMenuOnFadeEnd();
