395		private static void EndGameLoadingDone()
396		{
397			try
398			{
399				if (GlobalVariables.Instance == null || GlobalVariables.Instance.GetVariable("Act1_Gameover") != 1)
400				{
401					SDK.GameState.GameComplete = true;
402					if (!GameResources.SaveGame(UISaveLoadManager.GetGameCompleteSaveFileName()))
403					{
404						Debug.LogWarning("Unable to create end of game save");
405					}
406				}
407			}
408			finally
409			{
410				SDK.GameState.GameComplete = false;
411			}
412			UIMainMenuManager.s_performCleanup = true;
413			SDK.GameState.CleanupPersistAcrossSceneLoadObjects();
414			UILoadingScreen.LoadLevelAndHide("Credits");
415		}
