507		public Region GetCurrentRegionByStrongholdLocation(Stronghold.PillarLocation location)
508		{
509			List<Region> allRegions = WorldMap.Instance.AllRegions;
510			for (int i = 0; i < allRegions.Count; i++)
511			{
512				if ((location == Stronghold.PillarLocation.StoneSea1 || location == Stronghold.PillarLocation.StoneSea2) && (allRegions[i].PillarLocationParent == Stronghold.PillarLocation.StoneSea1 || allRegions[i].PillarLocationParent == Stronghold.PillarLocation.StoneSea2))
513				{
514					return allRegions[i];
515				}
516				if (allRegions[i].PillarLocationParent == location)
517				{
518					return allRegions[i];
519				}
520			}
521			return null;
522		}
