687		private void Update()
688		{
689			if (m_PerformPreloads)
690			{
691				m_PerformPreloads = false;
692				if (Application.isPlaying)
693				{
694					StartCoroutine(SDK.GameState.Coroutine_AsyncLoadInGameGlobalResource());
695					StartCoroutine(Coroutine_AsyncLoadClassBasedInstructionSetsAsset());
696					StartCoroutine(Coroutine_AsyncLoadRecipes());
697				}
698			}
699			if (m_FirstUpdate)
700			{
701				m_FirstUpdate = false;
702				if (Application.isPlaying)
703				{
704					StartCoroutine(SaveGameInfo.Coroutine_WaitForGameStartThenStartLoadingThread());
705				}
706				SDK.GameState.Controls = MappedInput.DefaultMapping.Copy();
