1062		public static void AutoPause(AutoPauseOptions.PauseEvent evt, GameObject target, GameObject triggerer, GenericAbility ability = null)
1063		{
1064			if (SDK.GameState.PlayerSafeMode || GameInput.DisableInput || SDK.Cutscene.CutsceneActive || (evt != AutoPauseOptions.PauseEvent.CombatTimer && evt != AutoPauseOptions.PauseEvent.CombatStart && (target == null || (evt != AutoPauseOptions.PauseEvent.EnemySpotted && evt != AutoPauseOptions.PauseEvent.SpellCast && target.GetComponent<PartyMemberAI>() == null))))
1065			{
1066				return;
1067			}
1068			if (Option.AutoPause.IsSlowEventSet(evt))
1069			{
1070				TimeController.Instance.Slow = true;
1071			}
1072			if (!Option.AutoPause.IsEventSet(evt))
1073			{
1074				return;
1075			}
1076			if (!SDK.GameState.Paused && Option.AutoPause.CenterOnCharacter)
1077			{
1078				CameraControl component = Camera.main.GetComponent<CameraControl>();
1079				if (component != null && target != null)
1080				{
1081					Vector3 vector = target.transform.position;
1082					if ((bool)triggerer)
1083					{
1084						Vector3 vector2 = triggerer.transform.position - vector;
1085						float num = vector2.magnitude * 0.85f;
1086						vector2.Normalize();
1087						vector = vector2 * num + target.transform.position;
1088					}
1089					component.FocusOnPoint(vector, 0.25f);
1090				}
1091			}
1092			if ((evt == AutoPauseOptions.PauseEvent.CombatStart && Option.AutoPause.EnteringCombatStopsMovement) || (evt == AutoPauseOptions.PauseEvent.EnemySpotted && Option.AutoPause.EnemySpottedStopMovement))
1093			{
1094				SDK.PartyMemberAI[] partyMembers = SDK.PartyMemberAI.PartyMembers;
1095				for (int i = 0; i < partyMembers.Length; i++)
1096				{
1097					PartyMemberAI partyMemberAI = (PartyMemberAI)partyMembers[i];
1098					if (!(partyMemberAI == null))
1099					{
1100						partyMemberAI.StateManager.ClearQueuedStates();
1101						if (partyMemberAI.IsMoving())
1102						{
1103							partyMemberAI.StateManager.PopCurrentState();
1104						}
1105					}
1106				}
1107			}
1108			TimeController.Instance.SafePaused = true;
1109			Console.AddMessage(AutoPauseOptions.GetResponseString(evt, target, ability), Color.red);
1110		}
