1284			SDK.GameState.IsRestoredLevel = File.Exists(levelFilePath);
1285			bool loadFromSaveFile = true;
1286			Instance.StartCoroutine(GameResources.Coroutine_LoadScene(map, currentRegionName, loadFromSaveFile));
1287		}
