1289		public void ProcessPersistenceData()
1290		{
1291			MapData mapData = null;
1292			GetCurrentMap(ref mapData);
1293			MapData currentNextMap = GetCurrentNextMap();
1294			SetLastMap(mapData);
1295			SetCurrentMap(currentNextMap);
1296			GetCurrentMap(ref mapData);
1297			if (mapData == null || (!mapData.IsStronghold && mapData.DisplayName.StringID < 0 && !mapData.IsInstance))
1298			{
1299				if (WorldMap.Instance != null)
1300				{
1301					SetCurrentMap(WorldMap.Instance.GetMap(SDK.GameState.LoadedLevelName));
1302				}
1303				else
1304				{
1305					SetCurrentMap(WorldMap.Maps.GetMap(SDK.GameState.LoadedLevelName));
1306				}
1307			}
1308			GetCurrentMap(ref mapData);
1309			if (mapData != null && mapData.IsStronghold)
1310			{
1311				StrongholdUpgrade majorUpgradeAtPillar = Stronghold.Instance.GetMajorUpgradeAtPillar(mapData.Location);
1312				if (majorUpgradeAtPillar != null)
1313				{
1314					TelemetryManager.Instance.QueueEvent_SkyPillarUpgradeVisited(SDK.TelemetryManager.Destination.Developer | SDK.TelemetryManager.Destination.Publisher, mapData.Location, majorUpgradeAtPillar.UpgradeType);
1315				}
1316			}
1317			MapData lastMap = GetLastMap();
1318			if (lastMap != null)
1319			{
1320				CouldCampOnLastMap = lastMap.CanCamp;
1321			}
1322			else
1323			{
1324				CouldCampOnLastMap = true;
1325			}
1326			try
1327			{
1328				if (SDK.GameState.s_firstLoad)
1329				{
1330					PersistenceManager.ClearTempData();
1331					PersistenceManager.LevelLoaded();
1332					SDK.GameState.s_firstLoad = false;
1333				}
1334				else
1335				{
1336					PersistenceManager.LevelLoaded();
1337					FogOfWar.Load();
1338				}
1339				if (CurrentRegion != null && (lastMap == null || !CurrentRegion.Equals(lastMap.region)) && CurrentRegion != null)
1340				{
1341					StartCoroutine(WaitForPartySpawnThenActivateEdict());
1342				}
1343				if (CurrentRegion != null && lastMap == null && ContentUnlockTracker.Instance != null)
1344				{
1345					ContentUnlockTracker.Instance.HandleAnniversaryGifts();
1346				}
1347			}
1348			catch (Exception ex)
1349			{
1350				Debug.LogError("GameState:ProcessPersistenceData() - " + ex.ToString());
1351				Instance.ReturnToMainMenuFromError();
1352			}
1353		}
