1356		{
1357			while (SDK.GameState.IsTransitionInProgress && !SDK.StartPoint.PartySpawned)
1358			{
1359				yield return null;
1360			}
1361			Edict edict = EdictManager.Instance.GetActiveEdict(CurrentRegion);
1362			if (edict != null)
1363			{
1364				edict.Activate();
1365			}
1366		}
