1368		public void FinalizeLevelLoad()
1369		{
1370			SDK.GameState.OnLevelLoadedEarly(SDK.GameState.LoadedLevelName, EventArgs.Empty);
1371			s_sentOnLevelLoadedEarly = true;
1372			SDK.GameState.OnLevelLoaded(SDK.GameState.LoadedLevelName, EventArgs.Empty);
1373			s_sentOnLevelLoaded = true;
1374			ScriptEvent.BroadcastEvent(ScriptEvent.ScriptEvents.OnLevelLoaded);
1375			SDK.GameState.OnLevelLoadedLate(SDK.GameState.LoadedLevelName, EventArgs.Empty);
1376			s_sentOnLevelLoadedLate = true;
1377			MapData currentMap = GetCurrentMap();
1378			if (SDK.GameState.NewGame)
1379			{
1380				if ((bool)WorldMap.Instance)
1381				{
1382					WorldMap.Instance.InitMapsFromList(force: true);
1383				}
1384				if (SDK.GameState.FirstPlaythrough && GlobalVariables.Instance != null)
1385				{
1386					GlobalVariables.Instance.SetVariable("tel_first_playthrough", 1);
1387					SDK.GameState.FirstPlaythrough = false;
1388				}
1389				TelemetryManager.Instance.QueueEvent_PlaySessionStarted(SDK.TelemetryManager.Destination.Developer | SDK.TelemetryManager.Destination.Publisher, bNewGame: true);
1390			}
1391			else if (SDK.GameState.LoadedGame)
1392			{
1393				MapType mapTypeFromData = WorldMap.Maps.GetMapTypeFromData(currentMap);
1394				if (CurrentMapIsStronghold && mapTypeFromData == MapType.AR_0002_SkyPillar_Empty)
1395				{
1396					UIWorldMapIconTravelBase lastMapIcon = UIWorldMapManager.Instance.GetLastMapIcon();
1397					if ((bool)lastMapIcon)
1398					{
1399						MapData mapData = lastMapIcon.GetMapData();
1400						if (mapData != null)
1401						{
1402							Instance.SetLastMap(currentMap);
1403							SetCurrentMap(lastMapIcon.GetMapData());
1404							currentMap = GetCurrentMap();
1405						}
1406					}
1407				}
1408				if ((bool)OnlineServicesManager.Instance)
1409				{
1410					OnlineServicesManager.Instance.PerformParadoxAccountRewards();
1411				}
1412				TelemetryManager.Instance.QueueEvent_PlaySessionStarted(SDK.TelemetryManager.Destination.Developer | SDK.TelemetryManager.Destination.Publisher, bNewGame: false);
1413			}
1414			SyncCameraOrthoSettings.Instance.SetZoomLevelDelta(0f);
1415			CameraControl.Instance.FocusOnPlayer();
1416			SDK.GameState.IsLoading = false;
1417			if (s_playerCharacter != null && !SDK.GameState.LoadedGame && !SDK.GameState.NewGame && SDK.GameState.NumSceneLoads > 0)
1418			{
1419				if ((bool)FogOfWar.Instance)
1420				{
1421					FogOfWar.Instance.WaitForFogUpdate();
1422				}
1423				PE_StreamTileManager.Instance.DoUpdate();
1424				Autosave();
1425			}
1426			SDK.GameState.NewGame = false;
1427			SetGameModeAchievementStats();
1428			if (currentMap != null && CouldCampOnLastMap != currentMap.CanCamp && !Option.GetOption(GameOption.BoolOption.DONT_RESTRICT_STASH))
1429			{
1430				if (currentMap.CanCamp)
1431				{
1432					UISystemMessager.Instance.PostMessage(SDK.GUIUtils.GetText(1391), Color.white);
1433				}
1434				else
1435				{
1436					UISystemMessager.Instance.PostMessage(SDK.GUIUtils.GetText(1392), Color.white);
1437				}
1438			}
1439			SDK.GameState.NumSceneLoads++;
1440			GammaCamera.CreateCamera();
1441			if (currentMap != null && !currentMap.HasBeenVisited && (bool)BonusXpManager.Instance && currentMap.GivesExplorationXp)
1442			{
1443				currentMap.HasBeenVisited = true;
1444				int num = 0;
1445				if (BonusXpManager.Instance != null)
1446				{
1447					num = BonusXpManager.Instance.MapExplorationXp;
1448				}
1449				if (num > 0)
1450				{
1451					Console.AddMessage("[" + NGUITools.EncodeColor(Color.yellow) + "]" + Console.Format(GUIUtils.GetTextWithLinks(1314), currentMap.DisplayName, num * PartyHelper.NumPartyMembers));
1452					PartyHelper.AssignXPToParty(num, printMessage: false);
1453				}
1454			}
1455			WinCursor.Clip(state: true);
1456		}
