using System;
using System.Collections;
using System.Collections.Generic;
using System.ComponentModel;
using System.IO;
using AI.Plan;
using OEICommon;
using SDK;
using UnityEngine;
using UnityEngine.SceneManagement;

namespace Game;

public class GameState : SDK.GameState
{
	private const float QUEUE_SHOW_CURSOR_DURATION = 0.35f;

	private const float QUEUE_HIDE_CURSOR_DURATION = 0.1f;

	private const int END_COMBAT_SAVE_FRAME_WAIT_TIME = 10;

	private const int END_COMBAT_TRAVEL_FRAME_WAIT_TIME = 10;

	private const int RenderContextCheckFrameCount = 10;

	public static UnityEngine.Object[] s_preloadedRecipes;

	public static UnityEngine.Object s_preloadedClassBasedInstructionSetsAsset;

	public static Action<Player> OnBeforePlayerChanged;

	private static Stronghold m_stronghold;

	private static GameObject s_scriptedInteractionUser;

	public static GameMode Mode;

	private string m_NewGamePlusSaveFilepath;

	private static float s_queueHideCursorTimer;

	private static float s_queueShowCursorTimer;

	private static int s_noSaveInCombatCountdown;

	private static bool s_isInTrapTriggeredCombat;

	private static float s_outOfCombatTimer;

	private static float s_inCombatTimer;

	private static int s_outOfCombatTravelFrameTimer;

	private static float s_combatPauseTimer;

	private static float s_deadTimer;

	private static bool s_inRestMode;

	public static bool ShowDebug;

	public static bool s_sentOnLevelLoadedEarly;

	public static bool s_sentOnLevelLoaded;

	public static bool s_sentOnLevelLoadedLate;

	private static string s_combatCause;

	private static RenderTexture m_renderContextChecker;

	private bool m_renderTextureCreatedOnce;

	private int m_renderContextCheckWait = -1;

	private MapData m_currentNextMap;

	private MapData m_currentMap;

	private MapData m_lastMap;

	private static Belief m_playerBelief;

	private bool m_FirstUpdate = true;

	private bool m_PerformPreloads;

	public new static Player s_playerCharacter
	{
		get
		{
			return SDK.GameState.s_playerCharacter as Player;
		}
		set
		{
			if (SDK.GameState.s_playerCharacter != null && OnBeforePlayerChanged != null)
			{
				OnBeforePlayerChanged(SDK.GameState.s_playerCharacter as Player);
			}
			SDK.GameState.s_playerCharacter = value;
			if (value != null)
			{
				SDK.GameState.s_playerCharacterFaction = value.GetComponent<Faction>();
			}
			OnPlayerCharacterChanged(value, EventArgs.Empty);
		}
	}

	public static Stronghold Stronghold
	{
		get
		{
			if (!m_stronghold)
			{
				m_stronghold = UnityEngine.Object.FindObjectOfType<Stronghold>();
			}
			return m_stronghold;
		}
	}

	public static GameObject LastPersonToUseScriptedInteraction
	{
		get
		{
			return s_scriptedInteractionUser;
		}
		set
		{
			s_scriptedInteractionUser = value;
		}
	}

	public static GameMode Option => Mode;

	[Persistent]
	public override GameDifficulty Difficulty
	{
		get
		{
			return Mode.Difficulty;
		}
		set
		{
			if (Mode.Difficulty != value)
			{
				if (SDK.GameState.DifficultyWillChange != null)
				{
					SDK.GameState.DifficultyWillChange(value);
				}
				Debug.Log(string.Concat("GameState: Difficulty being changed: [", Mode.Difficulty, "] -> [", value, "]"));
				Mode.Difficulty = value;
				if (SDK.GameState.DifficultyChanged != null)
				{
					SDK.GameState.DifficultyChanged(value);
				}
			}
			if ((bool)GlobalVariables.Instance)
			{
				GlobalVariables.Instance.SetVariable("_g_Difficulty", (int)Mode.Difficulty);
			}
		}
	}

	[Persistent]
	public bool TrialOfIron
	{
		get
		{
			return Mode.TrialOfIron;
		}
		set
		{
			Mode.TrialOfIron = value;
		}
	}

	[Persistent]
	public bool ExpertMode
	{
		get
		{
			return Mode.Expert;
		}
		set
		{
			Mode.Expert = value;
		}
	}

	public string NewGamePlusSaveFilepath
	{
		get
		{
			return m_NewGamePlusSaveFilepath;
		}
		set
		{
			m_NewGamePlusSaveFilepath = value;
		}
	}

	[DefaultValue(false)]
	[Persistent]
	public bool UiWorldMapTutorialFinished { get; set; }

	[DefaultValue(false)]
	public static bool ForceCombatMode { get; set; }

	public bool CouldCampOnLastMap { get; private set; }

	public Region CurrentRegion
	{
		get
		{
			MapData currentMap = GetCurrentMap();
			if (currentMap != null && currentMap.IsStronghold)
			{
				return GetCurrentRegionByStrongholdLocation(currentMap.Location);
			}
			return (!(currentMap == null)) ? currentMap.region : null;
		}
	}

	public static Belief PlayerBelief
	{
		get
		{
			if (!m_playerBelief && (bool)s_playerCharacter)
			{
				m_playerBelief = s_playerCharacter.GetComponent<Belief>();
			}
			return m_playerBelief;
		}
	}

	public bool CurrentMapIsStronghold
	{
		get
		{
			MapData currentMap = GetCurrentMap();
			return currentMap != null && currentMap.IsStronghold;
		}
	}

	public Stronghold.PillarLocation CurrentMapPillarLocation
	{
		get
		{
			MapData currentMap = GetCurrentMap();
			if (currentMap != null && currentMap.IsStronghold)
			{
				return currentMap.Location;
			}
			return Stronghold.PillarLocation.Count;
		}
	}

	public new static GameState Instance => SDK.GameState.s_instance as GameState;

	public static bool CannotSaveBecauseInCombat => SDK.GameState.s_isInCombat || s_noSaveInCombatCountdown > 0;

	public static bool CannotTravelBecauseInCombat => SDK.GameState.s_isInCombat || s_outOfCombatTravelFrameTimer > 0;

	public static bool IsInTrapTriggeredCombat => s_isInTrapTriggeredCombat;

	public static float InCombatDuration => s_inCombatTimer;

	public static bool CutsceneAllowed => !SDK.GameState.PartyDead && !SDK.GameState.GameOver;

	public static event EventHandler PlayerCharacterChanged;

	static GameState()
	{
		s_preloadedRecipes = null;
		s_preloadedClassBasedInstructionSetsAsset = null;
		s_scriptedInteractionUser = null;
		Mode = new GameMode();
		s_queueHideCursorTimer = 0f;
		s_queueShowCursorTimer = 0f;
		s_noSaveInCombatCountdown = 0;
		s_isInTrapTriggeredCombat = false;
		s_outOfCombatTimer = 0f;
		s_inCombatTimer = 0f;
		s_outOfCombatTravelFrameTimer = 0;
		s_combatPauseTimer = 0f;
		s_deadTimer = 0f;
		s_inRestMode = false;
		ShowDebug = false;
		s_sentOnLevelLoadedEarly = false;
		s_sentOnLevelLoaded = false;
		s_sentOnLevelLoadedLate = false;
		s_combatCause = "unknown";
		SDK.PartyMemberAI.MAX_PRIMARY_PARTY_MEMBERS = 4;
		SDK.PartyMemberAI.MAX_SECONDARY_SLOTS = 4;
		SDK.PartyMemberAI.AllocSelectedPartyMembersLists();
		SDK.PartyMemberAI.PartyMembers = new PartyMemberAI[SDK.PartyMemberAI.MAX_PARTY_MEMBERS];
	}

	public bool UsingValidNewGamePlusImport()
	{
		return !string.IsNullOrEmpty(m_NewGamePlusSaveFilepath) && SDK.GameResources.SaveFileExists(Instance.m_NewGamePlusSaveFilepath);
	}

	public bool HaveValidLegacyReputationImports()
	{
		return (bool)s_playerCharacter && s_playerCharacter.m_importedReputationAbilities.Count > 0;
	}

	public bool HasAvailableLegacyReputationImports()
	{
		int num = Mathf.Max(2 + Instance.GetNewGamePlusIteration() - 1 - s_playerCharacter.m_selectedImportedReputationAbilities.Count);
		return num > 0;
	}

	private void SetGameModeAchievementStats()
	{
		if ((bool)AchievementTracker.Instance)
		{
			AchievementTracker.Instance.ForceSetTrackedStat(AchievementTracker.TrackedAchievementStat.PathOfTheDamnedOn, (Difficulty == GameDifficulty.PathOfTheDamned) ? 1 : 0);
			AchievementTracker.Instance.ForceSetTrackedStat(AchievementTracker.TrackedAchievementStat.ExpertModeOn, ExpertMode ? 1 : 0);
			AchievementTracker.Instance.ForceSetTrackedStat(AchievementTracker.TrackedAchievementStat.TrialOfIronOn, TrialOfIron ? 1 : 0);
		}
	}

	public override int GetNewGamePlusIteration()
	{
		return NewGamePlusIteration + CommandLine.S_NGPLUS_ITERATION_OVERRIDE;
	}

	public bool IsRenderContextValid()
	{
		return m_renderContextChecker != null && m_renderContextChecker.IsCreated();
	}

	public static string GetDebugOutput()
	{
		string text = "-- Game State Debug --";
		text = text + "\nIn Combat: " + SDK.GameState.InCombat;
		text = text + "\nParty Dead: " + SDK.GameState.PartyDead;
		text = text + "\nForce Combat Mode: " + ForceCombatMode;
		text = text + "\nIs Restored Level: " + SDK.GameState.IsRestoredLevel;
		text = text + "\nGame Over: " + SDK.GameState.GameOver;
		text = text + "\nLoaded Game: " + SDK.GameState.LoadedGame;
		text = text + "\nPartyMemberAI.SafeEnableDisable: " + SDK.PartyMemberAI.SafeEnableDisable;
		text = text + "\nPlayer Safe Mode: " + SDK.GameState.PlayerSafeMode;
		return text + "\nGameInput.DisableInput: " + GameInput.DisableInput;
	}

	private void OnApplicationQuit()
	{
		if (CanTrialOfIronQuitSave())
		{
			TrialOfIronSave();
		}
		SaveGameInfo.CancelRunningThreads();
	}

	private static void LoadToMainMenuOnFadeEnd()
	{
		GameInput.DisableInput = false;
		FadeManager instance = FadeManager.Instance;
		instance.OnFadeEnded = (SDK.FadeManager.OnFadeEnd)Delegate.Remove(instance.OnFadeEnded, new SDK.FadeManager.OnFadeEnd(LoadToMainMenuOnFadeEnd));
		Debug.Log("\n");
		Debug.Log("------- LOAD TO MAIN MENU --------\n\n");
		UIMainMenuManager.s_performCleanup = true;
		SceneManager.LoadScene("MainMenu", LoadSceneMode.Single);
	}

	public static void LoadMainMenu(bool fadeOut)
	{
		if (CanTrialOfIronQuitSave())
		{
			TrialOfIronSave();
		}
		if (fadeOut)
		{
			FadeManager.Instance.FadeMusic = true;
			FadeManager.Instance.FadeAudio = true;
			FadeManager.Instance.FadeToBlack(SDK.FadeManager.FadeType.AreaTransition, 0.35f);
			FadeManager instance = FadeManager.Instance;
			instance.OnFadeEnded = (SDK.FadeManager.OnFadeEnd)Delegate.Combine(instance.OnFadeEnded, new SDK.FadeManager.OnFadeEnd(LoadToMainMenuOnFadeEnd));
			GameInput.DisableInput = true;
		}
		else
		{
			LoadToMainMenuOnFadeEnd();
		}
	}

	public static void EndGameAndLoadCredits()
	{
		UILoadingScreen.Show(MapData.LoadingScreenType.BlackOnly, EndGameLoadingDone);
	}

	private static void EndGameLoadingDone()
	{
		try
		{
			if (GlobalVariables.Instance == null || GlobalVariables.Instance.GetVariable("Act1_Gameover") != 1)
			{
				SDK.GameState.GameComplete = true;
				if (!GameResources.SaveGame(UISaveLoadManager.GetGameCompleteSaveFileName()))
				{
					Debug.LogWarning("Unable to create end of game save");
				}
			}
		}
		finally
		{
			SDK.GameState.GameComplete = false;
		}
		UIMainMenuManager.s_performCleanup = true;
		SDK.GameState.CleanupPersistAcrossSceneLoadObjects();
		UILoadingScreen.LoadLevelAndHide("Credits");
	}

	public static void Autosave()
	{
		if (Mode.TrialOfIron)
		{
			TrialOfIronSave();
		}
		else
		{
			GameResources.SaveGame(UISaveLoadManager.GetAutosaveFileName(s_playerCharacter.AdvanceAutoSaveNumber()));
		}
	}

	public static bool CanTrialOfIronQuitSave()
	{
		return (bool)InGameHUD.Instance && InGameHUD.Instance.QuicksaveAllowed && Mode != null && Mode.TrialOfIron && !SDK.GameState.s_gameOver;
	}

	public static void TrialOfIronSave()
	{
		string loadedFileName = SDK.GameState.LoadedFileName;
		string saveFileName = UISaveLoadManager.GetSaveFileName();
		if (GameResources.SaveGame(saveFileName, SDK.GUIUtils.GetText(3960)))
		{
			GameResources.WriteTrialOfIronReadme();
			if (!string.IsNullOrEmpty(loadedFileName) && !saveFileName.Equals(loadedFileName))
			{
				GameResources.DeleteSavedGame(loadedFileName, removeCloudSave: false);
			}
		}
	}

	public static void TrialOfIronDelete()
	{
		if (!string.IsNullOrEmpty(SDK.GameState.LoadedFileName) && Mode.TrialOfIron)
		{
			GameResources.DeleteSavedGame(SDK.GameState.LoadedFileName, removeCloudSave: true);
			SDK.GameState.LoadedFileName = string.Empty;
		}
	}

	public MapData GetCurrentNextMap()
	{
		return m_currentNextMap;
	}

	public void SetCurrentNextMap(MapData mapData)
	{
		m_currentNextMap = mapData;
	}

	public bool HasValidCurrentNextMap()
	{
		return m_currentNextMap != null;
	}

	public MapData GetCurrentMap()
	{
		return m_currentMap;
	}

	public void GetCurrentMap(ref MapData mapData)
	{
