	{
		List<Region> allRegions = WorldMap.Instance.AllRegions;
		for (int i = 0; i < allRegions.Count; i++)
		{
			if ((location == Stronghold.PillarLocation.StoneSea1 || location == Stronghold.PillarLocation.StoneSea2) && (allRegions[i].PillarLocationParent == Stronghold.PillarLocation.StoneSea1 || allRegions[i].PillarLocationParent == Stronghold.PillarLocation.StoneSea2))
