	private void Update()
	{
		if (m_PerformPreloads)
		{
			m_PerformPreloads = false;
			if (Application.isPlaying)
			{
				StartCoroutine(SDK.GameState.Coroutine_AsyncLoadInGameGlobalResource());
				StartCoroutine(Coroutine_AsyncLoadClassBasedInstructionSetsAsset());
				StartCoroutine(Coroutine_AsyncLoadRecipes());
			}
		}
		if (m_FirstUpdate)
		{
			m_FirstUpdate = false;
			if (Application.isPlaying)
			{
				StartCoroutine(SaveGameInfo.Coroutine_WaitForGameStartThenStartLoadingThread());
			}
			SDK.GameState.Controls = MappedInput.DefaultMapping.Copy();
			SDK.GameState.Controls.LoadFromPrefs();
			SDK.GameState.Controls.Restored();
			Mode.LoadFromPrefs();
			Mode.SaveToPrefs();
		}
		if (ShowDebug)
		{
			DrawDebugInfo();
		}
		if (!SDK.GameState.ApplicationIsFocused && Screen.fullScreen && TimeController.Instance != null && !UICharacterCreationManager.Instance)
		{
			TimeController.Instance.SafePaused = true;
		}
		if (m_renderTextureCreatedOnce)
		{
			bool flag = m_renderContextChecker.IsCreated();
			if (flag && m_renderContextCheckWait > 0)
			{
				Debug.Log("GameState Render Texture recreated frame count lost: " + m_renderContextCheckWait);
				if (m_renderContextCheckWait > 10)
				{
					Debug.Log("GameState Render Texture recreated, triggering event");
					SDK.GameState.TriggerOnDeviceRecreated();
				}
				m_renderContextCheckWait = 0;
			}
			else if (!flag)
			{
				m_renderContextChecker.Create();
				m_renderContextCheckWait++;
			}
		}
		else if (m_renderContextChecker.IsCreated())
		{
			Debug.Log("GameState RenderTexture created the first time");
			m_renderTextureCreatedOnce = true;
		}
		UpdateQueuedShowHideCursor();
		UpdateIsInCombatAndGameOver();
		PartyMemberAI.UpdateEnemySpottedTimer();
		SDK.GameUtilities.UpdateFadingEffects();
		if (Screen.fullScreen != Option.GetOption(GameOption.BoolOption.FULLSCREEN) && UIOptionsManager.Instance != null && !UIOptionsManager.Instance.IsVisible)
		{
			Option.SetOption(GameOption.BoolOption.FULLSCREEN, Screen.fullScreen);
			if ((bool)UIOptionsManager.Instance)
			{
				UIOptionsManager.Instance.ForceUpdateFullscreen();
			}
		}
	}

