	public static IEnumerator Coroutine_AsyncLoadClassBasedInstructionSetsAsset()
	{
		if (s_preloadedClassBasedInstructionSetsAsset != null)
		{
			yield break;
		}
		SDK.GameState.s_loadScreenWaitCount++;
		float startTime = Time.realtimeSinceStartup;
		Debug.Log("ASYNC LOADING CLASSBASEDINSTRUCTIONSETS");
		string assetPath = "assets/data/prefabs/lists/instruction sets/companions/classbasedinstructionsets.asset";
		AssetBundleRequestWrapper req = GameResources.LoadAssetAsync(assetPath, AssetBundleHint.Lists, instantiate: false);
		if (req.immediatelyAvailableAsset != null)
		{
			s_preloadedClassBasedInstructionSetsAsset = req.immediatelyAvailableAsset;
		}
		else if (req.loadRequest != null)
		{
			while (!req.loadRequest.isDone)
			{
				yield return null;
			}
			s_preloadedClassBasedInstructionSetsAsset = GameResources.LoadAssetFromAsyncRequest(assetPath, req.loadRequest, instantiate: false);
		}
		else
		{
			Debug.LogError("UNABLE TO ASYNC LOAD CLASSBASEDINSTRUCTIONSETS!");
			s_preloadedClassBasedInstructionSetsAsset = null;
		}
		Debug.Log("ASYNC LOADING OF CLASSBASEDINSTRUCTIONSETS COMPLETED. TOTAL TIME = " + (Time.realtimeSinceStartup - startTime) + " seconds.");
		SDK.GameState.s_loadScreenWaitCount--;
	}

	public static IEnumerator Coroutine_AsyncLoadRecipes()
	{
		if (s_preloadedRecipes == null)
		{
			AssetBundleManager.RefreshRecipeAssetBundle();
			SDK.GameState.s_loadScreenWaitCount++;
			float startTime = Time.realtimeSinceStartup;
			Debug.Log("ASYNC LOADING RECIPES");
			AssetBundleRequest request = AssetBundleManager.LoadAllAssetsFromBundleAsync(AssetBundleHint.Recipes);
			while (!request.isDone)
			{
				yield return null;
			}
			s_preloadedRecipes = request.allAssets;
			Debug.Log("ASYNC LOADING OF RECIPES COMPLETED. TOTAL TIME = " + (Time.realtimeSinceStartup - startTime) + " seconds.");
			SDK.GameState.s_loadScreenWaitCount--;
		}
	}

