	public void UpdateIsInCombatAndGameOver()
	{
		SDK.GameState.InstructionOverrideUpdateForced = true;
		if (ForceCombatMode)
		{
			s_combatCause = "force_combat_mode";
			SDK.GameState.s_isInCombat = true;
			SDK.Stealth.GlobalSetInStealthMode(inStealth: false);
		}
		else
		{
			if (SDK.GameState.IsTransitionInProgress)
			{
				return;
			}
			if (s_inRestMode)
			{
				SDK.GameState.OnResting(null, EventArgs.Empty);
				s_inRestMode = false;
			}
			else
			{
				if (SDK.GameState.Paused || s_playerCharacter == null)
				{
					return;
				}
				if (s_outOfCombatTimer > 0f)
				{
					s_outOfCombatTimer -= Time.deltaTime;
				}
				if (SDK.GameState.s_isInCombat && s_combatPauseTimer > 0f)
				{
					s_combatPauseTimer -= Time.deltaTime;
				}
				if (SDK.GameState.s_isInCombat && !SDK.GameState.Paused)
				{
					s_inCombatTimer += Time.deltaTime;
				}
				if (s_noSaveInCombatCountdown > 0)
				{
					s_noSaveInCombatCountdown--;
				}
				if (s_outOfCombatTravelFrameTimer > 0)
				{
					s_outOfCombatTravelFrameTimer--;
				}
				GameObject combatTarget = null;
				bool flag = SDK.GameState.s_isInCombat;
				bool flag2 = false;
				if (SDK.Faction.ActiveFactionComponents.Count == 0)
				{
					return;
				}
				for (int i = 0; i < SDK.Faction.ActiveFactionComponents.Count; i++)
				{
					SDK.Faction faction = SDK.Faction.ActiveFactionComponents[i];
					AIController[] components = faction.GetComponents<AIController>();
					foreach (AIController aIController in components)
					{
						if (!(aIController != null) || !aIController.enabled || !aIController.gameObject.activeInHierarchy || !aIController.InCombat)
						{
							continue;
						}
						bool flag3 = false;
						PartyMemberAI partyMemberAI = aIController as PartyMemberAI;
						if (aIController.MustDieForCombatToEnd || aIController.IsConfused || (partyMemberAI != null && partyMemberAI.IsActiveInParty))
						{
							flag3 = true;
						}
						else
						{
							GameObject currentTarget = aIController.StateManager.CurrentTarget;
							partyMemberAI = ((!currentTarget) ? null : currentTarget.GetComponent<PartyMemberAI>());
							if (currentTarget != null && partyMemberAI != null)
							{
								if (partyMemberAI.IsActiveInParty)
								{
									flag3 = true;
								}
							}
							else if (aIController.StateManager.SDKQueuedState is ApproachTarget approachTarget && approachTarget.CurrentTarget != null && approachTarget.CurrentTarget.GetComponent<PartyMemberAI>() != null)
							{
								flag3 = true;
							}
							else if (flag && FogOfWar.PointVisibleInFog(aIController.transform.position) && faction.IsHostile(SDK.GameState.s_playerCharacterFaction))
							{
								flag3 = true;
							}
						}
						if (flag3)
						{
							if (aIController is PartyMemberAI)
							{
								s_combatCause = ((!(aIController.CurrentTarget != null)) ? aIController.gameObject.name : aIController.CurrentTarget.name.ToLower());
							}
							else
							{
								s_combatCause = aIController.gameObject.name;
							}
							combatTarget = aIController.CurrentTarget;
							SDK.GameState.s_isInCombat = true;
							flag2 = true;
							s_outOfCombatTimer = StatsData.Instance.CombatEndDelay;
							break;
						}
					}
				}
				SDK.GameState.s_isInCombat = s_outOfCombatTimer > 0f;
				if (SDK.GameState.s_isInCombat && s_combatPauseTimer <= 0f)
				{
					AutoPause(AutoPauseOptions.PauseEvent.CombatTimer, null, null);
					s_combatPauseTimer = Option.AutoPause.CombatRoundTime;
				}
				if (SDK.GameState.s_isInCombat != flag || (flag2 && s_isInTrapTriggeredCombat))
				{
					s_inCombatTimer = 0f;
					if (SDK.GameState.s_isInCombat)
					{
						s_isInTrapTriggeredCombat = false;
						if (!s_isInTrapTriggeredCombat)
						{
							TutorialManager.STriggerTutorialsOfTypeFast(TutorialManager.ExclusiveTriggerType.COMBAT_START);
						}
						SDK.GameState.OnCombatStart(null, EventArgs.Empty);
						TelemetryManager.Instance.QueueEvent_CombatStarted(SDK.TelemetryManager.Destination.Developer | SDK.TelemetryManager.Destination.Publisher, s_combatCause);
						GlobalVariables.Instance.SetVariable("tel_attempted_combos_this_combat", 0);
						GlobalVariables.Instance.SetVariable("tel_successful_combos_this_combat", 0);
						if (s_playerCharacter != null)
						{
							s_playerCharacter.TryPlayPartySound(SoundSet.SoundAction.CombatBegin);
						}
						if (!s_isInTrapTriggeredCombat)
						{
							StartCoroutine(Coroutine_DelayCombatStartAutoPause(combatTarget));
						}
					}
					else
					{
						s_combatPauseTimer = 0f;
						s_noSaveInCombatCountdown = 10;
						s_outOfCombatTravelFrameTimer = 10;
						SDK.GameState.OnCombatEnd(null, EventArgs.Empty);
						TelemetryManager.Instance.QueueEvent_CombatEnded(SDK.TelemetryManager.Destination.Developer | SDK.TelemetryManager.Destination.Publisher);
						GlobalVariables.Instance.SetVariable("tel_attempted_combos_this_combat", 0);
						GlobalVariables.Instance.SetVariable("tel_successful_combos_this_combat", 0);
						if (s_playerCharacter != null)
						{
							s_playerCharacter.TryPlayPartySound(SoundSet.SoundAction.CombatEnds);
						}
						s_isInTrapTriggeredCombat = false;
						s_combatCause = "unknown";
					}
				}
				if (!SDK.GameState.s_gameOver && SDK.GameState.PartyDead)
				{
					SDK.GameState.s_gameOver = true;
					s_deadTimer = 2f;
				}
				if (SDK.GameState.s_gameOver && s_deadTimer > 0f)
				{
					s_deadTimer -= Time.deltaTime;
					if (s_deadTimer <= 0f)
					{
						s_deadTimer = 0f;
						UIDeathManager.Instance.ShowWindow();
					}
				}
				if (!SDK.GameState.s_isInCombat)
				{
					SDK.GameState.InstructionOverrideUpdateForced = false;
				}
			}
		}
	}

