	public static void ChangeLevel(MapType level)
	{
		if (level == MapType.Map)
		{
			Debug.LogError("Tried to transition to bad map. Did you forget to set a map in a dropdown?");
			return;
		}
		MapData mapData = null;
		for (int i = 0; i < WorldMap.Instance.LoadedMaps.Count; i++)
		{
			if (WorldMap.Instance.LoadedMaps[i].SceneName.Equals(level.ToString()))
			{
				mapData = WorldMap.Instance.LoadedMaps[i];
				break;
			}
		}
		if (mapData == null)
		{
			mapData = WorldMap.Instance.LoadedMaps[(int)level];
		}
		if (mapData.IsStronghold)
		{
			Debug.LogError("WARNING - Unable to use ChangeLevel(string/MapType) to transition to skypillar. Use Load Pillar Map(string) instead!!");
		}
		ChangeLevel(mapData);
	}

	public static void ChangeLevel(MapData map)
	{
		try
		{
			SDK.PartyMemberAI[] partyMembers = SDK.PartyMemberAI.PartyMembers;
			for (int i = 0; i < partyMembers.Length; i++)
			{
				PartyMemberAI partyMemberAI = (PartyMemberAI)partyMembers[i];
				if (!(partyMemberAI == null))
				{
					if (partyMemberAI.StateManager != null)
					{
						partyMemberAI.GameAIStateManager.CurrentState?.StopMover();
						partyMemberAI.StateManager.AbortStateStack();
					}
					Stealth component = partyMemberAI.GetComponent<Stealth>();
					if ((bool)component)
					{
						component.ClearAllSuspicion();
					}
				}
			}
			string currentRegionName = ((!(Instance.CurrentRegion != null)) ? "none" : Instance.CurrentRegion.Tag.ToLower());
			if (Instance.CurrentRegion != null && !Instance.CurrentRegion.Equals(map.region) && (bool)Instance.CurrentRegion)
			{
				Edict activeEdict = EdictManager.Instance.GetActiveEdict();
				if ((bool)activeEdict)
				{
					activeEdict.Deactivate();
				}
			}
			Instance.SetCurrentNextMap(map);
			SDK.StartPoint.ResetStartPoints();
			UIWindowManager.DisableWindowVisibilityHandling();
			BeginLevelUnload(map.SceneName);
			ConditionalToggleManager.Instance.ResetBetweenSceneLoads();
			PersistenceManager.SaveGame();
			FogOfWar.Save();
			SkirmishManager.Instance.TryCleanupPreviousSkirmish();
			string levelFilePath = PersistenceManager.GetLevelFilePath(map.SceneName);
			SDK.GameState.IsRestoredLevel = File.Exists(levelFilePath);
			UIWorldMapIcon uIWorldMapIcon = UIWorldMapManager.Instance.IconForScene(map);
			if ((bool)uIWorldMapIcon)
			{
				WorldMapDataManager.Instance.LastWorldMapIconGUID = uIWorldMapIcon.MapInstanceGUID.ToString();
				WorldMapEventManager.Instance.LastWorldMapIconGUID = uIWorldMapIcon.MapInstanceGUID.ToString();
			}
			if ((bool)GameUtilities.Instance)
			{
				bool loadFromSaveFile = false;
				GameUtilities.Instance.StartCoroutine(GameResources.Coroutine_LoadScene(map, currentRegionName, loadFromSaveFile));
			}
		}
		catch (Exception ex)
		{
			Debug.LogError(ex.ToString());
		}
		ScriptEvent.BroadcastEvent(ScriptEvent.ScriptEvents.OnSceneExited);
	}

	public override void ReturnToMainMenuFromError()
	{
		DestroyOnLevelLoad[] array = UnityEngine.Object.FindObjectsOfType<DestroyOnLevelLoad>();
		if (array != null)
		{
			DestroyOnLevelLoad[] array2 = array;
			foreach (DestroyOnLevelLoad destroyOnLevelLoad in array2)
			{
				destroyOnLevelLoad.InGameLevelOnly = false;
			}
		}
		Debug.Log("\n");
		Debug.Log("------- LOAD TO MAIN MENU --------\n\n");
		UIMainMenuManager.s_ReturningToMainMenuFromError = true;
		SceneManager.LoadScene("MainMenu", LoadSceneMode.Single);
	}

	public static bool LoadLevel(string level)
	{
		MapData mapData = null;
		mapData = ((!(WorldMap.Instance != null)) ? WorldMap.Maps.GetMap(level) : WorldMap.Instance.GetMap(level));
		if (mapData != null)
		{
			LoadLevel(mapData);
			return true;
		}
		Debug.LogError("Unable to find a map named " + level + ". Ensure it is contained in the AllMaps list.");
		return false;
	}

	public static void LoadLevel(MapData map)
	{
		SDK.StartPoint.ResetStartPoints();
		if ((bool)ConditionalToggleManager.Instance)
		{
			ConditionalToggleManager.Instance.ResetBetweenSceneLoads();
		}
		string currentRegionName = ((!(Instance.CurrentRegion != null)) ? "none" : Instance.CurrentRegion.Tag.ToLower());
		Instance.SetCurrentNextMap(map);
		SDK.GameState.s_firstLoad = false;
		string levelFilePath = PersistenceManager.GetLevelFilePath(map.SceneName);
		SDK.GameState.IsRestoredLevel = File.Exists(levelFilePath);
		bool loadFromSaveFile = true;
		Instance.StartCoroutine(GameResources.Coroutine_LoadScene(map, currentRegionName, loadFromSaveFile));
	}

	public void ProcessPersistenceData()
	{
		MapData mapData = null;
		GetCurrentMap(ref mapData);
		MapData currentNextMap = GetCurrentNextMap();
		SetLastMap(mapData);
		SetCurrentMap(currentNextMap);
		GetCurrentMap(ref mapData);
		if (mapData == null || (!mapData.IsStronghold && mapData.DisplayName.StringID < 0 && !mapData.IsInstance))
		{
			if (WorldMap.Instance != null)
			{
				SetCurrentMap(WorldMap.Instance.GetMap(SDK.GameState.LoadedLevelName));
			}
			else
			{
				SetCurrentMap(WorldMap.Maps.GetMap(SDK.GameState.LoadedLevelName));
			}
		}
		GetCurrentMap(ref mapData);
		if (mapData != null && mapData.IsStronghold)
		{
			StrongholdUpgrade majorUpgradeAtPillar = Stronghold.Instance.GetMajorUpgradeAtPillar(mapData.Location);
			if (majorUpgradeAtPillar != null)
			{
				TelemetryManager.Instance.QueueEvent_SkyPillarUpgradeVisited(SDK.TelemetryManager.Destination.Developer | SDK.TelemetryManager.Destination.Publisher, mapData.Location, majorUpgradeAtPillar.UpgradeType);
			}
		}
		MapData lastMap = GetLastMap();
		if (lastMap != null)
		{
			CouldCampOnLastMap = lastMap.CanCamp;
		}
		else
		{
			CouldCampOnLastMap = true;
		}
		try
		{
			if (SDK.GameState.s_firstLoad)
			{
				PersistenceManager.ClearTempData();
				PersistenceManager.LevelLoaded();
				SDK.GameState.s_firstLoad = false;
			}
			else
			{
				PersistenceManager.LevelLoaded();
				FogOfWar.Load();
			}
			if (CurrentRegion != null && (lastMap == null || !CurrentRegion.Equals(lastMap.region)) && CurrentRegion != null)
			{
				StartCoroutine(WaitForPartySpawnThenActivateEdict());
			}
			if (CurrentRegion != null && lastMap == null && ContentUnlockTracker.Instance != null)
			{
				ContentUnlockTracker.Instance.HandleAnniversaryGifts();
			}
		}
		catch (Exception ex)
		{
			Debug.LogError("GameState:ProcessPersistenceData() - " + ex.ToString());
			Instance.ReturnToMainMenuFromError();
		}
	}

	private IEnumerator WaitForPartySpawnThenActivateEdict()
	{
		while (SDK.GameState.IsTransitionInProgress && !SDK.StartPoint.PartySpawned)
		{
			yield return null;
		}
		Edict edict = EdictManager.Instance.GetActiveEdict(CurrentRegion);
		if (edict != null)
		{
			edict.Activate();
		}
	}

	public void FinalizeLevelLoad()
	{
		SDK.GameState.OnLevelLoadedEarly(SDK.GameState.LoadedLevelName, EventArgs.Empty);
		s_sentOnLevelLoadedEarly = true;
		SDK.GameState.OnLevelLoaded(SDK.GameState.LoadedLevelName, EventArgs.Empty);
		s_sentOnLevelLoaded = true;
		ScriptEvent.BroadcastEvent(ScriptEvent.ScriptEvents.OnLevelLoaded);
		SDK.GameState.OnLevelLoadedLate(SDK.GameState.LoadedLevelName, EventArgs.Empty);
		s_sentOnLevelLoadedLate = true;
		MapData currentMap = GetCurrentMap();
		if (SDK.GameState.NewGame)
		{
			if ((bool)WorldMap.Instance)
			{
				WorldMap.Instance.InitMapsFromList(force: true);
			}
			if (SDK.GameState.FirstPlaythrough && GlobalVariables.Instance != null)
			{
				GlobalVariables.Instance.SetVariable("tel_first_playthrough", 1);
				SDK.GameState.FirstPlaythrough = false;
			}
			TelemetryManager.Instance.QueueEvent_PlaySessionStarted(SDK.TelemetryManager.Destination.Developer | SDK.TelemetryManager.Destination.Publisher, bNewGame: true);
		}
		else if (SDK.GameState.LoadedGame)
		{
			MapType mapTypeFromData = WorldMap.Maps.GetMapTypeFromData(currentMap);
			if (CurrentMapIsStronghold && mapTypeFromData == MapType.AR_0002_SkyPillar_Empty)
			{
				UIWorldMapIconTravelBase lastMapIcon = UIWorldMapManager.Instance.GetLastMapIcon();
				if ((bool)lastMapIcon)
				{
					MapData mapData = lastMapIcon.GetMapData();
					if (mapData != null)
					{
						Instance.SetLastMap(currentMap);
						SetCurrentMap(lastMapIcon.GetMapData());
						currentMap = GetCurrentMap();
					}
				}
			}
			if ((bool)OnlineServicesManager.Instance)
			{
				OnlineServicesManager.Instance.PerformParadoxAccountRewards();
			}
			TelemetryManager.Instance.QueueEvent_PlaySessionStarted(SDK.TelemetryManager.Destination.Developer | SDK.TelemetryManager.Destination.Publisher, bNewGame: false);
		}
		SyncCameraOrthoSettings.Instance.SetZoomLevelDelta(0f);
		CameraControl.Instance.FocusOnPlayer();
		SDK.GameState.IsLoading = false;
		if (s_playerCharacter != null && !SDK.GameState.LoadedGame && !SDK.GameState.NewGame && SDK.GameState.NumSceneLoads > 0)
		{
			if ((bool)FogOfWar.Instance)
			{
				FogOfWar.Instance.WaitForFogUpdate();
			}
			PE_StreamTileManager.Instance.DoUpdate();
			Autosave();
		}
		SDK.GameState.NewGame = false;
		SetGameModeAchievementStats();
		if (currentMap != null && CouldCampOnLastMap != currentMap.CanCamp && !Option.GetOption(GameOption.BoolOption.DONT_RESTRICT_STASH))
		{
			if (currentMap.CanCamp)
			{
				UISystemMessager.Instance.PostMessage(SDK.GUIUtils.GetText(1391), Color.white);
			}
			else
			{
				UISystemMessager.Instance.PostMessage(SDK.GUIUtils.GetText(1392), Color.white);
			}
		}
		SDK.GameState.NumSceneLoads++;
		GammaCamera.CreateCamera();
		if (currentMap != null && !currentMap.HasBeenVisited && (bool)BonusXpManager.Instance && currentMap.GivesExplorationXp)
		{
			currentMap.HasBeenVisited = true;
			int num = 0;
			if (BonusXpManager.Instance != null)
			{
				num = BonusXpManager.Instance.MapExplorationXp;
			}
			if (num > 0)
			{
				Console.AddMessage("[" + NGUITools.EncodeColor(Color.yellow) + "]" + Console.Format(GUIUtils.GetTextWithLinks(1314), currentMap.DisplayName, num * PartyHelper.NumPartyMembers));
				PartyHelper.AssignXPToParty(num, printMessage: false);
			}
		}
		WinCursor.Clip(state: true);
	}

	public void UnsetLoadedGameFlags()
	{
		SDK.GameState.LoadedGame = false;
		SDK.GameState.IsRestoredLevel = false;
		s_sentOnLevelLoadedEarly = false;
		s_sentOnLevelLoaded = false;
		s_sentOnLevelLoadedLate = false;
	}

	public override string GetCurrentMapName()
	{
		MapData currentMap = GetCurrentMap();
		return (!(currentMap == null)) ? currentMap.GetDisplayNameText() : "MISSING MAP DATA";
	}

	public IEnumerator Coroutine_DelayCombatStartAutoPause(GameObject combatTarget)
	{
		yield return null;
		while (!TimeController.Instance.CanPause)
		{
			yield return null;
		}
		if (SDK.GameState.InCombat)
		{
			AutoPause(AutoPauseOptions.PauseEvent.CombatStart, combatTarget, null);
		}
	}

	protected static void OnPlayerCharacterChanged(object sender, EventArgs e)
	{
		GameState.PlayerCharacterChanged?.Invoke(sender, e);
	}

	public static void SlideSetPlayed(UIEndGameSlidesManager.StorySlides slideType)
	{
		switch (slideType)
		{
		case UIEndGameSlidesManager.StorySlides.Act2:
			TelemetryManager.Instance.QueueEvent_ActEnded(SDK.TelemetryManager.Destination.Developer | SDK.TelemetryManager.Destination.Publisher, 1);
			TelemetryManager.Instance.QueueEvent_CompanionUsage(SDK.TelemetryManager.Destination.Developer | SDK.TelemetryManager.Destination.Publisher);
			GlobalVariables.Instance.SetVariable("tel_attempted_combos_this_act", 0);
			GlobalVariables.Instance.SetVariable("tel_successful_combos_this_act", 0);
			break;
		case UIEndGameSlidesManager.StorySlides.Act3:
			TelemetryManager.Instance.QueueEvent_ActEnded(SDK.TelemetryManager.Destination.Developer | SDK.TelemetryManager.Destination.Publisher, 2);
			TelemetryManager.Instance.QueueEvent_CompanionUsage(SDK.TelemetryManager.Destination.Developer | SDK.TelemetryManager.Destination.Publisher);
			GlobalVariables.Instance.SetVariable("tel_attempted_combos_this_act", 0);
			GlobalVariables.Instance.SetVariable("tel_successful_combos_this_act", 0);
			break;
		case UIEndGameSlidesManager.StorySlides.Final:
			TelemetryManager.Instance.QueueEvent_ActEnded(SDK.TelemetryManager.Destination.Developer | SDK.TelemetryManager.Destination.Publisher, 3);
			TelemetryManager.Instance.QueueEvent_CompanionUsage(SDK.TelemetryManager.Destination.Developer | SDK.TelemetryManager.Destination.Publisher);
			GlobalVariables.Instance.SetVariable("tel_attempted_combos_this_act", 0);
			GlobalVariables.Instance.SetVariable("tel_successful_combos_this_act", 0);
			break;
		}
	}
}

