322					result = Mathf.Min(num3 - base.NegativeAxisValue, amount);
323					break;
324				}
325				case Axis.Positive:
326				{
327					if (num < m_gamesavePacket.m_positiveMaxRank)
328					{
329						num = m_gamesavePacket.m_positiveMaxRank;
330					}
331					int num2 = Mathf.FloorToInt(RankToPct(num + 1) * (float)GetScaleForAxis(Axis.Positive)) - 1;
332					result = Mathf.Min(num2 - base.PositiveAxisValue, amount);
333					break;
334				}
335				}
336			}
337			return result;
338		}
