803		public bool CheckAbilities(GameObject owner, GenericAbility.AbilityEventHandler OnUse)
804		{
805			int goodRank = base.GoodRank;
806			bool flag = false;
807			if (goodRank != m_gamesavePacket.m_posAbilityIndex)
808			{
809				RemoveAbilityTier(m_gamesavePacket.m_posAbility, OnUse);
810				if (goodRank > 0 && PositiveAbilities != null && PositiveAbilities.Length >= goodRank)
811				{
812					flag = AddAbilityTier(PositiveAbilities[goodRank - 1], m_gamesavePacket.m_posAbility, owner, OnUse);
813				}
814				m_gamesavePacket.m_posAbilityIndex = goodRank;
815			}
816			int badRank = base.BadRank;
817			bool flag2 = false;
818			if (badRank != m_gamesavePacket.m_negAbilityIndex)
819			{
820				RemoveAbilityTier(m_gamesavePacket.m_negAbility, OnUse);
821				if (badRank > 0 && NegativeAbilities != null && NegativeAbilities.Length >= badRank)
822				{
823					flag2 = AddAbilityTier(NegativeAbilities[badRank - 1], m_gamesavePacket.m_negAbility, owner, OnUse);
824				}
825				m_gamesavePacket.m_negAbilityIndex = badRank;
826			}
827			bool flag3 = m_gamesavePacket.m_newAbilities.Count > 0;
828			currentAbilityStringIDHash.Clear();
829			AddGenericAbilityListIntoStringIDHashSet(m_gamesavePacket.m_posAbility, currentAbilityStringIDHash);
830			AddGenericAbilityListIntoStringIDHashSet(m_gamesavePacket.m_negAbility, currentAbilityStringIDHash);
831			currentAbilityStringIDHash.ExceptWith(m_gamesavePacket.m_viewedAbilities);
832			m_newlyAddedAbilities.Clear();
833			m_newlyAddedAbilities.UnionWith(currentAbilityStringIDHash);
834			m_newlyAddedAbilities.ExceptWith(m_gamesavePacket.m_newAbilities);
835			m_gamesavePacket.m_newAbilities.Clear();
836			if (currentAbilityStringIDHash.Count > 0)
837			{
838				m_gamesavePacket.m_newAbilities.UnionWith(currentAbilityStringIDHash);
839			}
840			if (currentAbilityStringIDHash.Count > 0 != flag3)
841			{
842				ReputationManager.FireReputationNewAbilityChanged(this);
843			}
844			if (m_newlyAddedAbilities.Count > 0 && ShouldReputationAbilityShow())
845			{
846				foreach (int newlyAddedAbility in m_newlyAddedAbilities)
847				{
848					for (int i = 0; i < m_gamesavePacket.m_posAbility.Count; i++)
849					{
850						GenericAbility genericAbility = m_gamesavePacket.m_posAbility[i];
851						if (genericAbility.DisplayName.StringID == newlyAddedAbility)
852						{
853							FireNewQuestNotificationForAbility(genericAbility, Axis.Positive);
854						}
855					}
856					for (int j = 0; j < m_gamesavePacket.m_negAbility.Count; j++)
857					{
858						GenericAbility genericAbility2 = m_gamesavePacket.m_negAbility[j];
859						if (genericAbility2.DisplayName.StringID == newlyAddedAbility)
860						{
861							FireNewQuestNotificationForAbility(genericAbility2, Axis.Negative);
862						}
863					}
864				}
865			}
866			currentAbilityStringIDHash.Clear();
867			return flag || flag2;
868		}
