using System;
using System.Collections.Generic;
using System.Text;
using Polenter.Serialization;
using SDK;
using UnityEngine;
using UnityEngine.Serialization;

namespace Game;

[Serializable]
public class Reputation : SDK.Reputation
{
	public enum ReputationType
	{
		Faction,
		Companion,
		Artifact,
		Archon,
		Count
	}

	public enum ChangeEventType
	{
		Add,
		Remove,
		LinkedAdd,
		LinkedRemove,
		ForcedHostile,
		ForcedAxisRank
	}

	[Serializable]
	public class ChangeEvent
	{
		public ChangeEventType m_type;

		public Axis m_axis;

		public ChangeStrength m_strength;

		public int m_reasonIndex;

		public string ReasonText
		{
			get
			{
				if (m_type == ChangeEventType.LinkedAdd || m_type == ChangeEventType.LinkedRemove)
				{
					if (!(ReputationManager.Instance.GetReputation(m_reasonIndex) is Reputation reputation))
					{
						return SDK.GUIUtils.GetText(2232);
					}
					if (reputation.Type != ReputationType.Archon)
					{
						return string.Format(SDK.GUIUtils.GetText(2233), reputation.Name.GetText());
					}
					return SDK.GUIUtils.Format(4355, reputation.Name.GetText());
				}
				if (m_reasonIndex < 0)
				{
					return SDK.GUIUtils.GetText(2234);
				}
				return StringTableManager.GetText(DatabaseString.StringTableType.ReputationChangeReasons, m_reasonIndex);
			}
		}
	}

	[Serializable]
	public class LinkedReputation
	{
		public FactionName FactionID;

		public float Weight = 1f;
	}

	[Serializable]
	public class AbilityTier
	{
		public GenericAbility[] Ability;
	}

	public const int EventSize = 20;

	[Tooltip("Abilities gained for positive axis ranks 1 to 5 (stored as 0 to 4). No abilities are gained for rank 0.")]
	[ExcludeFromSerialization]
	public AbilityTier[] PositiveAbilities = new AbilityTier[SDK.Reputation.MaxRank];

	[ExcludeFromSerialization]
	[Tooltip("Abilities gained for negative axis ranks 1 to 5 (stored as 0 to 4). No abilities are gained for rank 0.")]
	public AbilityTier[] NegativeAbilities = new AbilityTier[SDK.Reputation.MaxRank];

	public FactionName FactionID;

	public ReputationType Type;

	[Tooltip("A companion that is uniquely linked to this reputation. This field is not valid unless the reputation's Type field is set to Companion.")]
	public CompanionInstanceID Companion;

	[Tooltip("Prior to joining the player the companion belonged to this faction. Used for display purposes in the UI.")]
	public FactionName CompanionOriginFaction;

	[ExcludeFromSerialization]
	public int FriendlyAtGoodRank = 4;

	[ExcludeFromSerialization]
	public int HostileAtBadRank = 3;

	public List<LinkedReputation> LinkedReputations = new List<LinkedReputation>();

	public bool CanBeAlly;

	public bool CanBeEnemy;

	[ExcludeFromSerialization]
	public Color ColorPrimary;

	[ExcludeFromSerialization]
	public Color ColorSecondary;

	[ExcludeFromSerialization]
	public Color MapRegionColor = Color.white;

	[ExcludeFromSerialization]
	public Color MapRegionNightColor = Color.black;

	[ExcludeFromSerialization]
	public Color MapRegionDayColor = Color.white;

	[ExcludeFromSerialization]
	[FormerlySerializedAs("BannerSigil")]
	public Texture2D BannerIcon;

	private HashSet<int> currentAbilityStringIDHash = new HashSet<int>();

	private HashSet<int> m_newlyAddedAbilities = new HashSet<int>();

	private ReputationSaveData m_gamesavePacket;

	public int RecordCount => m_gamesavePacket.m_changeEventCount;

	[ExcludeFromSerialization]
	public int TotalBeliefGained
	{
		get
		{
			return m_gamesavePacket.m_totalBeliefGained;
		}
		set
		{
			m_gamesavePacket.m_totalBeliefGained = value;
		}
	}

	[ExcludeFromSerialization]
	public int PositiveMaxRank => m_gamesavePacket.m_positiveMaxRank;

	[ExcludeFromSerialization]
	public int NegativeMaxRank => m_gamesavePacket.m_negativeMaxRank;

	public override bool Equals(object obj)
	{
		if (obj is Reputation)
		{
			return (obj as Reputation).FactionID == FactionID;
		}
		if (obj is FactionName)
		{
			return FactionID == (FactionName)(int)obj;
		}
		if (obj is int)
		{
			return FactionID == (FactionName)(int)obj;
		}
		if (obj is string)
		{
			return FactionID.ToString().ToLower() == (obj as string).ToLower();
		}
		return base.Equals(obj);
	}

	public override bool Equals(int checkFactionID)
	{
		return checkFactionID == (int)FactionID;
	}

	public override int GetHashCode()
	{
		return FactionID.GetHashCode();
	}

	public override void OnStart()
	{
		base.OnStart();
		base.OnReputationRankChanged += HandleRankChange;
	}

	public override void InitializePacket(SDK.ReputationSaveData packet)
	{
		base.InitializePacket(packet);
		ReputationSaveData reputationSaveData = (ReputationSaveData)packet;
		int num3 = (reputationSaveData.m_negativeMaxRank = (reputationSaveData.m_positiveMaxRank = StrengthToMaxRank(ChangeStrength.VeryMinor)));
		reputationSaveData.m_posAbilityIndex = -1;
		reputationSaveData.m_negAbilityIndex = -1;
		reputationSaveData.m_wasAlly = false;
		reputationSaveData.m_wasEnemy = false;
		reputationSaveData.m_forcedHostile = false;
		reputationSaveData.m_changeEventCount = 0;
		reputationSaveData.m_viewedAbilities = new HashSet<int>();
		reputationSaveData.m_newAbilities = new HashSet<int>();
	}

	public override void SetPacket(SDK.ReputationSaveData packet)
	{
		base.SetPacket(packet);
		m_gamesavePacket = (ReputationSaveData)packet;
	}

	public override void AddReputation(Axis axis, ChangeStrength strength)
	{
		AddReputationIgnoreLinked(axis, strength);
		int num = StrengthToAmount(strength);
		foreach (LinkedReputation linkedReputation in LinkedReputations)
		{
			int amount = (int)((float)num * linkedReputation.Weight);
			int factionID = (int)linkedReputation.FactionID;
			Reputation reputation = (Reputation)ReputationManager.Instance.GetReputation(factionID);
			reputation.ChangeMaxRank(axis, strength);
			if (reputation != null && reputation.CanAddReputation(axis, amount))
			{
				reputation.AddReputation(axis, amount);
				reputation.RecordLinkedAdd(axis, strength, (int)FactionID);
			}
		}
	}

	public static CompanionNames.Companions ConvertRepFactionIDToCompanionID(FactionName companionFactionID)
	{
		return companionFactionID switch
		{
			FactionName.Comp_Beastman => CompanionNames.Companions.Comp_Beastwoman, 
			FactionName.Comp_Defender => CompanionNames.Companions.Comp_Defender, 
			FactionName.Comp_Sirin => CompanionNames.Companions.Comp_Sirin, 
			FactionName.Comp_MobileDmg => CompanionNames.Companions.Comp_MobileDamage, 
			FactionName.Comp_RangedMagic => CompanionNames.Companions.Comp_RangedMagic, 
			FactionName.Comp_Historian => CompanionNames.Companions.Comp_Historian, 
			_ => CompanionNames.Companions.Invalid, 
		};
	}

	public static FactionName ConvertCompanionIDToRepFactionID(CompanionNames.Companions companionID)
	{
		return companionID switch
		{
			CompanionNames.Companions.Comp_Beastwoman => FactionName.Comp_Beastman, 
			CompanionNames.Companions.Comp_Defender => FactionName.Comp_Defender, 
			CompanionNames.Companions.Comp_Historian => FactionName.Comp_Historian, 
			CompanionNames.Companions.Comp_MobileDamage => FactionName.Comp_MobileDmg, 
			CompanionNames.Companions.Comp_RangedMagic => FactionName.Comp_RangedMagic, 
			CompanionNames.Companions.Comp_Sirin => FactionName.Comp_Sirin, 
			_ => FactionName.None, 
		};
	}

	public void AddReputationIgnoreLinked(Axis axis, ChangeStrength strength)
	{
		ChangeMaxRank(axis, strength);
		base.AddReputation(axis, strength);
	}

	public void RemoveReputationIgnoreLinked(Axis axis, ChangeStrength strength)
	{
		base.RemoveReputation(axis, strength);
	}

	public override bool CanAddReputation(Axis axis, int amount)
	{
		bool flag = base.CanAddReputation(axis, amount);
		if (flag)
		{
			int num = AmountToMaxRank(amount);
			switch (axis)
			{
			case Axis.Negative:
				if (num < m_gamesavePacket.m_negativeMaxRank)
				{
					num = m_gamesavePacket.m_negativeMaxRank;
				}
				base.NegativeAxisValue += amount;
				flag = base.BadRank <= num;
				base.NegativeAxisValue -= amount;
				break;
			case Axis.Positive:
				if (num < m_gamesavePacket.m_positiveMaxRank)
				{
					num = m_gamesavePacket.m_positiveMaxRank;
				}
				base.PositiveAxisValue += amount;
				flag = base.GoodRank <= num;
				base.PositiveAxisValue -= amount;
				break;
			}
		}
		return flag;
	}

	public override int GetPointsThatCanBeAdded(Axis axis, int amount)
	{
		int result = 0;
		if (base.CanAddReputation(axis, amount))
		{
			int num = AmountToMaxRank(amount);
			switch (axis)
			{
			case Axis.Negative:
			{
				if (num < m_gamesavePacket.m_negativeMaxRank)
				{
					num = m_gamesavePacket.m_negativeMaxRank;
				}
				int num3 = Mathf.FloorToInt(RankToPct(num + 1) * (float)GetScaleForAxis(Axis.Negative)) - 1;
				result = Mathf.Min(num3 - base.NegativeAxisValue, amount);
				break;
			}
			case Axis.Positive:
			{
				if (num < m_gamesavePacket.m_positiveMaxRank)
				{
					num = m_gamesavePacket.m_positiveMaxRank;
				}
				int num2 = Mathf.FloorToInt(RankToPct(num + 1) * (float)GetScaleForAxis(Axis.Positive)) - 1;
				result = Mathf.Min(num2 - base.PositiveAxisValue, amount);
				break;
			}
			}
		}
		return result;
	}

	public override void RemoveReputation(Axis axis, ChangeStrength strength)
	{
		RemoveReputationIgnoreLinked(axis, strength);
		int num = StrengthToAmount(strength);
		foreach (LinkedReputation linkedReputation in LinkedReputations)
		{
			int amount = (int)((float)num * linkedReputation.Weight);
			int factionID = (int)linkedReputation.FactionID;
			Reputation reputation = (Reputation)ReputationManager.Instance.GetReputation(factionID);
			if (reputation != null && reputation.CanRemoveReputation(axis, amount))
			{
				reputation.RemoveReputation(axis, amount);
				reputation.RecordLinkedRemove(axis, strength, (int)FactionID);
			}
		}
	}

	public override bool CanRemoveReputation(Axis axis, int amount)
	{
		bool flag = base.CanRemoveReputation(axis, amount);
		if (flag && m_gamesavePacket.m_forcedHostile && axis == Axis.Negative)
		{
			float num = m_gamesavePacket.m_negativeValue - amount;
			float pct = num / (float)GetScaleForAxis(Axis.Negative);
			return PctToRank(pct) >= HostileAtBadRank;
		}
		return flag;
	}

	public bool HasLinkedReputations()
	{
		if (LinkedReputations != null)
		{
			foreach (LinkedReputation linkedReputation in LinkedReputations)
			{
				if (linkedReputation != null)
				{
					return true;
				}
			}
		}
		return false;
	}

	public bool HasNewAbilities()
	{
		if (m_gamesavePacket != null && m_gamesavePacket.m_newAbilities != null)
		{
			return m_gamesavePacket.m_newAbilities.Count > 0;
		}
		return false;
	}

	public bool HasAbilities()
	{
		if (HasAbilitiesInArray(PositiveAbilities))
		{
			return true;
		}
		if (HasAbilitiesInArray(NegativeAbilities))
		{
			return true;
		}
		return false;
	}

	private bool HasAbilitiesInArray(AbilityTier[] abilities)
	{
		if (abilities != null)
		{
			for (int i = 0; i < abilities.Length; i++)
			{
				if (abilities[i] == null || abilities[i].Ability == null)
				{
					continue;
				}
				for (int j = 0; j < abilities[i].Ability.Length; j++)
				{
					if (abilities[i].Ability[j] != null)
					{
						return true;
					}
				}
			}
		}
		return false;
	}

	public GenericAbility[] GetAblitiesForRank(Axis axis, int rank)
	{
		if (rank > 0)
		{
			AbilityTier[] array = ((axis != 0) ? NegativeAbilities : PositiveAbilities);
			return array[rank - 1].Ability;
		}
		return null;
	}

	public GenericAbility GetAbility(Axis axis, int rank, int index)
	{
		GenericAbility result = null;
		if (rank > 0)
		{
			AbilityTier[] array = ((axis != 0) ? NegativeAbilities : PositiveAbilities);
			if (array != null && array.Length >= rank && array[rank - 1] != null && array[rank - 1].Ability != null && array[rank - 1].Ability.Length > index)
			{
				result = array[rank - 1].Ability[index];
			}
		}
		return result;
	}

	public int MaxAbilityDepth(Axis axis)
	{
		int num = 0;
		AbilityTier[] array = PositiveAbilities;
		if (axis == Axis.Negative)
		{
			array = NegativeAbilities;
		}
		if (array != null)
		{
			for (int i = 1; i <= SDK.Reputation.MaxRank; i++)
			{
				for (int j = 0; j < array.Length; j++)
				{
					if (num < j + 1 && GetAbility(axis, i, j) != null)
					{
						num = j + 1;
					}
				}
			}
		}
		return num;
	}

