	public override int StrengthToAmount(ChangeStrength strength)
	{
		int result = 0;
		ReputationManager instance = ReputationManager.Instance;
		if (instance != null)
		{
			switch (strength)
			{
			case ChangeStrength.None:
				result = 0;
				break;
			case ChangeStrength.VeryMinor:
				result = instance.VeryMinorBonus;
				break;
			case ChangeStrength.Minor:
				result = instance.MinorBonus;
				break;
			case ChangeStrength.Average:
				result = instance.AverageBonus;
				break;
			case ChangeStrength.Major:
				result = instance.MajorBonus;
				break;
			case ChangeStrength.VeryMajor:
				result = instance.VeryMajorBonus;
				break;
			default:
				Debug.LogError("Invalid change strength value of " + strength.ToString() + "submitted for reputation " + Name.GetText() + ". Returning amount of zero.");
				break;
			}
		}
		return result;
	}

	public static ChangeStrength GetStrengthForMaxRank(int rank)
	{
		for (int i = 0; i <= 8; i++)
		{
			if (StrengthToMaxRank((ChangeStrength)i) == rank)
			{
				return (ChangeStrength)i;
			}
		}
		return ChangeStrength.VeryMajor;
	}

	public static int StrengthToMaxRank(ChangeStrength strength)
	{
		return strength switch
		{
			ChangeStrength.None => 0, 
			ChangeStrength.VeryMinor => 1, 
			ChangeStrength.Minor => 2, 
			ChangeStrength.Average => 3, 
			ChangeStrength.Major => 4, 
			ChangeStrength.VeryMajor => 5, 
			_ => 0, 
		};
	}

	public static int AmountToMaxRank(int amount)
	{
		int result = 0;
		ReputationManager instance = ReputationManager.Instance;
		if (instance != null)
		{
			result = ((amount <= instance.VeryMinorBonus) ? 1 : ((amount <= instance.MinorBonus) ? 2 : ((amount <= instance.AverageBonus) ? 3 : ((amount > instance.MajorBonus) ? 5 : 4))));
		}
		return result;
	}

