	private void GrantMaxRankAchievements()
	{
		if (!AchievementTracker.Instance)
		{
			return;
		}
		if (Type == ReputationType.Faction)
		{
			if (SDK.Reputation.MaxRank <= base.GoodRank)
			{
				AchievementTracker.Instance.ForceSetTrackedStat(AchievementTracker.TrackedAchievementStat.FactionMaxedFavor, 1);
			}
			else if (SDK.Reputation.MaxRank <= base.BadRank)
			{
				AchievementTracker.Instance.ForceSetTrackedStat(AchievementTracker.TrackedAchievementStat.FactionMaxedWrath, 1);
			}
		}
		else if (Type == ReputationType.Companion)
		{
			if (SDK.Reputation.MaxRank <= base.GoodRank)
			{
				AchievementTracker.Instance.ForceSetTrackedStat(AchievementTracker.TrackedAchievementStat.FactionMaxedLoyalty, 1);
			}
			else if (SDK.Reputation.MaxRank <= base.BadRank)
