	private void CheckForAlliesAndEnemies()
	{
		if (!CanBeAlly && !CanBeEnemy)
		{
			return;
		}
		RankType rankType;
		int rank = GetRank(out rankType);
		if (m_gamesavePacket.m_isAlly)
		{
			if (rankType != RankType.Good || rank == 0)
			{
				AllyStop();
			}
		}
		else if (m_gamesavePacket.m_isEnemy && rankType != RankType.Bad && (rankType != RankType.Mixed || rank == 0 || rank >= 3))
		{
			EnemyStop();
		}
		if (CanBeAlly && rankType == RankType.Good && rank == 4)
		{
			AllyStart();
		}
		else if (CanBeEnemy && rankType == RankType.Bad && rank >= 3)
		{
			EnemyStart();
		}
	}

