	public bool CheckAbilities(GameObject owner, GenericAbility.AbilityEventHandler OnUse)
	{
		int goodRank = base.GoodRank;
		bool flag = false;
		if (goodRank != m_gamesavePacket.m_posAbilityIndex)
		{
			RemoveAbilityTier(m_gamesavePacket.m_posAbility, OnUse);
			if (goodRank > 0 && PositiveAbilities != null && PositiveAbilities.Length >= goodRank)
			{
				flag = AddAbilityTier(PositiveAbilities[goodRank - 1], m_gamesavePacket.m_posAbility, owner, OnUse);
			}
			m_gamesavePacket.m_posAbilityIndex = goodRank;
		}
		int badRank = base.BadRank;
		bool flag2 = false;
		if (badRank != m_gamesavePacket.m_negAbilityIndex)
		{
			RemoveAbilityTier(m_gamesavePacket.m_negAbility, OnUse);
			if (badRank > 0 && NegativeAbilities != null && NegativeAbilities.Length >= badRank)
			{
				flag2 = AddAbilityTier(NegativeAbilities[badRank - 1], m_gamesavePacket.m_negAbility, owner, OnUse);
			}
			m_gamesavePacket.m_negAbilityIndex = badRank;
		}
		bool flag3 = m_gamesavePacket.m_newAbilities.Count > 0;
		currentAbilityStringIDHash.Clear();
		AddGenericAbilityListIntoStringIDHashSet(m_gamesavePacket.m_posAbility, currentAbilityStringIDHash);
		AddGenericAbilityListIntoStringIDHashSet(m_gamesavePacket.m_negAbility, currentAbilityStringIDHash);
		currentAbilityStringIDHash.ExceptWith(m_gamesavePacket.m_viewedAbilities);
		m_newlyAddedAbilities.Clear();
		m_newlyAddedAbilities.UnionWith(currentAbilityStringIDHash);
		m_newlyAddedAbilities.ExceptWith(m_gamesavePacket.m_newAbilities);
		m_gamesavePacket.m_newAbilities.Clear();
		if (currentAbilityStringIDHash.Count > 0)
		{
			m_gamesavePacket.m_newAbilities.UnionWith(currentAbilityStringIDHash);
		}
		if (currentAbilityStringIDHash.Count > 0 != flag3)
		{
			ReputationManager.FireReputationNewAbilityChanged(this);
		}
		if (m_newlyAddedAbilities.Count > 0 && ShouldReputationAbilityShow())
		{
			foreach (int newlyAddedAbility in m_newlyAddedAbilities)
			{
				for (int i = 0; i < m_gamesavePacket.m_posAbility.Count; i++)
				{
					GenericAbility genericAbility = m_gamesavePacket.m_posAbility[i];
					if (genericAbility.DisplayName.StringID == newlyAddedAbility)
					{
						FireNewQuestNotificationForAbility(genericAbility, Axis.Positive);
					}
				}
				for (int j = 0; j < m_gamesavePacket.m_negAbility.Count; j++)
				{
					GenericAbility genericAbility2 = m_gamesavePacket.m_negAbility[j];
					if (genericAbility2.DisplayName.StringID == newlyAddedAbility)
					{
						FireNewQuestNotificationForAbility(genericAbility2, Axis.Negative);
					}
				}
			}
		}
		currentAbilityStringIDHash.Clear();
		return flag || flag2;
	}

