	private void AddGenericAbilityListIntoStringIDHashSet(List<GenericAbility> abil, HashSet<int> hashSet)
	{
		for (int i = 0; i < abil.Count; i++)
		{
			GenericAbility genericAbility = abil[i];
			if (!(genericAbility == null))
			{
				int stringID = abil[i].DisplayName.StringID;
