	private void RestoreAbilityTier(AbilityTier tier, List<GenericAbility> abilityList, GameObject owner)
	{
		if (tier == null || tier.Ability == null || !(owner != null))
		{
			return;
		}
		CharacterStats component = owner.GetComponent<CharacterStats>();
		if (!(component != null))
		{
			return;
		}
		GenericAbility[] ability = tier.Ability;
		foreach (GenericAbility genericAbility in ability)
		{
			if (genericAbility is SharedAbility && owner != GameState.s_playerCharacter.gameObject)
			{
				continue;
			}
			foreach (GenericAbility activeAbility in component.ActiveAbilities)
			{
				if (activeAbility.Equals(genericAbility))
				{
					abilityList.Add(activeAbility);
					break;
				}
			}
		}
	}

	private bool AddAbilityTier(AbilityTier tier, List<GenericAbility> abilityList, GameObject owner, GenericAbility.AbilityEventHandler OnUse)
	{
		bool result = false;
		if (tier != null && tier.Ability != null)
		{
			GenericAbility[] ability = tier.Ability;
			foreach (GenericAbility prefab in ability)
			{
				GenericAbility genericAbility = AddAbility(prefab, owner, OnUse);
				if (genericAbility != null)
				{
					abilityList.Add(genericAbility);
					result = true;
				}
			}
		}
		return result;
	}

	private GenericAbility AddAbility(GenericAbility prefab, GameObject owner, GenericAbility.AbilityEventHandler OnUse)
	{
		if (owner == null || prefab == null)
		{
			return null;
		}
		CharacterStats component = owner.GetComponent<CharacterStats>();
		if (component != null)
		{
			int num = component.ActiveAbilities.IndexOf(prefab);
			if (num >= 0)
			{
				if (GameState.Instance.NewGamePlusIteration > 0 && Type != ReputationType.Artifact)
				{
					return null;
				}
				GameUtilities.Instance.DebugHelper_LogOnScreenWarning_Programming("Found instance of reputation ability<" + prefab.name + "> already present on: " + owner.name + " while attempting to add it. Removing previous instance.", 10f);
				GenericAbility ability = component.ActiveAbilities[num] as GenericAbility;
				component.ActiveAbilities.RemoveAt(num);
				GameUtilities.DestroyAbility(ability);
			}
		}
		GenericAbility genericAbility = UnityEngine.Object.Instantiate(prefab);
		if (genericAbility == null)
		{
			return null;
		}
		genericAbility.name = SDK.GameUtilities.RemoveClone(genericAbility.name);
		genericAbility.Owner = owner;
		genericAbility.EffectType = prefab.EffectType;
		AttackBase component2 = genericAbility.GetComponent<AttackBase>();
		if ((bool)component2)
		{
			component2.Owner = genericAbility.Owner;
		}
		if (component != null)
		{
			component.ActiveAbilities.Add(genericAbility);
		}
		if (OnUse != null)
		{
			genericAbility.OnCooldown += OnUse;
		}
		if (Type != ReputationType.Artifact)
		{
			TutorialManager.STriggerTutorialsOfTypeFast(TutorialManager.ExclusiveTriggerType.REPUTATION_ABILITY_UNLOCKED);
			AchievementTracker.Instance.ForceSetTrackedStat(AchievementTracker.TrackedAchievementStat.HasLearnedReputationAbility, 1);
		}
		return genericAbility;
	}

	private void RemoveAbilityTier(List<GenericAbility> abilityList, GenericAbility.AbilityEventHandler OnUse)
	{
		if (abilityList == null)
		{
			return;
		}
		foreach (GenericAbility ability in abilityList)
		{
			RemoveAbility(ability, OnUse);
		}
		abilityList.Clear();
	}

	private void RemoveAbility(GenericAbility ability, GenericAbility.AbilityEventHandler OnUse)
	{
		if (!(ability != null))
		{
			return;
		}
		if (OnUse != null)
		{
			ability.OnCooldown -= OnUse;
		}
		CharacterStats component = ability.Owner.GetComponent<CharacterStats>();
		if (component != null)
		{
			for (int i = 0; i < component.ActiveAbilities.Count; i++)
			{
				GenericAbility genericAbility = component.ActiveAbilities[i] as GenericAbility;
				if (genericAbility == ability || ability.Equals(genericAbility))
				{
					component.ClearAIStatesUsingAbility(genericAbility);
					if (genericAbility.Activated)
					{
						genericAbility.ForceDeactivate(genericAbility.Owner);
					}
					component.ActiveAbilities.RemoveAt(i);
					break;
				}
			}
		}
		GameUtilities.DestroyAbility(ability);
	}

