	public void ForceHostile(int reasonIndex)
	{
		m_gamesavePacket.m_forcedHostile = true;
		if (!IsHostile())
		{
			if (base.PositiveAxisValue > 0)
			{
				RemoveReputation(Axis.Positive, base.PositiveAxisValue);
				RecordEvent(ChangeEventType.Remove, Axis.Positive, ChangeStrength.VeryMajor, reasonIndex);
			}
			float num = RankToPct(HostileAtBadRank);
			int num2 = (int)(num * (float)GetScaleForAxis(Axis.Negative)) + 1;
			if (base.NegativeAxisValue < num2)
			{
				ChangeMaxRank(Axis.Negative, ChangeStrength.VeryMajor);
				AddReputation(Axis.Negative, num2 - base.NegativeAxisValue);
				RecordEvent(ChangeEventType.Add, Axis.Negative, ChangeStrength.VeryMajor, reasonIndex);
			}
		}
	}

	public void SetAxisRank(Axis axis, int rank, int reasonIndex)
	{
		int num = ((axis != 0) ? base.BadRank : base.GoodRank);
		if (num != rank)
		{
			float num2 = RankToPct(rank);
			int num3 = (int)(num2 * (float)GetScaleForAxis(axis)) + 1;
			int num4 = ((axis != 0) ? base.NegativeAxisValue : base.PositiveAxisValue);
			if (num3 > num4)
			{
				ChangeMaxRank(axis, ChangeStrength.VeryMajor);
				AddReputation(axis, num3 - num4);
				RecordEvent(ChangeEventType.Add, axis, ChangeStrength.VeryMajor, reasonIndex);
			}
			else
			{
				RemoveReputation(axis, num4 - num3);
				RecordEvent(ChangeEventType.Remove, axis, ChangeStrength.VeryMajor, reasonIndex);
			}
		}
	}

