	public float PercentToNextRank(Axis axis, float percentModifier = 0f)
	{
		int num = ((axis != 0) ? base.BadRank : base.GoodRank);
		float num2 = RankToPct(num);
		float num3 = RankToPct(num + 1);
		float num4 = GetReputationPct(axis) + percentModifier;
		return (num4 - num2) / (num3 - num2);
	}

