	private void AppendTooltipLineForAxis(StringBuilder sb, Axis axis)
	{
		sb.Append(GetAxisDisplayName(axis));
		sb.Append(SDK.GUIUtils.GetText(4231) + " ");
		sb.Append(PctToRank(GetReputationPct(axis)));
		sb.Append(" ");
		sb.Append("(");
		sb.Append(SDK.GUIUtils.Format(3801, Mathf.FloorToInt(PercentToNextRank(axis) * 100f).ToString(), GetNextRankAfterModifier(axis, 0f)));
		sb.Append(")");
		sb.Append(Environment.NewLine);
	}

	public int GetNextRankAfterModifier(Axis axis, float percentModifier)
	{
		return PctToRank(GetReputationPct(axis) + percentModifier) + 1;
	}

	public float PercentToNextRankAfterModifier(Axis axis, float percentModifier)
	{
		float num = GetReputationPct(axis) + percentModifier;
		int nextRankAfterModifier = GetNextRankAfterModifier(axis, percentModifier);
		float num2 = RankToPct(nextRankAfterModifier);
		float num3 = RankToPct(nextRankAfterModifier - 1);
		return (num - num3) / (num2 - num3);
	}

	public void Clear()
	{
		RemoveReputation(Axis.Positive, base.PositiveAxisValue);
		RemoveReputation(Axis.Negative, base.NegativeAxisValue);
		m_gamesavePacket.m_changeEvent = new ChangeEvent[20];
		m_gamesavePacket.m_changeEventCount = 0;
		m_gamesavePacket.m_totalBeliefGained = 0;
		m_gamesavePacket.m_wasAlly = false;
		m_gamesavePacket.m_wasEnemy = false;
		m_gamesavePacket.m_forcedHostile = false;
	}
}

