	public int NewEnemyBeliefBonus = 50;

	public int VeryMinorBonus = 1;

	public int MinorBonus = 2;

	public int AverageBonus = 4;

	public int MajorBonus = 6;

	public int VeryMajorBonus = 8;

	[Persistent]
	[HideInInspector]
	public List<FactionName> Alliance = new List<FactionName>();

	public new static ReputationManager Instance => SDK.ReputationManager.s_instance as ReputationManager;

	public override SDK.Reputation[] FactionsArray => Factions;

	public event Action<Reputation> OnReputationNewAbilityChanged;

	public override void Start()
	{
		base.Start();
		FactionPackets = new ReputationSaveData[Factions.Length];
		for (int i = 0; i < Factions.Length; i++)
		{
			SDK.Reputation reputation = GetReputation((int)Factions[i].FactionID);
			if (reputation != null)
			{
				Reputation reputation2 = (Reputation)reputation;
				FactionPackets[i] = new ReputationSaveData();
				reputation2.InitializePacket(FactionPackets[i]);
				reputation2.SetPacket(FactionPackets[i]);
			}
		}
	}

	public override void Restored()
	{
		base.Restored();
		List<SDK.PartyMemberAI> onlyPrimaryPartyMembers = SDK.PartyMemberAI.OnlyPrimaryPartyMembers;
		int num = FactionPackets.Length;
		int num2 = Factions.Length;
		if (num < num2)
		{
			int num3 = num2 - num;
			Array.Resize(ref FactionPackets, num + num3);
			for (int i = 0; i < num3; i++)
			{
				SDK.Reputation reputation = GetReputation((int)Factions[num2 - Mathf.Abs(i - num3)].FactionID);
				if (reputation != null)
				{
					Reputation reputation2 = (Reputation)reputation;
					FactionPackets[num + i] = new ReputationSaveData();
					reputation2.InitializePacket(FactionPackets[num + i]);
					reputation2.SetPacket(FactionPackets[num + i]);
				}
			}
		}
		for (int j = 0; j < FactionPackets.Length; j++)
		{
			SDK.Reputation reputation3 = GetReputation((int)Factions[j].FactionID);
			if (reputation3 != null)
			{
				Reputation reputation4 = (Reputation)reputation3;
				reputation4.SetPacket(FactionPackets[j]);
				for (int k = 0; k < onlyPrimaryPartyMembers.Count; k++)
				{
					reputation4.RestoreAbilities(onlyPrimaryPartyMembers[k].gameObject);
				}
			}
		}
	}

	public override void OnDestroy()
	{
		this.OnReputationNewAbilityChanged = null;
		base.OnDestroy();
	}

	public override bool AddReputation(SDK.Reputation rep, SDK.Reputation.Axis axis, SDK.Reputation.ChangeStrength strength)
	{
		return AddReputation(rep, axis, strength, -1);
	}

	public bool AddReputation(SDK.Reputation rep, SDK.Reputation.Axis axis, SDK.Reputation.ChangeStrength strength, bool ignoreLinkedReputations = false)
	{
