	}

	public bool AddReputation(SDK.Reputation rep, SDK.Reputation.Axis axis, SDK.Reputation.ChangeStrength strength, int reasonIndex, bool ignoreLinkedReputations = false)
	{
		if (rep == null)
		{
			return false;
		}
		Reputation reputation = (Reputation)rep;
		if (!reputation.CanAddReputation(axis, strength))
		{
			return false;
		}
		if (UIConversationManager.IsInConversation() && UIConversationManager.Instance.HasConversationNodeBeenCompletedAlready())
		{
			return false;
		}
		bool flag = true;
		if (ignoreLinkedReputations && rep != null)
		{
			reputation.AddReputationIgnoreLinked(axis, strength);
		}
		else
		{
			flag = base.AddReputation(reputation, axis, strength);
		}
		if (flag)
		{
			if (UIConversationManager.Instance.IsVisible)
			{
				UIConversationManager.Instance.HandleReputationGain(reputation, axis, strength);
			}
			else if (UIWMEConversationManager.Instance.IsVisible)
			{
				UIWMEConversationManager.Instance.HandleReputationGain(reputation, axis, strength);
			}
			if (strength >= BeliefRepThreshold)
			{
				int num = Mathf.CeilToInt((float)strength * BeliefModifier);
				if (num > 0)
				{
					GameState.PlayerBelief.GainBelief(num);
					reputation.TotalBeliefGained += num;
				}
			}
			reputation.RecordAdd(axis, strength, reasonIndex);
			LogConsoleRepChangeWithReason(Console.Format(SDK.GUIUtils.GetText(1219), reputation.GetAxisDisplayName(axis), rep.Name.ToString()), SDK.GUIUtils.Format(3420, rep.GetAxisDisplayName(axis)) + " - " + Reputation.StrengthToText(strength), reasonIndex);
		}
		return flag;
	}

	public virtual bool AddReputationIgnoreLinked(Reputation rep, SDK.Reputation.Axis axis, SDK.Reputation.ChangeStrength strength)
	{
		if (rep == null)
		{
			return false;
		}
		rep.AddReputationIgnoreLinked(axis, strength);
		return true;
	}

	public string GetFactionName(FactionName id)
	{
		for (int i = 0; i < Factions.Length; i++)
		{
			if (Factions[i].Equals(id))
			{
				return Factions[i].Name.GetText();
			}
		}
		return string.Empty;
	}

	public override bool RemoveReputation(SDK.Reputation rep, SDK.Reputation.Axis axis, SDK.Reputation.ChangeStrength strength)
	{
