	public bool RemoveReputation(int factionId, SDK.Reputation.Axis axis, SDK.Reputation.ChangeStrength strength, int reasonIndex, bool ignoreLinkedReputations = false)
	{
		return RemoveReputation(GetReputation(factionId), axis, strength, reasonIndex, ignoreLinkedReputations);
	}

	public bool RemoveReputation(SDK.Reputation rep, SDK.Reputation.Axis axis, SDK.Reputation.ChangeStrength strength, int reasonIndex, bool ignoreLinkedReputations = false)
	{
		if (rep == null)
		{
			return false;
		}
		Reputation reputation = (Reputation)rep;
		if (!reputation.CanRemoveReputation(axis, strength))
		{
			return false;
		}
		if (UIConversationManager.IsInConversation() && UIConversationManager.Instance.HasConversationNodeBeenCompletedAlready())
		{
			return false;
		}
		bool flag = true;
		if (ignoreLinkedReputations && rep != null)
		{
			reputation.RemoveReputationIgnoreLinked(axis, strength);
		}
		else
		{
			flag = base.RemoveReputation(reputation, axis, strength);
		}
		if (flag)
		{
			if (UIConversationManager.Instance.IsVisible)
			{
				UIConversationManager.Instance.HandleReputationLost(reputation, axis, strength);
			}
			else if (UIWMEConversationManager.Instance.IsVisible)
			{
				UIWMEConversationManager.Instance.HandleReputationLost(reputation, axis, strength);
			}
			reputation.RecordRemove(axis, strength, reasonIndex);
			LogConsoleRepChangeWithReason(Console.Format(SDK.GUIUtils.GetText(1220), reputation.GetAxisDisplayName(axis), rep.Name.ToString()), SDK.GUIUtils.Format(3421, rep.GetAxisDisplayName(axis)) + " - " + Reputation.StrengthToText(strength), reasonIndex);
		}
		return flag;
	}

	public override SDK.Reputation GetReputation(int id, bool suppressWarnings = false)
	{
		if ((bool)SkirmishManager.Instance)
		{
			SkirmishRecord currentSkirmish = SkirmishManager.Instance.CurrentSkirmish;
			switch (id)
			{
			case 40:
				if (currentSkirmish != null && currentSkirmish.HasValidEnemyTeam)
				{
					id = (int)currentSkirmish.Enemy.Teams[0].GameFaction;
				}
				break;
			case 39:
				if (currentSkirmish != null && currentSkirmish.HasValidAllyTeam)
				{
					id = (int)currentSkirmish.Ally.Teams[0].GameFaction;
				}
				break;
			}
		}
		SDK.Reputation reputation = base.GetReputation(id);
		if (!suppressWarnings && reputation == null && id != 0)
		{
			Debug.LogWarning(string.Concat("Didn't find the faction ", (FactionName)id, " in the ReputationManager on ", base.gameObject.name, ". You must add it to the list."));
		}
		return reputation;
	}

	public FactionName[] GetKnownFactionsOfType(Reputation.ReputationType type, bool excludeFactionsWithNoLinks, bool excludeFactionsWithNoAbilities)
	{
		List<FactionName> list = new List<FactionName>();
		for (int i = 0; i < Factions.Length; i++)
		{
			if (Factions[i] != null && Factions[i].Type == type && Factions[i].RecordCount > 0 && (!excludeFactionsWithNoLinks || Factions[i].HasLinkedReputations()) && (!excludeFactionsWithNoAbilities || Factions[i].HasAbilities()))
			{
				list.Add(Factions[i].FactionID);
			}
		}
		if (list.Count == 0)
		{
			return null;
		}
		return list.ToArray();
	}

	public FactionName[] GetAllFactionsOfType(Reputation.ReputationType type, bool excludeFactionsWithNoLinks, bool excludeFactionsWithNoAbilities)
	{
		List<FactionName> list = new List<FactionName>();
		for (int i = 0; i < Factions.Length; i++)
		{
			if (Factions[i] != null && Factions[i].Type == type)
			{
				Reputation reputation = Factions[i];
				if ((!excludeFactionsWithNoLinks || reputation.HasLinkedReputations()) && (!excludeFactionsWithNoAbilities || reputation.HasAbilities()) && reputation.Description.IsValidString)
				{
					list.Add(reputation.FactionID);
				}
			}
		}
		if (list.Count == 0)
		{
			return null;
		}
		return list.ToArray();
	}

	public void ClearAllReputations()
	{
		for (int i = 0; i < Factions.Length; i++)
		{
			Factions[i].Clear();
		}
	}

	public void AddFactionIntoAlliance(FactionName id)
	{
		if (!Alliance.Contains(id))
		{
			Alliance.Add(id);
			Debug.Log("Reputation " + id.ToString() + " added to Alliance.");
		}
		else
		{
			Debug.LogError("Reputation " + id.ToString() + " is already in the Alliance.");
		}
	}

	public void RemoveFactionFromAlliance(FactionName id)
	{
		if (Alliance.Contains(id))
		{
			Alliance.Remove(id);
			Debug.Log("Reputation " + id.ToString() + " removed from Alliance.");
		}
		else
		{
			Debug.LogError("Reputation " + id.ToString() + " is not in the Alliance.");
		}
	}

	public bool IsLowestRespectInAlliance(FactionName id)
	{
		FactionName factionName = FactionName.None;
		float num = 2f;
		foreach (FactionName item in Alliance)
		{
			Reputation reputation = (Reputation)GetReputation((int)item);
			if (reputation != null)
			{
				float reputationPct = reputation.GetReputationPct(SDK.Reputation.Axis.Positive);
				if (factionName == FactionName.None || reputationPct <= num)
				{
					factionName = item;
					num = reputationPct;
				}
			}
		}
		if (factionName == id)
		{
			return true;
		}
		return false;
	}

	public static void FireReputationNewAbilityChanged(Reputation repChanged)
	{
		if (!(Instance == null) && Instance.OnReputationNewAbilityChanged != null)
		{
			Instance.OnReputationNewAbilityChanged(repChanged);
		}
	}

	public bool DoAnyReputationsHaveNewAbilities()
	{
		for (int i = 0; i < Factions.Length; i++)
		{
			if (GetReputation((int)Factions[i].FactionID) is Reputation reputation && reputation.HasNewAbilities())
			{
				return true;
			}
		}
		return false;
	}

	private void LogConsoleRepChangeWithReason(string logChange, string strength, int reasonIndex)
	{
		StringBuilder stringBuilder = new StringBuilder();
		stringBuilder.Append(strength);
		if (reasonIndex >= 0)
		{
			stringBuilder.AppendLine();
			stringBuilder.Append(StringTableManager.GetText(DatabaseString.StringTableType.ReputationChangeReasons, reasonIndex));
		}
		Console.AddMessage(logChange, stringBuilder.ToString(), UIGlobalColor.FetchColor(UIGlobalColor.ColorLookupID.TOOLTIP_HIGHLIGHT));
	}
}

