using SDK;
using UnityEngine;

namespace Game;

public class WorldTime : SDK.WorldTime
{
	public int m_gameSecondsPerRealSecond = 24;

	public int StartSecond;

	public int StartMinute = 30;

	public int StartHour = 8;

	public int StartDay = 18;

	public int StartMonth = 4;

	public int StartYear = 430;

	public int SecondsPerMinute = 60;

	public int MinutesPerHour = 60;

	public int HoursPerDay = 24;

	public int DaysPerMonth = 26;

	public int MonthsPerYear = 14;

	public int DaytimeStartHour = 6;

	public int NighttimeStartHour = 20;

	private int m_DaysPerYear;

	public GUIDatabaseString[] TransitionNames;

	public GUIDatabaseString[] MonthNames;

	public GUIDatabaseString[] PlainMonthNames;

	public GUIDatabaseString[] DayNames;

	public GUIDatabaseString YearName;

	private float SecondsTimer;

	private PE_DayNightRender DayNight;

	private float DayNightOverideTime = -1f;

	public new static WorldTime Instance => SDK.WorldTime.s_instance as WorldTime;

	public override int GameSecondsPerRealSecond => m_gameSecondsPerRealSecond;

	public int TotalSecondsToday => base.CurrentHour * MinutesPerHour * SecondsPerMinute + base.CurrentMinute * SecondsPerMinute + base.CurrentSecond;

	public int DaysPerYear
	{
		get
		{
			if (m_DaysPerYear <= 0)
			{
				m_DaysPerYear = MonthsPerYear * DaysPerMonth;
			}
			return m_DaysPerYear;
		}
	}

	public int SecondsPerYear => DaysPerYear * SecondsPerDay;

	public int SecondsPerMonth => DaysPerMonth * SecondsPerDay;

	public int SecondsPerDay => HoursPerDay * MinutesPerHour * SecondsPerMinute;

	public int SecondsPerHour => MinutesPerHour * SecondsPerMinute;

	public float DayNightTime
	{
		get
		{
			if (DayNightOverideTime >= 0f)
			{
				return DayNightOverideTime;
			}
			return (float)TotalSecondsToday / (float)SecondsPerDay * 24f;
		}
	}

	public event WorldTimeEventHandler OnTimeJump;

	private void Awake()
	{
		SDK.WorldTime.s_instance = this;
	}

	protected override void OnDestroy()
	{
		base.OnDestroy();
		if (SDK.WorldTime.s_instance == this)
		{
			SDK.WorldTime.s_instance = null;
		}
		ComponentUtils.NullOutObjectReferences(this);
	}

	public void Reset()
	{
		base.CurrentTime = new OEIDateTime(StartYear, StartMonth, StartDay, StartHour, StartMinute, StartSecond);
		base.AdventureStart = new OEIDateTime(base.CurrentTime);
		base.TimeInCombat = new TimeInterval();
		base.TimeSpentTravelling = new TimeInterval();
		DayNightOverideTime = -1f;
		SecondsTimer = 0f;
		base.FrameWorldSeconds = 0;
		base.RealWorldPlayTime = 0f;
		m_realWorldPlayTimeStartTimestamp = Time.realtimeSinceStartup;
		UpdateDayNightCycle();
	}

	public void Restored()
	{
		ValidateTime();
		UpdateDayNightCycle();
		HandleCurrentTimeJump(0, isMapTravel: false, isResting: false);
	}

	private void Start()
	{
		if (base.CurrentTime == null)
		{
			base.CurrentTime = new OEIDateTime(StartYear, StartMonth, StartDay, StartHour, StartMinute, StartSecond);
		}
		if (base.AdventureStart == null)
		{
			base.AdventureStart = new OEIDateTime(base.CurrentTime);
		}
		if (base.TimeInCombat == null)
		{
			base.TimeInCombat = new TimeInterval();
		}
		if (base.TimeSpentTravelling == null)
		{
			base.TimeSpentTravelling = new TimeInterval();
		}
		m_realWorldPlayTimeStartTimestamp = Time.realtimeSinceStartup;
		UpdateDayNightCycle();
	}

	private void Update()
	{
		if (Time.realtimeSinceStartup - m_realWorldPlayTimeStartTimestamp >= 1f)
		{
			base.RealWorldPlayTime += Time.realtimeSinceStartup - m_realWorldPlayTimeStartTimestamp;
			m_realWorldPlayTimeStartTimestamp = Time.realtimeSinceStartup;
		}
		SecondsTimer += Time.deltaTime;
		base.FrameWorldSeconds = Mathf.FloorToInt(SecondsTimer);
		SecondsTimer -= base.FrameWorldSeconds;
		if (SDK.GameState.InCombat)
		{
			base.TimeInCombat.AddSeconds(base.FrameWorldSeconds);
		}
	}

	public override void ValidateTime()
	{
		if (base.CurrentTime.TotalSeconds < 0)
		{
			base.CurrentTime.TotalSeconds = Mathf.Abs(base.CurrentTime.TotalSeconds);
		}
	}

	public bool IsDateTimeHoliday(OEIDateTime dateTime)
	{
		return dateTime != null && dateTime.Day == DaysPerMonth;
	}

	public void AdvanceTimeBySeconds(int seconds)
	{
		AdvanceTimeBySeconds(seconds, isTravel: false, isResting: false);
	}

	public void AdvanceTimeBySeconds(int secondsToAdvance, bool isTravel, bool isResting)
	{
		base.CurrentTime.AddSeconds(secondsToAdvance);
		HandleCurrentTimeJump(secondsToAdvance, isTravel, isResting);
		UpdateDayNightCycle();
	}

	public void AdvanceTimeByHours(int hoursToAdvance, bool isResting)
	{
		base.CurrentTime.AddHours(hoursToAdvance);
		HandleCurrentTimeJump(hoursToAdvance * MinutesPerHour * SecondsPerMinute, isMapTravel: false, isResting);
		UpdateDayNightCycle();
		Console.AddMessage(Console.Format(GUIUtils.GetTextWithLinks(220), hoursToAdvance));
	}

	public void AdvanceTimeToHour(int hour)
	{
		int num = 0;
		num = ((base.CurrentTime.Hour >= hour) ? (HoursPerDay - base.CurrentTime.Hour + hour) : (hour - base.CurrentTime.Hour));
		AdvanceTimeByHours(num, isResting: false);
	}

	public bool IsCurrentlyDaytime()
	{
		return DayNightTime < (float)NighttimeStartHour && DayNightTime >= (float)DaytimeStartHour;
	}

	public bool IsCurrentlyNighttime()
	{
		return DayNightTime >= (float)NighttimeStartHour || DayNightTime < (float)DaytimeStartHour;
	}

	private void UpdateDayNightCycle()
	{
		if ((bool)DayNight)
		{
			DayNight.twentyFourHourTime = DayNightTime;
		}
	}

	public OEIDateTime GetNextOccuranceOfDate(int month, int day, int hour)
	{
		OEIDateTime oEIDateTime = base.CurrentTime as OEIDateTime;
		OEIDateTime oEIDateTime2 = new OEIDateTime(oEIDateTime.Year, month, day, hour, 0, 0);
		if (oEIDateTime2.TotalSeconds < oEIDateTime.TotalSeconds)
		{
			oEIDateTime2.AddYears(1);
		}
		return oEIDateTime2;
	}

	public void SetDayNightOverrideTime(float time)
	{
		DayNightOverideTime = time;
		UpdateDayNightCycle();
	}

	public void ClearDayNightOverrideTime()
	{
		DayNightOverideTime = -1f;
		UpdateDayNightCycle();
	}

	public override void SetDayNightCycle(PE_DayNightRender dayNight)
	{
		DayNight = dayNight;
		UpdateDayNightCycle();
	}

	public override void UnsetDayNightCycle(PE_DayNightRender dayNight)
	{
		if (DayNight == dayNight)
		{
			DayNight = null;
		}
	}

	public string GetTimeDisplayString()
	{
		return base.CurrentTime.GetTime();
	}

	public string GetDateDisplayString()
	{
		return base.CurrentTime.GetDate();
	}

	public void HandleCurrentTimeJump(int gameSeconds, bool isMapTravel, bool isResting)
	{
		if (this.OnTimeJump != null)
		{
			this.OnTimeJump(gameSeconds, isMapTravel, isResting);
		}
	}
}

