38			public int CompareTo(ReactivitySoundRequest other)
39			{
40				if (audioHook == other.audioHook)
41				{
42					if (IsReputationSound() && other.IsReputationSound())
43					{
44						int num = (int)repChangeStrength;
45						return num.CompareTo((int)other.repChangeStrength);
46					}
47					return 0;
48				}
49				if (audioHook == UIAudioList.UIAudioType.ConversationNewMap)
50				{
51					return -1;
52				}
53				if (other.audioHook == UIAudioList.UIAudioType.ConversationNewMap)
54				{
55					return 1;
56				}
57				bool flag = IsReputationSound();
58				bool flag2 = other.IsReputationSound();
59				if (flag && !flag2)
60				{
61					return -1;
62				}
63				if (flag2 && !flag)
64				{
65					return 1;
66				}
67				if (flag && flag2)
68				{
69					if (repChangeStrength != other.repChangeStrength)
70					{
71						int num2 = (int)other.repChangeStrength;
72						return num2.CompareTo((int)repChangeStrength);
73					}
74					if ((audioHook == UIAudioList.UIAudioType.ConversationPosAxisUp || audioHook == UIAudioList.UIAudioType.ConversationPosAxisDown) && (other.audioHook == UIAudioList.UIAudioType.ConversationNegAxisUp || other.audioHook == UIAudioList.UIAudioType.ConversationNegAxisDown))
75					{
76						return -1;
77					}
78					if ((other.audioHook == UIAudioList.UIAudioType.ConversationPosAxisUp || other.audioHook == UIAudioList.UIAudioType.ConversationPosAxisDown) && (audioHook == UIAudioList.UIAudioType.ConversationNegAxisUp || audioHook == UIAudioList.UIAudioType.ConversationNegAxisDown))
79					{
80						return 1;
81					}
82				}
83				return 0;
84			}
