357		public override void HandleInput()
358		{
359			if (m_ActiveFlowChart == null || m_ActiveFlowChart.CurrentFlowChart == null || ShowHideTween.enabled)
360			{
361				return;
362			}
363			int num = TextList.LineAt(GameInput.MousePosition);
364			int num2 = LineToResponse(num);
365			int num3 = LineToResponse(m_TextListMousedLine);
366			if (num2 != num3)
367			{
368				if (m_TextListMousedLine >= 0)
369				{
370					TextList.Alter(m_TextListMousedLine, m_MouseTextPreviousText);
371				}
372				if (num2 >= 0 && num2 < m_OutstandingResponses)
373				{
374					List<PlayerResponseNode> responseNodes = conversation.GetResponseNodes(m_ActiveFlowChart);
375					m_MouseTextPreviousText = TextList.GetParagraph(num);
376					if (num2 >= responseNodes.Count || conversation.PassesConditionalsEx(responseNodes[num2], m_ActiveFlowChart))
377					{
378						TextList.Alter(num, m_RespMousedColor + NGUITools.StripColorSymbols(m_MouseTextPreviousText) + "[-]");
379					}
380					m_TextListMousedLine = num;
381				}
382				else
383				{
384					m_TextListMousedLine = -1;
385				}
386			}
387			if (GameInput.GetControlDown(MappedControl.CONV_CONTINUE))
388			{
389				ContinueButton.ForceDown(state: true);
390				if (ContinueButton.gameObject.activeInHierarchy)
391				{
392					GlobalAudioPlayer.SPlay(UIAudioList.UIAudioType.ButtonDown);
393				}
394			}
395			if (GameInput.GetControlUp(MappedControl.CONV_CONTINUE))
396			{
397				if (ContinueButton.gameObject.activeInHierarchy)
398				{
399					GlobalAudioPlayer.SPlay(UIAudioList.UIAudioType.ButtonUp);
400				}
401				OnButton(null);
402				ContinueButton.ForceDown(state: false);
403			}
404			else if (GameInput.NumberPressed > 0)
405			{
406				PlayerKeyInput(GameInput.NumberPressed - 1);
407			}
408			else if (GameInput.GetMouseButtonDown(0, setHandled: true))
409			{
410				mWasDownLine = num2;
411			}
412			else if (mWasDownLine >= 0 && GameInput.GetMouseButtonUp(0, setHandled: true))
413			{
414				if (mWasDownLine == num2)
415				{
416					PlayerKeyInput(num2);
417				}
418				mWasDownLine = -1;
419			}
420			if (GameInput.GetMouseButtonUp(0, setHandled: false))
421			{
422				mWasDownLine = -1;
423			}
424			base.HandleInput();
425		}
