447		private void PlayerInput(int number)
448		{
449			List<PlayerResponseNode> responseNodes = conversation.GetResponseNodes(m_ActiveFlowChart);
450			if (number < 0 || number >= responseNodes.Count || !conversation.PassesConditionalsEx(responseNodes[number], m_ActiveFlowChart))
451			{
452				return;
453			}
454			ClearReactivityText();
455			GlobalAudioPlayer.SPlay(UIAudioList.UIAudioType.ButtonDown);
456			GlobalAudioPlayer.SPlay(UIAudioList.UIAudioType.ButtonUp);
457			bool flag = MarkedAsRead(number);
458			MoveToNode(responseNodes[number].NodeID);
459			FlowChartNode nextNode = conversation.GetNextNode(m_ActiveFlowChart);
460			bool flag2 = conversation.GetNode(m_ActiveFlowChart.CurrentNodeID).NodeType == FlowChartNodeType.PlayerResponse;
461			if (!flag2 || (nextNode != null && nextNode.NodeID != m_CurrentNodeId))
462			{
463				CheckRemoveResponses();
464				if (!flag)
465				{
466					AwardStatCheckXP(responseNodes[number]);
467				}
468				string text = SDK.GUIUtils.GetText(2203);
469				string text2 = Game.CharacterStats.NameColored(Game.GameState.s_playerCharacter.gameObject) + text + m_PlayerSpeakerTextColor + conversation.GetActiveNodeText(m_ActiveFlowChart);
470				ConsoleMessage(text2);
471				m_PlayerResponseLines = TextList.Add(text2 + Environment.NewLine);
472			}
473			if (flag2)
474			{
475				if (nextNode != null)
476				{
477					MoveToNode(nextNode.NodeID);
478				}
479				else
480				{
481					End();
482				}
483			}
484		}
