using UnityEngine;

public class UIConversationManager : UIHudWindow
{
	private struct ReactivitySoundRequest : IComparable<ReactivitySoundRequest>
	{
		public SDK.Reputation.ChangeStrength repChangeStrength;

		public UIAudioList.UIAudioType audioHook;

		public ReactivitySoundRequest(UIAudioList.UIAudioType hookToPlay)
		{
			repChangeStrength = SDK.Reputation.ChangeStrength.None;
			audioHook = hookToPlay;
		}

		public ReactivitySoundRequest(UIAudioList.UIAudioType hookToPlay, SDK.Reputation.ChangeStrength strength)
		{
			repChangeStrength = strength;
			audioHook = hookToPlay;
		}

		public bool IsReputationSound()
		{
			return (audioHook == UIAudioList.UIAudioType.ConversationPosAxisUp || audioHook == UIAudioList.UIAudioType.ConversationPosAxisDown || audioHook == UIAudioList.UIAudioType.ConversationNegAxisUp || audioHook == UIAudioList.UIAudioType.ConversationNegAxisDown) && repChangeStrength != SDK.Reputation.ChangeStrength.None;
		}

		public int CompareTo(ReactivitySoundRequest other)
		{
			if (audioHook == other.audioHook)
			{
				if (IsReputationSound() && other.IsReputationSound())
				{
					int num = (int)repChangeStrength;
					return num.CompareTo((int)other.repChangeStrength);
				}
				return 0;
			}
			if (audioHook == UIAudioList.UIAudioType.ConversationNewMap)
			{
				return -1;
			}
			if (other.audioHook == UIAudioList.UIAudioType.ConversationNewMap)
			{
				return 1;
			}
			bool flag = IsReputationSound();
			bool flag2 = other.IsReputationSound();
			if (flag && !flag2)
			{
				return -1;
			}
			if (flag2 && !flag)
			{
				return 1;
			}
			if (flag && flag2)
			{
				if (repChangeStrength != other.repChangeStrength)
				{
					int num2 = (int)other.repChangeStrength;
					return num2.CompareTo((int)repChangeStrength);
				}
				if ((audioHook == UIAudioList.UIAudioType.ConversationPosAxisUp || audioHook == UIAudioList.UIAudioType.ConversationPosAxisDown) && (other.audioHook == UIAudioList.UIAudioType.ConversationNegAxisUp || other.audioHook == UIAudioList.UIAudioType.ConversationNegAxisDown))
				{
					return -1;
				}
				if ((other.audioHook == UIAudioList.UIAudioType.ConversationPosAxisUp || other.audioHook == UIAudioList.UIAudioType.ConversationPosAxisDown) && (audioHook == UIAudioList.UIAudioType.ConversationNegAxisUp || audioHook == UIAudioList.UIAudioType.ConversationNegAxisDown))
				{
					return 1;
				}
			}
			return 0;
		}
	}

