	private static char[] m_QuotePairs = new char[24]
	{
		'"', '"', '“', '”', '„', '“', '„', '”', '«', '»',
		'»', '«', '슻', '슫', '「', '」', '『', '』', '‹', '›',
		'‚', '‘', '‘', '’'
	};

	private bool m_IncludedName;

