	private string m_RespMousedColor => NGUITools.EncodeColorFormat(ConversationResponseMouseoverColor);

	private string m_FollowedRespColor => NGUITools.EncodeColorFormat(ConversationResponseReadColor);

	private string m_DisabledRespColor => NGUITools.EncodeColorFormat(ConversationResponseDisabledColor);

	private string m_SpeakerNameColor => NGUITools.EncodeColorFormat(ConversationSpeakerNameColor);

	private string m_SpeakerTextColor => NGUITools.EncodeColorFormat(ConversationSpeakerTextColor);

	private string m_PlayerSpeakerTextColor => NGUITools.EncodeColorFormat(ConversationPlayerTextColor);

	private Conversation conversation
	{
		get
		{
			if (m_ActiveFlowChart == null)
			{
				return null;
			}
			return m_ActiveFlowChart.CurrentFlowChart as Conversation;
		}
	}

	private int m_HandleMaxPosition => (int)((float)(Screen.height / 2) - ConversationBox.transform.localPosition.y) * 2;

	public bool ForceRefresh { private get; set; }

	public GameObject Speaker => speaker;

	public static string GetColorOrEmpty(GameObject speaker)
	{
		if (speaker != null)
		{
			NPCAppearance component = speaker.GetComponent<NPCAppearance>();
			if ((bool)component)
			{
				Color dialogColor = component.DialogColor;
				if (dialogColor.grayscale < 0.3f)
				{
					dialogColor.r = 1f - 0.7f * (1f - dialogColor.r);
					dialogColor.b = 1f - 0.7f * (1f - dialogColor.b);
					dialogColor.g = 1f - 0.7f * (1f - dialogColor.g);
				}
				return "[" + NGUITools.EncodeColor(dialogColor) + "]";
			}
		}
		return string.Empty;
	}

	public string GetCharacterColor(GameObject speaker)
	{
		string text = GetColorOrEmpty(speaker);
		if (string.IsNullOrEmpty(text))
		{
			text = m_SpeakerNameColor;
		}
		return text;
	}

	private void Awake()
	{
		s_Instance = this;
		CanDeactivate = false;
		if (ConversationPanel != null)
		{
			ConversationPanel.gameObject.SetActive(value: true);
		}
		ConversationDescriptionColorString = NGUITools.EncodeColorFormat(ConversationDescriptionColor);
		ConversationSpeakerNameColorString = NGUITools.EncodeColorFormat(ConversationSpeakerNameColor);
	}

	private void Start()
	{
		UIMultiSpriteImageButton continueButton = ContinueButton;
		continueButton.onClick = (UIEventListener.VoidDelegate)Delegate.Combine(continueButton.onClick, new UIEventListener.VoidDelegate(OnButton));
		m_TextInitialTransform = ConversationTextList.transform.localPosition;
		ConversationManager instance = ConversationManager.Instance;
		instance.FlowChartPlayerAdded = (ConversationManager.FlowChartPlayerDelegate)Delegate.Combine(instance.FlowChartPlayerAdded, new ConversationManager.FlowChartPlayerDelegate(FlowChartPlayerAdded));
		if ((bool)Game.QuestManager.Instance)
		{
			Game.QuestManager instance2 = Game.QuestManager.Instance;
			instance2.OnQuestAdvanced = (SDK.QuestManager.QuestDelegate)Delegate.Combine(instance2.OnQuestAdvanced, new SDK.QuestManager.QuestDelegate(OnQuestAdvanced));
		}
	}

	private void Update()
	{
		if (!m_Init)
		{
			m_Init = true;
			HideConversationImmediate();
		}
		if (m_waitOnHideTweenThenHide)
		{
			ReactivityPanel.alpha *= ConversationPanel.alpha;
		}
		CheckRecreateContent();
		if (m_waitOnHideTweenThenHide && (!ShowHideTween.enabled || !ShowHideTween.gameObject.activeInHierarchy))
		{
			HideConversationImmediate();
		}
	}

	private void FlowChartPlayerAdded(FlowChartPlayer player)
	{
		if (!ConversationManager.IsWMEConversation(player))
		{
			CheckRecreateContent();
		}
	}

	public void OnQuestAdvanced(Quest quest)
	{
		ForceRefresh = true;
	}

	public override void Init()
	{
		base.Init();
		SetPaperdoll(PrimarySpeakerPortrait, PrimarySpeakerFrameNone, null);
		SetPaperdoll(InterjectorPortrait, InterjectorFrameNone, null);
	}

	protected override void OnDestroy()
	{
		if ((bool)ConversationManager.Instance)
		{
			ConversationManager instance = ConversationManager.Instance;
			instance.FlowChartPlayerAdded = (ConversationManager.FlowChartPlayerDelegate)Delegate.Remove(instance.FlowChartPlayerAdded, new ConversationManager.FlowChartPlayerDelegate(FlowChartPlayerAdded));
		}
		if ((bool)Game.QuestManager.Instance)
		{
			Game.QuestManager instance2 = Game.QuestManager.Instance;
			instance2.OnQuestAdvanced = (SDK.QuestManager.QuestDelegate)Delegate.Remove(instance2.OnQuestAdvanced, new SDK.QuestManager.QuestDelegate(OnQuestAdvanced));
		}
		if (s_Instance == this)
		{
			s_Instance = null;
		}
		if (ContinueButton != null)
		{
			UIMultiSpriteImageButton continueButton = ContinueButton;
			continueButton.onClick = (UIEventListener.VoidDelegate)Delegate.Remove(continueButton.onClick, new UIEventListener.VoidDelegate(OnButton));
		}
		base.OnDestroy();
		ComponentUtils.NullOutObjectReferences(this);
	}

	public override void HandleInput()
	{
		if (m_ActiveFlowChart == null || m_ActiveFlowChart.CurrentFlowChart == null || ShowHideTween.enabled)
		{
			return;
		}
		int num = TextList.LineAt(GameInput.MousePosition);
		int num2 = LineToResponse(num);
		int num3 = LineToResponse(m_TextListMousedLine);
		if (num2 != num3)
		{
			if (m_TextListMousedLine >= 0)
			{
				TextList.Alter(m_TextListMousedLine, m_MouseTextPreviousText);
			}
			if (num2 >= 0 && num2 < m_OutstandingResponses)
			{
				List<PlayerResponseNode> responseNodes = conversation.GetResponseNodes(m_ActiveFlowChart);
				m_MouseTextPreviousText = TextList.GetParagraph(num);
				if (num2 >= responseNodes.Count || conversation.PassesConditionalsEx(responseNodes[num2], m_ActiveFlowChart))
				{
					TextList.Alter(num, m_RespMousedColor + NGUITools.StripColorSymbols(m_MouseTextPreviousText) + "[-]");
				}
				m_TextListMousedLine = num;
			}
			else
			{
				m_TextListMousedLine = -1;
			}
		}
		if (GameInput.GetControlDown(MappedControl.CONV_CONTINUE))
		{
			ContinueButton.ForceDown(state: true);
			if (ContinueButton.gameObject.activeInHierarchy)
			{
				GlobalAudioPlayer.SPlay(UIAudioList.UIAudioType.ButtonDown);
			}
		}
		if (GameInput.GetControlUp(MappedControl.CONV_CONTINUE))
		{
			if (ContinueButton.gameObject.activeInHierarchy)
			{
				GlobalAudioPlayer.SPlay(UIAudioList.UIAudioType.ButtonUp);
			}
			OnButton(null);
			ContinueButton.ForceDown(state: false);
		}
		else if (GameInput.NumberPressed > 0)
		{
			PlayerKeyInput(GameInput.NumberPressed - 1);
		}
		else if (GameInput.GetMouseButtonDown(0, setHandled: true))
		{
			mWasDownLine = num2;
		}
		else if (mWasDownLine >= 0 && GameInput.GetMouseButtonUp(0, setHandled: true))
		{
			if (mWasDownLine == num2)
			{
				PlayerKeyInput(num2);
			}
			mWasDownLine = -1;
		}
		if (GameInput.GetMouseButtonUp(0, setHandled: false))
		{
			mWasDownLine = -1;
		}
		base.HandleInput();
	}

	private int LineToResponse(int line)
	{
		return m_OutstandingResponses - TextList.ParagraphCount + line;
	}

	private void PlayerKeyInput(int number)
	{
		if (m_ActiveFlowChart != null)
		{
			if (Conversation.LocalizationDebuggingEnabled)
			{
				PlayerInputDebug(number);
			}
			else
			{
				PlayerInput(number);
			}
		}
	}

	private void PlayerInput(int number)
	{
		List<PlayerResponseNode> responseNodes = conversation.GetResponseNodes(m_ActiveFlowChart);
		if (number < 0 || number >= responseNodes.Count || !conversation.PassesConditionalsEx(responseNodes[number], m_ActiveFlowChart))
		{
			return;
		}
		ClearReactivityText();
		GlobalAudioPlayer.SPlay(UIAudioList.UIAudioType.ButtonDown);
		GlobalAudioPlayer.SPlay(UIAudioList.UIAudioType.ButtonUp);
		bool flag = MarkedAsRead(number);
		MoveToNode(responseNodes[number].NodeID);
		FlowChartNode nextNode = conversation.GetNextNode(m_ActiveFlowChart);
		bool flag2 = conversation.GetNode(m_ActiveFlowChart.CurrentNodeID).NodeType == FlowChartNodeType.PlayerResponse;
		if (!flag2 || (nextNode != null && nextNode.NodeID != m_CurrentNodeId))
		{
			CheckRemoveResponses();
			if (!flag)
			{
				AwardStatCheckXP(responseNodes[number]);
			}
			string text = SDK.GUIUtils.GetText(2203);
			string text2 = Game.CharacterStats.NameColored(Game.GameState.s_playerCharacter.gameObject) + text + m_PlayerSpeakerTextColor + conversation.GetActiveNodeText(m_ActiveFlowChart);
			ConsoleMessage(text2);
			m_PlayerResponseLines = TextList.Add(text2 + Environment.NewLine);
		}
		if (flag2)
		{
			if (nextNode != null)
			{
				MoveToNode(nextNode.NodeID);
			}
			else
			{
				End();
			}
		}
	}

	private void PlayerInputDebug(int number)
	{
		List<FlowChartNode> allNodesFromActiveNode = conversation.GetAllNodesFromActiveNode(m_ActiveFlowChart);
		if (number >= 0 && number < allNodesFromActiveNode.Count)
		{
			CheckRemoveResponses();
			MoveToNode(allNodesFromActiveNode[number].NodeID);
			ForceRefresh = true;
		}
		else if (number == allNodesFromActiveNode.Count)
		{
			CheckRemoveResponses();
			conversation.MoveToPreviousNode(m_ActiveFlowChart);
			ForceRefresh = true;
		}
	}

	public static bool IsInConversation()
	{
		return Instance != null && ConversationManager.Instance != null && ConversationManager.Instance.GetActiveConversationForHUD() != null && (bool)UIEndGameSlidesManager.Instance && !UIEndGameSlidesManager.Instance.IsVisible;
	}

	public bool HasConversationNodeBeenCompletedAlready()
	{
		if (conversation == null || m_ActiveFlowChart == null)
		{
			return false;
		}
		return ConversationManager.Instance.GetNodeCompleted(conversation, m_ActiveFlowChart.CurrentNodeID);
	}

	public static void OnScriptMoneyChanged(int moneyAmount)
	{
		if (IsInConversation() && moneyAmount != 0)
		{
			if (moneyAmount > 0)
			{
				Instance.AddReactivityText(SDK.GUIUtils.Format(176, moneyAmount));
				Instance.PlayReactivitySFx(UIAudioList.UIAudioType.ConversationMoneyGained);
			}
			else
			{
				Instance.AddReactivityText(SDK.GUIUtils.Format(177, -moneyAmount));
				Instance.PlayReactivitySFx(UIAudioList.UIAudioType.ConversationMoneyLost);
			}
		}
	}

	public static void OnScriptMapVisibilityChanged(MapType map, MapData.VisibilityType newVisibility)
	{
		if (IsInConversation() && newVisibility == MapData.VisibilityType.Unlocked)
		{
			MapData map2 = WorldMap.Instance.GetMap(map);
			if (map2 != null)
			{
				Instance.AddReactivityText(SDK.GUIUtils.Format(3044, map2.GetDisplayNameText()));
				Instance.PlayReactivitySFx(UIAudioList.UIAudioType.ConversationNewMap);
			}
		}
	}

	public static void OnScriptRegionOwnershipChanged(Game.Region region, FactionName factionControl)
	{
		if (!IsInConversation() || factionControl == FactionName.None)
		{
			return;
		}
		string text = string.Empty;
		if (factionControl == FactionName.Player)
		{
			text = Game.GameState.s_playerCharacter.GetComponent<Game.CharacterStats>().Name();
		}
		else
		{
			SDK.Reputation reputation = Game.ReputationManager.Instance.GetReputation((int)factionControl);
			if (reputation != null)
			{
				text = reputation.Name.GetText();
			}
		}
		if (region != null)
		{
			Instance.AddReactivityText(SDK.GUIUtils.Format(3092, region.Name.GetText(), text));
			Instance.PlayReactivitySFx(UIAudioList.UIAudioType.ConversationNewMap);
		}
	}

	public static void OnScriptInventoryGained(Item item, int qty, bool stash)
	{
		if (IsInConversation())
		{
			Currency currency = item as Currency;
			if (currency != null)
			{
				Instance.AddReactivityText(SDK.GUIUtils.Format(1570, Mathf.RoundToInt((float)qty * currency.GetValue())));
			}
			else if (stash)
			{
				Instance.AddReactivityText(SDK.GUIUtils.Format(3046, item.Name));
			}
			else
			{
				Instance.AddReactivityText(SDK.GUIUtils.Format(3045, item.Name));
			}
			Instance.PlayReactivitySFx(UIAudioList.UIAudioType.ConversationItemGained);
		}
	}

	public static void OnScriptInventoryLost(Item item)
	{
