	private void PlayReactivitySFx(UIAudioList.UIAudioType soundHook, SDK.Reputation.ChangeStrength strength)
	{
		m_reactivitySoundsToPlay.Add(new ReactivitySoundRequest(soundHook, strength));
		if (m_coroutineWaitThenProcessAudio == null)
		{
			m_coroutineWaitThenProcessAudio = Coroutine_WaitThenPlayAppropriateReactivityAudio();
			StartCoroutine(m_coroutineWaitThenProcessAudio);
		}
	}

	private IEnumerator Coroutine_WaitThenPlayAppropriateReactivityAudio()
	{
		yield return null;
		yield return null;
		yield return null;
		m_reactivitySoundsToPlay.Sort();
		bool soundPlayed = false;
		bool reputationSoundPlayed = false;
		for (int i = 0; i < m_reactivitySoundsToPlay.Count; i++)
		{
			ReactivitySoundRequest curSound = m_reactivitySoundsToPlay[i];
			if (curSound.audioHook == UIAudioList.UIAudioType.ConversationNewMap)
			{
				GlobalAudioPlayer.SPlay(curSound.audioHook);
				soundPlayed = true;
			}
			else if (!reputationSoundPlayed && curSound.IsReputationSound())
			{
				GlobalAudioPlayer.SPlay(curSound.audioHook);
				soundPlayed = true;
				reputationSoundPlayed = true;
			}
			else if (!soundPlayed)
			{
				GlobalAudioPlayer.SPlay(curSound.audioHook);
				soundPlayed = true;
			}
		}
		m_coroutineWaitThenProcessAudio = null;
		m_reactivitySoundsToPlay.Clear();
	}

