	public string ProcessSpeakerText(string text, string speakerName, string speakerNameColor, string defaultColor)
	{
		StringBuilder stringBuilder = new StringBuilder(text.Length);
		string text2 = string.Empty;
		if (!string.IsNullOrEmpty(speakerName))
		{
			string text3 = SDK.GUIUtils.GetText(2203);
			text2 = speakerNameColor + speakerName + text3;
		}
		stringBuilder.Append(ConversationDescriptionColorString);
		Stack<char> stack = new Stack<char>();
		for (int i = 0; i < text.Length; i++)
		{
			bool flag = false;
			bool flag2 = false;
			if (StringTableManager.CurrentLanguage.EnumLanguage != OEICommon.Language.polish || text[i] != '’')
			{
				for (int j = 0; j < m_QuotePairs.Length; j += 2)
				{
					if (text[i] == m_QuotePairs[j])
					{
						flag = true;
					}
					if (text[i] == m_QuotePairs[j + 1] && stack.Count > 0 && stack.Peek() == m_QuotePairs[j])
					{
						flag = true;
						flag2 = true;
					}
				}
			}
			if (flag)
			{
				if (flag2)
				{
					stack.Pop();
					stringBuilder.Append(text[i]);
					if (stack.Count == 0)
					{
						stringBuilder.Append(ConversationDescriptionColorString);
					}
				}
				else
				{
					stack.Push(text[i]);
					if (stack.Count > 0)
					{
						stringBuilder.Append(defaultColor);
					}
					stringBuilder.Append(text[i]);
				}
			}
			else if (text[i] == '\n')
			{
				if (!CurrentLanguageIsRussian() && stack.Count > 0)
				{
					stack.Clear();
					stringBuilder.Append(defaultColor);
				}
				stringBuilder.Append(text[i]);
			}
			else
			{
				stringBuilder.Append(text[i]);
			}
		}
		m_IncludedName = true;
		return text2 + stringBuilder.ToString();
	}

	private bool MarkedAsRead(int response)
