	private IEnumerator Coroutine_MakeSureNoFadeForConversation()
	{
		Game.FadeManager fadeMan = Game.FadeManager.Instance;
		float conversationSafetyTimeout = 10f;
		if (fadeMan != null && fadeMan.IsFadeActive() && (fadeMan.CurrentFadeType == SDK.FadeManager.FadeType.Cutscene || fadeMan.CurrentFadeType == SDK.FadeManager.FadeType.Script))
		{
			float timeStart = Time.realtimeSinceStartup;
			while (Time.realtimeSinceStartup - timeStart < conversationSafetyTimeout && fadeMan.IsFadeActive() && (fadeMan.CurrentFadeType == SDK.FadeManager.FadeType.Cutscene || fadeMan.CurrentFadeType == SDK.FadeManager.FadeType.Script))
			{
				yield return null;
			}
			if (Time.realtimeSinceStartup - timeStart > conversationSafetyTimeout)
			{
				Debug.LogError("UIConversationmanager - Conversation started, but fade from script or cutscene was still active returning from fade to prevent bad game state");
				fadeMan.FadeFrom(fadeMan.CurrentFadeType, 0.5f, fadeMan.GetFadeTargetColor());
			}
		}
	}

