		ShowHideTween.ResetTo(0f);
		ShowHideTween.enabled = false;
		ConversationPanel.alpha = 0f;
		m_waitOnHideTweenThenHide = false;
		if ((bool)PrimarySpeakerPortrait)
		{
			PrimarySpeakerPortrait.HidePaperDoll();
		}
		m_PrimarySpeaker = null;
		m_PrimarySpeakerMood = -1;
		if ((bool)InterjectorPortrait)
		{
			InterjectorPortrait.HidePaperDoll();
		}
		m_InterjectorMood = -1;
		ClearReactivityText();
		HideWindow();
	}

	private void CheckRemoveResponses()
	{
		for (int i = 0; i < m_OutstandingResponses; i++)
		{
			TextList.RemoveLast();
		}
		m_OutstandingResponses = 0;
		m_TextListMousedLine = -1;
	}

	private void CheckRemoveSpeakerLines()
	{
		for (int i = 0; i < m_OutstandingSpeakerLines; i++)
		{
			TextList.RemoveLast();
		}
		m_OutstandingSpeakerLines = 0;
		m_TextListMousedLine = -1;
	}

	private void OnButton(GameObject go)
	{
		if (m_ActiveFlowChart == null)
		{
			Debug.LogError("ActiveFlowChart is null in ConversationManager.");
			EndConversation();
		}
		if (conversation == null)
		{
			Debug.LogError("ActiveFlowChart.CurrentFlowChart is null or not a Conversation in ConversationManager.");
			EndConversation();
		}
		List<PlayerResponseNode> responseNodes = conversation.GetResponseNodes(m_ActiveFlowChart, qualifiedOnly: true);
		if (responseNodes.Count == 0)
		{
			ClearReactivityText();
			if (conversation.GetNextNode(m_ActiveFlowChart) == null || Conversation.LocalizationDebuggingEnabled)
			{
				End();
			}
			else
			{
				Continue();
			}
		}
	}

	private void Continue()
	{
		FlowChartNode flowChartNode = null;
		while ((!(flowChartNode is DialogueNode) || flowChartNode is ScriptNode) && !(conversation == null))
		{
			FlowChartNode nextNode = conversation.GetNextNode(m_ActiveFlowChart);
			if (flowChartNode == nextNode || nextNode == null)
			{
				break;
			}
			MoveToNode(nextNode.NodeID);
			flowChartNode = nextNode;
		}
	}

	private void MoveToNode(int nodeid)
	{
		GameObject gameObject = Game.GameState.s_playerCharacter.gameObject;
		if (gameObject != null)
		{
			AudioSource component = gameObject.GetComponent<AudioSource>();
			component.Stop();
		}
		conversation.MoveToNode(nodeid, m_ActiveFlowChart);
	}

	private void End()
	{
		if (m_ActiveFlowChart == null)
		{
			HideConversation();
		}
		else if (m_ActiveFlowChart.FlowChartDisplayMode == FlowChartPlayer.DisplayMode.Standard)
		{
			EndConversation();
		}
	}

	private void EndConversation()
	{
		if (m_ActiveFlowChart != null && (bool)ConversationManager.Instance)
		{
			ConversationManager.Instance.SetNodeCompleted(conversation, m_ActiveFlowChart.CurrentNodeID, complete: true);
			ConversationManager.Instance.EndConversation(m_ActiveFlowChart);
		}
		HideConversation();
		m_LastSpeakerPos = Vector3.zero;
	}

	private void HandleFadeOut()
	{
		Game.FadeManager instance = Game.FadeManager.Instance;
		instance.OnFadeEnded = (SDK.FadeManager.OnFadeEnd)Delegate.Remove(instance.OnFadeEnded, new SDK.FadeManager.OnFadeEnd(HandleFadeOut));
		bool flag = true;
		FlowChartPlayer activeFlowChart = m_ActiveFlowChart;
		if (activeFlowChart != null)
		{
			flag = activeFlowChart.FadeFromBlackOnExit;
			ConversationManager.Instance.EndConversation(activeFlowChart);
		}
		if (flag)
		{
			Game.FadeManager.Instance.FadeFromBlack(SDK.FadeManager.FadeType.Script, 0.75f);
		}
	}

	private static void ConsoleMessage(string str)
	{
		Console.AddMessage(str.Trim(), Console.ConsoleState.DIALOG_BIG);
	}

	private static void ConsoleBegin()
	{
	}

	private static void ConsoleEnd()
	{
	}
}

