using System.Collections.Generic;
using OEIFormats.FlowCharts.Quests;
using SDK;

namespace Game;

public class QuestManager : SDK.QuestManager
{
	private static List<Quest> QuestsToReset = new List<Quest>();

	public float MinorXpMultiplier;

	public float MajorXpMultiplier;

	public float MinorBeliefMutliplier;

	public float MajorBeliefMutliplier;

	public float BanishmentArmorMultiplier = 1.5f;

	public new static QuestManager Instance => SDK.QuestManager.s_instance as QuestManager;

	public new static QuestManager ToolInstance => SDK.QuestManager.s_instance as QuestManager;

	protected override void Awake()
	{
		m_experienceTable = new ExperienceTable();
		base.Awake();
	}

	public override void Update()
	{
		base.Update();
		lock (QuestsToReset)
		{
			for (int i = 0; i < QuestsToReset.Count; i++)
			{
				ResetQuest(QuestsToReset[i]);
			}
			QuestsToReset.Clear();
		}
	}

	protected override void CompleteQuestObjective(Quest quest, ObjectiveNode objective)
	{
		((ExperienceTable)m_experienceTable).CompleteQuestObjective(quest, base.QuestTrackers[quest.Filename].QuestLevel, objective);
	}

	protected override void CompleteQuest(Quest quest)
	{
		((ExperienceTable)m_experienceTable).CompleteQuest(quest, base.QuestTrackers[quest.Filename].QuestLevel);
	}

	public void CompleteAndRemoveQuest(string questName)
	{
		questName = SDK.QuestManager.FormatQuestName(questName);
		if (base.LoadedQuests.ContainsKey(questName))
		{
			CompleteAndRemoveQuest(base.LoadedQuests[questName]);
		}
	}

	public void CompleteAndRemoveQuest(Quest quest)
	{
		TriggerQuestEndState(quest, 0, failed: false);
		MarkQuestForReset(quest);
	}

	public static void MarkQuestForReset(Quest quest)
	{
		lock (QuestsToReset)
		{
			QuestsToReset.Add(quest);
		}
	}
}

