387				using ZipFile zipFile = new ZipFile(text2, Encoding.UTF8);
388				zipFile.ExtractAll(PersistenceManager.s_tempSavePath);
389			}
390			catch (Exception ex)
391			{
392				Debug.LogError(ex.ToString());
393				Debug.LogError(text + " ZIP FILE IS CORRUPT!");
394				return null;
395			}
396			SaveGameInfo saveGameInfo = SaveGameInfo.Load(PersistenceManager.s_tempSavePath, sizeStyle);
