using Ionic.Zip;
using SDK;
using UnityEngine;
using UnityEngine.SceneManagement;

namespace Game;

public class GameResources : SDK.GameResources
{
	private const string VOAssetPath = "assets/data/audio/vocalization/vo assets";

	private static bool s_loading = false;

	private static AssetBundle s_currentScene = null;

	private static Dictionary<string, WeakReference> s_loadedAssets = new Dictionary<string, WeakReference>(15000);

	private static HashSet<string> s_missingAssets = new HashSet<string>();

	private static Dictionary<string, AssetBundleRequest> s_asyncAssetLoads = new Dictionary<string, AssetBundleRequest>(100);

	private static List<string> s_clearAssetList = new List<string>();

	private static Dictionary<string, List<string>> s_voAssetsAtPath;

	public static void ClearAssetReferences(Type type)
	{
		foreach (KeyValuePair<string, WeakReference> s_loadedAsset in s_loadedAssets)
		{
			if (s_loadedAsset.Value != null)
			{
				UnityEngine.Object @object = s_loadedAsset.Value.Target as UnityEngine.Object;
				if (@object != null && @object.GetType() == type)
				{
					s_clearAssetList.Add(s_loadedAsset.Key);
				}
			}
			else
			{
				s_clearAssetList.Add(s_loadedAsset.Key);
			}
		}
		foreach (string s_clearAsset in s_clearAssetList)
		{
			s_loadedAssets.Remove(s_clearAsset);
		}
		s_clearAssetList.Clear();
	}

	public static void ClearAssetReference(string loadedAsset)
	{
		foreach (KeyValuePair<string, WeakReference> s_loadedAsset in s_loadedAssets)
		{
			if (s_loadedAsset.Key == loadedAsset)
			{
				s_loadedAssets.Remove(loadedAsset);
				break;
			}
		}
	}

	public static void ClearAssetReference(UnityEngine.Object loadedAsset)
	{
		foreach (KeyValuePair<string, WeakReference> s_loadedAsset in s_loadedAssets)
		{
			if (s_loadedAsset.Value != null)
			{
				UnityEngine.Object @object = s_loadedAsset.Value.Target as UnityEngine.Object;
				if (@object != null && @object == loadedAsset)
				{
					s_clearAssetList.Add(s_loadedAsset.Key);
				}
			}
			else
			{
				s_clearAssetList.Add(s_loadedAsset.Key);
			}
		}
		foreach (string s_clearAsset in s_clearAssetList)
		{
			s_loadedAssets.Remove(s_clearAsset);
		}
		s_clearAssetList.Clear();
	}

	public static void ClearAssetReferences()
	{
		s_loadedAssets.Clear();
		Caching.CleanCache();
		Debug.Log("GAMERESOURCES.CLEARASSETREFERENCES: CALLING RESOURCES.UNLOADUNUSEDASSETS");
		Resources.UnloadUnusedAssets();
		Debug.Log("GAMERESOURCES.CLEARASSETREFERENCES: CALLING SYSTEM.GC.COLLECT");
		GC.Collect();
	}

	public static void TakeScreenShot()
	{
		int num = 84;
		int num2 = 150;
		string path = Path.Combine(SDK.GameResources.TemporaryCachePath, "screenshot.png");
		if (File.Exists(path))
		{
			File.Delete(path);
		}
		List<Camera> list = new List<Camera>();
		list.AddRange(from c in UnityEngine.Object.FindObjectsOfType<Camera>()
			where c.GetComponent<UICamera>() == null
			select c);
		list.Sort(PE_GameRender.CameraDepthComparer.Instance);
		RenderTexture renderTexture = new RenderTexture(num2, num, 24);
		Texture2D texture2D = new Texture2D(num2, num, TextureFormat.RGB24, mipmap: false);
		foreach (Camera item in list)
		{
			if (item.targetTexture == null && item.name != "Camera_DynamicNormals" && item.name != "Camera_DynamicDepth" && item.name != "Camera_DynamicAlbedo" && item.name != "Camera_DynamicDeferred")
			{
				item.targetTexture = renderTexture;
			}
		}
		Shader.SetGlobalInt("_FlipYForRenderTextureUV", 1);
		foreach (Camera item2 in list)
		{
			if (item2.gameObject.activeInHierarchy && item2.enabled && !(item2.name == "GUI") && !(item2.name == "InGameUIPass") && !(item2.name == "PostProcess") && !item2.name.Contains("WatcherFatigueCamera") && !item2.name.Contains("SoulMemoryCamera") && !item2.name.Contains("GammaCamera"))
			{
				item2.Render();
			}
		}
		Shader.SetGlobalInt("_FlipYForRenderTextureUV", 0);
		foreach (Camera item3 in list)
		{
			if (item3.targetTexture == renderTexture)
			{
				item3.targetTexture = null;
				item3.ResetAspect();
			}
		}
		RenderTexture.active = renderTexture;
		texture2D.ReadPixels(new Rect(0f, 0f, num2, num), 0, 0);
		texture2D.Apply();
		RenderTexture.active = null;
		renderTexture.DiscardContents(discardColor: true, discardDepth: true);
		SDK.GameUtilities.Destroy(renderTexture);
		byte[] bytes = texture2D.EncodeToPNG();
		File.WriteAllBytes(path, bytes);
		SDK.GameUtilities.Destroy(texture2D);
	}

	private static void LoadLastSaveOnFadeEnd()
	{
		GameInput.DisableInput = false;
		FadeManager instance = FadeManager.Instance;
		instance.OnFadeEnded = (SDK.FadeManager.OnFadeEnd)Delegate.Remove(instance.OnFadeEnded, new SDK.FadeManager.OnFadeEnd(LoadLastSaveOnFadeEnd));
		bool flag = false;
		while (!flag)
		{
			IEnumerable<SaveGameInfo> enumerable = SaveGameInfo.CachedSaveGameInfo.OrderByDescending((SaveGameInfo sgi) => sgi?.RealTimestamp ?? DateTime.Now);
			if (enumerable != null && enumerable.Any())
			{
				flag = LoadGame(enumerable.First().FileName);
				continue;
			}
			break;
		}
		if (!flag)
		{
			FadeManager.Instance.FadeFromBlack(SDK.FadeManager.FadeType.AreaTransition, 0.35f);
		}
	}

	public static void LoadLastGame(bool fadeOut)
	{
		if (fadeOut)
		{
			FadeManager.Instance.FadeMusic = true;
			FadeManager.Instance.FadeAudio = true;
			FadeManager.Instance.FadeToBlack(SDK.FadeManager.FadeType.AreaTransition, 0.35f);
			FadeManager instance = FadeManager.Instance;
			instance.OnFadeEnded = (SDK.FadeManager.OnFadeEnd)Delegate.Combine(instance.OnFadeEnded, new SDK.FadeManager.OnFadeEnd(LoadLastSaveOnFadeEnd));
			GameInput.DisableInput = true;
			return;
		}
		bool flag = false;
		while (!flag)
		{
			IEnumerable<SaveGameInfo> enumerable = SaveGameInfo.CachedSaveGameInfo.OrderByDescending((SaveGameInfo sgi) => sgi?.RealTimestamp ?? DateTime.Now);
			if (enumerable != null && enumerable.Any())
			{
				LoadGame(enumerable.First().FileName);
				continue;
			}
			break;
		}
		if (!flag)
		{
			FadeManager.Instance.FadeFromBlack(SDK.FadeManager.FadeType.AreaTransition, 0.35f);
		}
	}

	public static SaveGameInfo GetContinueSaveGame()
	{
		IEnumerable<SaveGameInfo> enumerable = SaveGameInfo.CachedSaveGameInfo.OrderByDescending((SaveGameInfo sgi) => sgi?.RealTimestamp ?? DateTime.Now);
		if (enumerable != null && enumerable.Count() > 0)
		{
			return enumerable.First();
		}
		return null;
	}

	public static bool SaveGameExists()
	{
		return SaveGameInfo.SaveGameExists();
	}

	public static bool SaveGameExists(string filename)
	{
		return GetCachedSaveGameInfo(filename) != null;
	}

	public static SaveGameInfo GetCachedSaveGameInfo(string filename)
	{
		return SaveGameInfo.CachedSaveGameInfo.Find((SaveGameInfo sv) => sv.FileName.Equals(filename));
	}

	public static void WriteTrialOfIronReadme()
	{
	}

	public static bool SaveGame(string filename)
	{
		return SaveGame(filename, string.Empty);
	}

	public static bool SaveGame(string filename, string userString, bool ShouldCloudSync = false)
	{
		SaveGameInfo.WaitUntilSafeToSaveLoad();
		if (SDK.GameState.InCombat)
		{
			return false;
		}
		if (SDK.GameState.IsTransitionInProgress)
		{
			return false;
		}
		SDK.GameResources.OnPreSaveGame();
		if ((bool)QuestManager.Instance)
		{
			QuestManager.Instance.Update();
		}
		string temporaryCachePath = SDK.GameResources.TemporaryCachePath;
		if (!Directory.Exists(temporaryCachePath))
		{
			Directory.CreateDirectory(temporaryCachePath);
		}
		TakeScreenShot();
		FogOfWar.Save();
		GlobalVariables.WriteGlobalsToSaveGame();
		SaveGameInfo saveGameInfo = SDK.GameResources.BuildSaveFile(filename, userString);
		SDK.GameState.LoadedFileName = filename;
		SDK.GameState.LoadedSaveGameInfo = saveGameInfo;
		if ((bool)OnlineServicesManager.Instance && OnlineServicesManager.Instance.ShouldUseCloudSaves() && ShouldCloudSync)
		{
			saveGameInfo.CloudState = SaveGameInfo.CloudSyncState.Pending;
			SaveGameInfo.WaitUntilSafeToSaveLoad();
			OnlineServicesManager.Instance.UploadCloudSaveFile_ManagedCallback(saveGameInfo, filename);
		}
		return true;
	}

	public static bool LoadGame(string filename)
	{
		SDK.GameResources.PreLoadingGame = true;
		Debug.Log("Loading Save Game: " + filename);
		SaveGameInfo.WaitUntilSafeToSaveLoad();
		if (!File.Exists(Path.Combine(SDK.GameResources.SaveGamePath, filename)))
		{
			return false;
		}
		if (GameState.CanTrialOfIronQuitSave())
		{
			GameState.TrialOfIronSave();
		}
		if (MusicManager.Instance != null)
		{
			MusicManager.Instance.StopAllMusic();
			MusicManager.Instance.UnloadMusic();
		}
		if ((bool)TimeController.Instance)
		{
			TimeController.Instance.Paused = false;
		}
		SDK.GameResources.OnPreloadGame();
		for (int num = SDK.PartyMemberAI.PartyMembers.Length - 1; num >= 0; num--)
		{
			if (!(SDK.PartyMemberAI.PartyMembers[num] == null))
			{
				if (SDK.PartyMemberAI.PartyMembers[num].StateManager != null)
				{
					SDK.PartyMemberAI.PartyMembers[num].StateManager.AbortStateStack();
				}
				SDK.GameState.DestroyTrackedObjectImmediate(SDK.PartyMemberAI.PartyMembers[num].gameObject);
			}
		}
		if ((bool)GameState.Stronghold)
		{
			GameState.Stronghold.DestroyStoredCompanions();
		}
		SDK.GameState.CleanupPersistAcrossSceneLoadObjectsOfType(typeof(AIController));
		SDK.GameState.LoadedGame = true;
		SDK.GameState.LoadedFileName = filename;
		GameInput.ClickHandled = true;
		SaveGameInfo saveGameInfo = LoadSaveFile(filename, SaveGameInfo.SizeStyle.DataOnly);
		if (saveGameInfo == null)
		{
			return false;
		}
		if (!GameUtilities.Instance.HasGamePackage(saveGameInfo))
		{
			Debug.LogError("This save is using content that you no longer have! Please load a valid save!");
			return false;
		}
		SDK.GameResources.PreLoadingGame = false;
		GameState.BeginLevelUnload(saveGameInfo.MapName);
		GameState.Instance.Difficulty = saveGameInfo.Difficulty;
		GameUtilities.CreateInGameGlobalPrefabObject();
		GlobalVariables.ReadGlobalsFromSaveGame();
		if (!GameState.LoadLevel(saveGameInfo.MapName))
		{
			return false;
		}
		SDK.GameState.LoadedSaveGameInfo = saveGameInfo;
		SDK.GameResources.OnLoadedSave();
		return true;
	}

	public static void DeleteSavedGame(string filename, bool removeCloudSave)
	{
		SaveGameInfo.WaitUntilSafeToSaveLoad();
		try
		{
			SaveGameInfo saveGameInfo = SaveGameInfo.CachedSaveGameInfo.Find((SaveGameInfo sv) => sv != null && sv.FileName == filename);
			if (saveGameInfo != null)
			{
				SaveGameInfo.CachedSaveGameInfo.Remove(saveGameInfo);
				saveGameInfo.Cleanup();
			}
			if (!filename.EndsWith(".savegame"))
			{
				filename += ".savegame";
			}
			string path = Path.Combine(SDK.GameResources.SaveGamePath, filename);
			File.Delete(path);
			if (removeCloudSave && saveGameInfo.ShouldCloudSave && (bool)OnlineServicesManager.Instance && OnlineServicesManager.Instance.ShouldUseCloudSaves() && OnlineServicesManager.Instance.SaveHasMatchingCloudGUID(saveGameInfo.CloudSaveGUID))
			{
				OnlineServicesManager.Instance.SyncSaveDeletionOnCloud_ManagedCallback(filename);
			}
		}
		catch (Exception message)
		{
			Debug.Log("Error while delete save file:");
			Debug.Log(message);
		}
	}

	public static SaveGameInfo LoadSaveFile(string filename, SaveGameInfo.SizeStyle sizeStyle)
	{
		//Discarded unreachable code: IL_009d
		SaveGameInfo.WaitUntilSafeToSaveLoad();
		string text = Path.Combine(SDK.GameResources.SaveGamePath, filename);
		if (!File.Exists(text))
		{
			return null;
		}
		PersistenceManager.ClearTempData();
		try
		{
			string text2 = Path.Combine(SDK.GameResources.TemporaryCachePath, "loadedSave.zip");
			if (File.Exists(text2))
			{
				File.Delete(text2);
			}
			File.Copy(text, text2);
			using ZipFile zipFile = new ZipFile(text2, Encoding.UTF8);
			zipFile.ExtractAll(PersistenceManager.s_tempSavePath);
		}
		catch (Exception ex)
		{
			Debug.LogError(ex.ToString());
			Debug.LogError(text + " ZIP FILE IS CORRUPT!");
			return null;
		}
		SaveGameInfo saveGameInfo = SaveGameInfo.Load(PersistenceManager.s_tempSavePath, sizeStyle);
		saveGameInfo.FileName = Path.GetFileName(filename);
		return saveGameInfo;
	}

	public static UnityEngine.Object LoadAsset(string assetPath, Type type, bool instantiate)
	{
		AssetBundleHint bundleHint = AssetBundleHint.Unknown;
		if (type == typeof(RuntimeAnimatorController))
		{
			bundleHint = AssetBundleHint.Animation;
		}
		return LoadAsset(assetPath, type, bundleHint, instantiate);
	}

	public static UnityEngine.Object LoadAsset(string assetPath, AssetBundleHint bundleHint, bool instantiate)
	{
		return LoadAsset(assetPath, null, bundleHint, instantiate);
	}

	public static UnityEngine.Object LoadAsset(string assetPath, Type type, AssetBundleHint bundleHint, bool instantiate)
	{
		assetPath = SDK.GameUtilities.RemoveClone(assetPath);
		string assetNameLower = Path.GetFileNameWithoutExtension(assetPath).ToLower();
		string loadedAssetLookupName = GetLoadedAssetLookupName(assetNameLower, bundleHint);
		UnityEngine.Object @object = null;
		if (s_loadedAssets.ContainsKey(loadedAssetLookupName))
		{
			WeakReference weakReference = s_loadedAssets[loadedAssetLookupName];
			if (weakReference == null)
			{
				s_loadedAssets.Remove(loadedAssetLookupName);
			}
			else
			{
				UnityEngine.Object object2 = weakReference.Target as UnityEngine.Object;
				if (!(object2 == null))
				{
					if (instantiate)
					{
						return SDK.GameResources.Instantiate<UnityEngine.Object>(object2);
					}
					return object2;
				}
				s_loadedAssets.Remove(loadedAssetLookupName);
			}
		}
		if (s_missingAssets.Contains(loadedAssetLookupName))
		{
			return null;
		}
		@object = AssetBundleManager.LoadAsset(assetPath, bundleHint);
		if (@object != null)
		{
			if (@object is GameObject)
			{
				GameObject gameObject = @object as GameObject;
				InstanceID component = gameObject.GetComponent<InstanceID>();
				if (component != null)
				{
					component.isFromPrefab = true;
					component.ValidateGUID();
				}
			}
			else if (@object is MonoBehaviour)
			{
				MonoBehaviour monoBehaviour = @object as MonoBehaviour;
				InstanceID component2 = monoBehaviour.gameObject.GetComponent<InstanceID>();
				if (component2 != null)
				{
					component2.isFromPrefab = true;
					component2.ValidateGUID();
				}
			}
			WeakReference value = new WeakReference(@object);
			s_loadedAssets.Add(loadedAssetLookupName, value);
		}
		else if (@object == null)
		{
			s_missingAssets.Add(loadedAssetLookupName);
			Debug.LogError("LoadAsset(): Unable to load asset '" + assetPath + "'.");
			return null;
		}
		if (instantiate)
		{
			@object = SDK.GameResources.Instantiate<UnityEngine.Object>(@object);
		}
		return @object;
	}

	public static string GetLoadedAssetLookupName(string assetNameLower, AssetBundleHint type)
	{
		if (type == AssetBundleHint.VOAssets)
		{
			return "voasset_" + assetNameLower;
		}
		return assetNameLower;
	}

	public static AssetBundleRequestWrapper LoadAssetAsync(string assetPath, AssetBundleHint typeHint, bool instantiate)
	{
		assetPath = SDK.GameUtilities.RemoveClone(assetPath);
		string text = Path.GetFileNameWithoutExtension(assetPath).ToLower();
		string loadedAssetLookupName = GetLoadedAssetLookupName(text, typeHint);
		if (s_asyncAssetLoads.ContainsKey(loadedAssetLookupName))
		{
			if (s_asyncAssetLoads[loadedAssetLookupName] != null)
			{
				AssetBundleRequestWrapper result = default(AssetBundleRequestWrapper);
				result.loadRequest = s_asyncAssetLoads[loadedAssetLookupName];
				result.immediatelyAvailableAsset = null;
				result.fullAssetPath = assetPath;
				return result;
			}
			s_asyncAssetLoads.Remove(loadedAssetLookupName);
		}
		AssetBundleRequestWrapper result2 = default(AssetBundleRequestWrapper);
		result2.loadRequest = null;
		result2.immediatelyAvailableAsset = null;
		result2.fullAssetPath = assetPath;
		UnityEngine.Object @object = null;
		if (s_loadedAssets.ContainsKey(loadedAssetLookupName))
		{
			WeakReference weakReference = s_loadedAssets[loadedAssetLookupName];
			if (weakReference == null)
			{
				s_loadedAssets.Remove(loadedAssetLookupName);
			}
			else
			{
				UnityEngine.Object object2 = weakReference.Target as UnityEngine.Object;
				if (!(object2 == null))
				{
					@object = (result2.immediatelyAvailableAsset = ((!instantiate) ? object2 : SDK.GameResources.Instantiate<UnityEngine.Object>(object2)));
				}
				else
				{
					s_loadedAssets.Remove(loadedAssetLookupName);
				}
			}
		}
		if (result2.immediatelyAvailableAsset != null)
		{
			return result2;
		}
		AssetBundleRequest assetBundleRequest = AssetBundleManager.LoadAssetAsync(text, typeHint);
		s_asyncAssetLoads.Add(loadedAssetLookupName, assetBundleRequest);
		result2.loadRequest = assetBundleRequest;
		return result2;
	}

	public static void StopAssetAsyncRequest(string assetName)
	{
		string key = Path.GetFileNameWithoutExtension(assetName).ToLower();
		if (s_asyncAssetLoads.ContainsKey(key))
		{
			s_asyncAssetLoads.Remove(key);
		}
	}

	public static UnityEngine.Object LoadAssetFromAsyncRequest(string assetName, AssetBundleRequest request, bool instantiate)
	{
		return LoadAssetFromAsyncRequest(assetName, request, AssetBundleHint.Unknown, instantiate);
	}

	public static UnityEngine.Object LoadAssetFromAsyncRequest(string assetName, AssetBundleRequest request, AssetBundleHint bundleHint, bool instantiate)
	{
		if (request.isDone)
		{
			string assetNameLower = Path.GetFileNameWithoutExtension(assetName).ToLower();
			string loadedAssetLookupName = GetLoadedAssetLookupName(assetNameLower, bundleHint);
			UnityEngine.Object @object = request.asset;
			if (s_loadedAssets.ContainsKey(loadedAssetLookupName))
			{
				WeakReference weakReference = s_loadedAssets[loadedAssetLookupName];
				if (weakReference == null || weakReference.Target == null)
				{
					s_loadedAssets.Remove(loadedAssetLookupName);
				}
				else
				{
					@object = weakReference.Target as UnityEngine.Object;
				}
			}
			else
			{
				WeakReference value = new WeakReference(@object);
				s_loadedAssets.Add(loadedAssetLookupName, value);
			}
			if (s_asyncAssetLoads.ContainsKey(loadedAssetLookupName))
			{
				s_asyncAssetLoads.Remove(loadedAssetLookupName);
			}
			if (@object == null)
			{
				Debug.LogError("LoadAssetFromAsyncRequest(): Despite having completed, the async AssetBundleRequest for asset " + assetName + " returned NULL.");
				return null;
			}
			if (instantiate)
			{
				@object = SDK.GameResources.Instantiate<UnityEngine.Object>(@object);
			}
			return @object;
		}
		return null;
	}

	public static UnityEngine.Object[] LoadAllAssetsAtPath(string path, AssetBundleHint bundleHint, bool instantiate)
	{
		List<UnityEngine.Object> list = new List<UnityEngine.Object>();
		DirectoryInfo directoryInfo = new DirectoryInfo(path);
		FileInfo[] files = directoryInfo.GetFiles();
		for (int i = 0; i < files.Length; i++)
		{
			string name = files[i].Name;
			if (name.EndsWith("meta"))
			{
				continue;
			}
			string text = Path.GetFileNameWithoutExtension(files[i].FullName).ToLower();
			if (IsAssetLoaded(text))
			{
				list.Add(s_loadedAssets[text].Target as UnityEngine.Object);
				continue;
			}
			string fullName = files[i].FullName;
			fullName = fullName.Replace("\\", "/");
			int num = fullName.IndexOf("/Assets/");
			fullName = fullName.Substring(num, fullName.Length - num);
			UnityEngine.Object @object = LoadAsset(fullName, bundleHint, instantiate);
			if (@object != null)
			{
				list.Add(@object);
			}
		}
		return list.ToArray();
	}

	public static bool IsAssetLoaded(string assetName)
	{
		string key = Path.GetFileNameWithoutExtension(assetName).ToLower();
		if (!s_loadedAssets.ContainsKey(key))
		{
			return false;
		}
		WeakReference weakReference = s_loadedAssets[key];
		if (weakReference == null || weakReference.Target as UnityEngine.Object == null)
		{
			s_loadedAssets.Remove(key);
			return false;
		}
		return true;
	}

	public static void RemoveNullEntriesFromAssetCache()
	{
		List<string> list = new List<string>();
		foreach (KeyValuePair<string, WeakReference> s_loadedAsset in s_loadedAssets)
		{
			if (s_loadedAsset.Value != null)
			{
				UnityEngine.Object @object = s_loadedAsset.Value.Target as UnityEngine.Object;
				if (@object == null)
				{
					list.Add(s_loadedAsset.Key);
				}
			}
			else
			{
				list.Add(s_loadedAsset.Key);
			}
		}
		foreach (string item in list)
		{
			s_loadedAssets.Remove(item);
		}
	}

	public static void Cleanup()
	{
		if (s_currentScene != null)
		{
			s_currentScene.Unload(unloadAllLoadedObjects: true);
		}
		s_currentScene = null;
	}

	public static IEnumerator Coroutine_LoadScene(MapData newMapData, string currentRegionName, bool loadFromSaveFile)
	{
		if (s_loading || newMapData == null)
		{
			yield break;
		}
		yield return null;
		yield return null;
		try
