		}
		catch (Exception ex3)
		{
			Debug.LogError(ex3.ToString());
			GameState.Instance.ReturnToMainMenuFromError();
			yield break;
		}
		string newSceneName = newMapData.SceneName;
		string newRegionName = ((!(newMapData.region != null)) ? "none" : newMapData.region.Tag.ToLower());
		if (TelemetryManager.Instance != null)
		{
			string source = ((!SDK.GameState.LoadedGame) ? ((!string.IsNullOrEmpty(SDK.GameState.ApplicationLoadedLevelName)) ? SDK.GameState.ApplicationLoadedLevelName : "unknown_scene") : "loaded_game");
			string destination = ((newSceneName != null && !(newSceneName == string.Empty)) ? newSceneName : "unknown_scene");
			TelemetryManager.Instance.QueueEvent_SceneTransition(SDK.TelemetryManager.Destination.Developer | SDK.TelemetryManager.Destination.Publisher, source.ToLower(), destination.ToLower(), currentRegionName, newRegionName);
		}
		s_loading = true;
		Application.backgroundLoadingPriority = ThreadPriority.High;
		float transitionStartTime = Time.realtimeSinceStartup;
		AsyncOperation emptyLevelLoad2 = null;
		try
		{
			Debug.Log("-------- TRANSITION TO EMPTY LEVEL --------");
			FadeManager.Instance.FadeAudio = true;
			FadeManager.Instance.FadeMusic = false;
			FadeManager.Instance.FadeToBlack(SDK.FadeManager.FadeType.AreaTransition, 0f);
			emptyLevelLoad2 = SceneManager.LoadSceneAsync("oei_scene_transition", LoadSceneMode.Single);
		}
		catch (Exception ex2)
		{
			s_loading = false;
			Debug.LogError(ex2.ToString());
			GameState.Instance.ReturnToMainMenuFromError();
			yield break;
		}
		yield return emptyLevelLoad2;
		Debug.Log("-------- CALLING SYSTEM.GC.COLLECT --------");
		float gcStartTime = Time.realtimeSinceStartup;
		GC.Collect();
		Debug.Log("-------- SYSTEM.GC.COLLECT COMPLETE (Total Time: " + (Time.realtimeSinceStartup - gcStartTime) + ") --------");
		PersistenceManager.ClearPersistenceObjects();
		Debug.Log("-------- TRANSITION TO EMPTY LEVEL COMPLETE (Total Time: " + (Time.realtimeSinceStartup - transitionStartTime) + ") --------");
		yield return null;
		WWW download = null;
		string filename = SDK.GameResources.GetOverridePath(newSceneName);
		if (filename != string.Empty && File.Exists(filename))
		{
			AssetBundle level = AssetBundle.LoadFromFile(filename);
			if (level == null)
			{
				download = WWW.LoadFromCacheOrDownload(TextUtils.LiteEscapeUrl("file://" + filename), 1);
				yield return download;
				if (download.error != null)
				{
					Debug.LogError(download.error);
					GameState.Instance.ReturnToMainMenuFromError();
					yield break;
				}
			}
			s_currentScene = download.assetBundle;
		}
		AsyncOperation newLevelLoad = null;
		try
		{
			FadeManager.Instance.FadeAudio = true;
			FadeManager.Instance.FadeMusic = false;
			FadeManager.Instance.FadeToBlack(SDK.FadeManager.FadeType.AreaTransition, 0f);
			transitionStartTime = Time.realtimeSinceStartup;
			Debug.Log("-------- TRANSITION TO LEVEL " + newSceneName.ToUpper() + "--------");
			newLevelLoad = SceneManager.LoadSceneAsync(newSceneName, LoadSceneMode.Single);
		}
		catch (Exception ex)
		{
			Debug.LogError(ex.ToString());
		}
		yield return newLevelLoad;
		Debug.Log("-------- TRANSITION TO LEVEL " + newSceneName.ToUpper() + " COMPLETE (Total Time: " + (Time.realtimeSinceStartup - transitionStartTime) + ") --------");
		s_loading = false;
		UIWindowManager.ForceFullEnableWindowVisibilityHandling();
