	public static void CheckSaveVersionVX1Maps(SaveGameInfo info)
	{
		if (info != null && info.SaveVersion != 5)
		{
			Debug.Log("Upgrading Save Version from " + info.SaveVersion + " to " + 5);
		}
		if (info != null && info.SaveVersion == 4)
		{
			Debug.Log("Upgrading Save Version from 4: World Map Overridden!");
			Array values = Enum.GetValues(typeof(MapType));
			foreach (int item in values)
			{
				MapData map = WorldMap.Instance.GetMap((MapType)item);
				if (map == null || !((MapType)item).ToString().StartsWith("VX1"))
				{
					continue;
				}
				for (int num = WorldMap.Maps.Length - 1; num >= 0; num--)
				{
					if (WorldMap.Maps.Maps[num].SceneName.Equals(((MapType)item).ToString()))
					{
						WorldMap.Instance.SetVisibility((MapType)item, WorldMap.Maps.Maps[num].Visibility);
						break;
					}
				}
			}
		}
		if (info != null && info.SaveVersion != 5)
		{
			info.SaveVersion = 5;
		}
	}

