	public static IEnumerator Coroutine_GetVOAssetsInDirectoryAsync(string VOAssetFolderPath, Action<List<VOAsset>> callback)
	{
		if (s_voAssetsAtPath == null)
		{
			CacheVOAssetDirectories();
		}
		if (!s_voAssetsAtPath.TryGetValue("assets/data/audio/vocalization/vo assets/" + VOAssetFolderPath, out var assetsInDirectory))
		{
			callback(null);
		}
		List<VOAsset> retVal = new List<VOAsset>();
		VOAsset loadedAsset3 = null;
		for (int i = 0; i < assetsInDirectory.Count; i++)
		{
			loadedAsset3 = null;
			string fullAssetPath = assetsInDirectory[i];
			if (i % 3 == 0)
			{
				yield return null;
			}
			loadedAsset3 = LoadAsset(fullAssetPath, AssetBundleHint.VOAssets, instantiate: false) as VOAsset;
			if (loadedAsset3 != null)
			{
				retVal.Add(loadedAsset3);
			}
		}
		callback(retVal);
	}

	public static List<VOAsset> GetVOAssetsInDirectory(string VOAssetFolderPath)
	{
		if (s_voAssetsAtPath == null)
		{
			CacheVOAssetDirectories();
		}
		if (!s_voAssetsAtPath.TryGetValue("assets/data/audio/vocalization/vo assets/" + VOAssetFolderPath, out var value))
		{
			return null;
		}
		List<VOAsset> list = new List<VOAsset>();
		for (int i = 0; i < value.Count; i++)
		{
			VOAsset vOAsset = LoadVOAssetAtPath(value[i]);
			if (vOAsset != null)
			{
				list.Add(vOAsset);
			}
		}
		return list;
	}

	public static VOAsset GetVOAssetForConversation(string dialogueName, int nodeID, bool useFemale)
	{
		if (s_voAssetsAtPath == null)
		{
			CacheVOAssetDirectories();
		}
		string value = Path.GetFileNameWithoutExtension(dialogueName).ToLower();
		StringBuilder stringBuilder = new StringBuilder();
		stringBuilder.Append("assets/data/audio/vocalization/vo assets");
		stringBuilder.Append("/");
		stringBuilder.Append(value);
		stringBuilder.Append("/");
		stringBuilder.Append(value);
		stringBuilder.Append("_");
		stringBuilder.Append(nodeID.ToString("0000"));
		if (useFemale)
		{
			stringBuilder.Append("_fem");
		}
		stringBuilder.Append(".asset");
		return LoadVOAssetAtPath(stringBuilder.ToString());
	}

	private static void CacheVOAssetDirectories()
	{
		string[] array = null;
		if (!Application.isEditor || !DEBUG_CONSTANTS.LOAD_ASSETS_DIRECTLY)
		{
			array = AssetBundleManager.LoadAllAssetNamesFromBundle(AssetBundleHint.VOAssets);
		}
		if (array == null)
		{
			return;
		}
		s_voAssetsAtPath = new Dictionary<string, List<string>>(StringComparer.InvariantCultureIgnoreCase);
		foreach (string text in array)
		{
			string vODirectoryPathForAssetPath = GetVODirectoryPathForAssetPath(text);
			List<string> value = null;
			if (!s_voAssetsAtPath.TryGetValue(vODirectoryPathForAssetPath, out value))
			{
				value = new List<string>();
				s_voAssetsAtPath[vODirectoryPathForAssetPath] = value;
			}
			value.Add(text);
		}
	}

	private static string GetVODirectoryPathForAssetPath(string assetPath)
	{
		string directoryName = Path.GetDirectoryName(assetPath);
		directoryName = directoryName.Replace("\\", "/");
		int num = directoryName.IndexOf("/assets/", StringComparison.InvariantCultureIgnoreCase);
		if (num > 0)
		{
			directoryName = directoryName.Substring(num, directoryName.Length - num);
		}
		return directoryName.ToLower();
	}

	private static VOAsset LoadVOAssetAtPath(string fullAssetPath)
	{
		string vODirectoryPathForAssetPath = GetVODirectoryPathForAssetPath(fullAssetPath);
		if (!s_voAssetsAtPath.TryGetValue(vODirectoryPathForAssetPath, out var value))
		{
			return null;
		}
		for (int i = 0; i < value.Count; i++)
		{
			if (value[i].Equals(fullAssetPath, StringComparison.InvariantCultureIgnoreCase) && (!Application.isEditor || !DEBUG_CONSTANTS.LOAD_ASSETS_DIRECTLY))
			{
				return AssetBundleManager.LoadAsset(fullAssetPath, AssetBundleHint.VOAssets) as VOAsset;
			}
		}
		return null;
	}
