using System;
using System.Collections.Generic;
using System.Diagnostics;
using System.IO;
using System.Text;
using SDK;
using UnityEngine;

namespace Game;

public class CommandLine : SDK.CommandLine
{
	private class ObjectComparer : IComparer<GameObject>
	{
		private static ObjectComparer s_instance;

		public static ObjectComparer Instance
		{
			get
			{
				if (s_instance == null)
				{
					s_instance = new ObjectComparer();
				}
				return s_instance;
			}
		}

		public int Compare(GameObject a, GameObject b)
		{
			if (a == null || b == null)
			{
				return 0;
			}
			int hashCode = a.GetType().GetHashCode();
			int hashCode2 = b.GetType().GetHashCode();
			if (hashCode > hashCode2)
			{
				return 1;
			}
			if (hashCode == hashCode2)
			{
				return 0;
			}
			return -1;
		}
	}

	public static object[] s_ScriptAttributeTypes;

	public static bool S_LEGACYMODE_ALLOW_ALL_SAVES;

	public static bool S_USE_PROGRESSION_FOR_LOOT;

	public static bool S_DELETE_ALL_CLOUD_ENTRIES;

	public static bool S_OVERRIDE_NGPLUS_CONDITIONAL_CHECKS;

	public static int S_NGPLUS_ITERATION_OVERRIDE;

	public static bool S_ALLOW_ALL_ITEM_IMPORTS;

	private static bool S_HAS_OVERRIDE_NGPLUS_CONDITIONAL_CHECKS;

	private static bool m_CkOn;

	static CommandLine()
	{
		S_USE_PROGRESSION_FOR_LOOT = true;
		s_ScriptAttributeTypes = new object[8]
		{
			typeof(ScriptParam0Attribute),
			typeof(ScriptParam1Attribute),
			typeof(ScriptParam2Attribute),
			typeof(ScriptParam3Attribute),
			typeof(ScriptParam4Attribute),
			typeof(ScriptParam5Attribute),
			typeof(ScriptParam6Attribute),
			typeof(ScriptParam7Attribute)
		};
	}

	public static bool HasOverridenNGPLusConditionalChecks()
	{
		return S_HAS_OVERRIDE_NGPLUS_CONDITIONAL_CHECKS;
	}

	public new static void IRoll20s()
	{
		SDK.GameState.CheatsEnabled = !SDK.GameState.CheatsEnabled;
		if (SDK.GameState.CheatsEnabled && AchievementTracker.Instance != null)
		{
			AchievementTracker.Instance.DisableAchievements = true;
		}
		if (SDK.GameState.CheatsEnabled)
		{
			Console.AddMessage("Cheats Enabled - Warning - Achievements disabled for this game.");
		}
		else
		{
			Console.AddMessage("Cheats Disabled");
		}
	}

	[Cheat]
	public static void ResetParty()
	{
		for (int i = 0; i < SDK.PartyMemberAI.PartyMembers.Length; i++)
		{
			if (SDK.PartyMemberAI.PartyMembers[i] != null)
			{
				Health.ResetCharacter(SDK.PartyMemberAI.PartyMembers[i].gameObject);
			}
		}
	}

	[Cheat]
	public static void Damage(string amount)
	{
		GameObject[] selectedPartyMembers = SDK.PartyMemberAI.SelectedPartyMembers;
		foreach (GameObject gameObject in selectedPartyMembers)
		{
			if (!(gameObject == null))
			{
				Health component = gameObject.GetComponent<Health>();
				if (!(component != null) || !float.TryParse(amount, out var result))
				{
					Console.AddMessage("Parameter Invalid, must be a number!");
					break;
				}
				component.ApplyHealthChangeDirectly(0f - result, applyIfDead: false);
			}
		}
	}

	[Cheat]
