	[Cheat]
	[ScriptParam0("Prefab Name", "The name of the prefab to spawn.", "", BrowserType.None)]
	[ScriptParam4("Z Position", "Z location to place the prefab.", "0", BrowserType.None)]
	[ScriptParam2("X Position", "X location to place the prefab.", "0", BrowserType.None)]
	[ScriptParam1("Hates All", "Should switch the character's faction to hates all?", "", BrowserType.None)]
	[ScriptParam3("Y Position", "Y location to place the prefab.", "0", BrowserType.None)]
	public static void SpawnPrefabAtPoint(string prefabName, bool hostile, float x, float y, float z)
	{
		GameObject gameObject = GameResources.LoadAsset(prefabName, AssetBundleHint.Characters, instantiate: false) as GameObject;
		if (!gameObject)
		{
			return;
		}
		Vector3 sourcePosition = new Vector3(x, y, z);
		NavMeshHit hit = default(NavMeshHit);
		int areaMask = 1 << LayerMask.NameToLayer("Walkable");
		if (NavMesh.SamplePosition(sourcePosition, out hit, float.PositiveInfinity, areaMask))
		{
			sourcePosition = hit.position;
		}
		else
		{
			UnityEngine.Debug.LogError("Couldn't find a place on the navmesh to spawn the prefab at that location.");
		}
		sourcePosition = new Vector3(sourcePosition.x, sourcePosition.y, sourcePosition.z);
		gameObject = SDK.GameResources.Instantiate<GameObject>(gameObject, sourcePosition, Quaternion.identity);
		if (hostile && gameObject != null)
		{
			Faction component = gameObject.GetComponent<Faction>();
			if (component != null)
			{
				component.CurrentTeam = GameResources.LoadAsset("Team_HatesAll", AssetBundleHint.Teams, instantiate: false) as Team;
			}
		}
	}

