	[Cheat]
	public static void AddCompanion(string name)
	{
		name = name.ToLower();
		for (CompanionNames.Companions companions = CompanionNames.Companions.Comp_Beastwoman; companions <= CompanionNames.Companions.Comp_Stealth; companions++)
		{
			string displayName = CompanionNames.GetDisplayName(companions);
			displayName = Terminology.StripGlossaryUrlTags(displayName);
			displayName = displayName.ToLower();
			if (!displayName.Equals(name))
			{
				continue;
			}
			UnityEngine.Object @object = GameResources.LoadAsset(companions.ToString(), AssetBundleHint.Characters, instantiate: true);
			GameObject gameObject = @object as GameObject;
			if (gameObject == null)
			{
				UnityEngine.Debug.LogWarning("Could not find object to add to party.");
				break;
			}
			PartyMemberAI component = gameObject.GetComponent<PartyMemberAI>();
			if ((bool)component)
			{
				component.AssignedSlot = SDK.PartyMemberAI.NextAvailablePrimarySlot;
				if (GameState.Mode.Difficulty == GameDifficulty.Easy || GameState.Mode.Difficulty == GameDifficulty.Normal)
				{
					component.UseInstructionSet = true;
				}
				else
				{
					component.UseInstructionSet = false;
				}
			}
			PartyMemberAI.AddToActiveParty(gameObject, fromScript: true);
			SDK.PartyMemberAI[] partyMembers = SDK.PartyMemberAI.PartyMembers;
			foreach (SDK.PartyMemberAI partyMemberAI in partyMembers)
			{
				if (partyMemberAI != null)
				{
					gameObject.transform.position = SDK.GameUtilities.NearestUnoccupiedLocation(partyMemberAI.transform.position, 5f, 10f, partyMemberAI.GetComponent<Mover>());
				}
			}
			break;
		}
