using System;
using SDK;
using UnityEngine;

namespace Game;

public class GameCursor : SDK.GameCursor
{
	public enum CursorType
	{
		None,
		Normal,
		Walk,
		NoWalk,
		RotateFormation,
		Attack,
		OpenDoor,
		CloseDoor,
		LockedDoor,
		BarredDoor,
		AreaTransition,
		Examine,
		Talk,
		Interact,
		CastAbility,
		CastAbilityInvalid,
		ArrowUp,
		ArrowRight,
		ArrowDown,
		ArrowLeft,
		ArrowUpRight,
		ArrowDownRight,
		ArrowUpLeft,
		ArrowDownLeft,
		Deprecated1,
		DoubleArrow_L_R,
		DoubleArrow_U_D,
		DoubleArrow_DL_UR,
		DoubleArrow_UL_DR,
		Disarm,
		CastAbilityNoLOS,
		CastAbilityFar,
		Stealing,
		Loot,
		NormalHeld,
		WalkHeld,
		SpecialAttack,
		FieldInteraction,
		StealingLocked,
		Disengage,
		DisengageHeld,
		AttackAdvantage,
		ContainerLocked
	}

	public enum CursorSetType
	{
		Normal,
		Normal64
	}

	public GameCursorSet CurrentCursorSet;

	private static CursorType m_activeCursor = CursorType.None;

	private static CursorType m_desiredCursor = CursorType.None;

	private static CursorType m_uiCursor = CursorType.None;

	private static Texture2D m_castCursor = null;

	private static Texture2D m_castCursorInvalid = null;

	private static Texture2D m_castCursorMove = null;

	private static Texture2D m_castCursorLoS = null;

	private static bool m_castCursorValid = false;

	private static Color[] m_castCursorBuffer;

	private static int m_frameCount = 0;

	private static Vector2 m_centerHotSpot = new Vector2(16f, 16f);

	private static float s_cursorScale = 1f;

	private CursorSetType m_loadedCursorSet;

	private static bool m_showDebug = false;

	public static GameObject UiObjectUnderCursor;

	public static CursorType CursorOverride { get; set; }

	public new static GameCursor Instance => SDK.GameCursor.s_instance as GameCursor;

	public static bool ShowDebug
	{
		get
		{
			return m_showDebug;
		}
		set
		{
			m_showDebug = value;
			if (!m_showDebug)
			{
				UIDebug.Instance.RemoveText("Cursor Debug");
			}
		}
	}

	public static bool LockCursor
	{
		get
		{
			return Cursor.lockState == CursorLockMode.Locked;
		}
		set
		{
			if (value)
			{
				Cursor.lockState = CursorLockMode.Locked;
				Cursor.visible = false;
			}
			else
			{
				Cursor.lockState = CursorLockMode.None;
				Cursor.visible = true;
			}
			WinCursor.Clip(state: true);
		}
	}

	public static bool ActiveCursorIsTargeting => IsTargetCursor(ActiveCursor);

	public static CursorType ActiveCursor => m_activeCursor;

	public static CursorType UiCursor
	{
		get
		{
			return m_uiCursor;
		}
		set
		{
			m_uiCursor = value;
		}
	}

	public static CursorType DesiredCursor
	{
		get
		{
			if (m_uiCursor != 0)
			{
				if (IsAttackCursor(m_desiredCursor))
				{
					return m_desiredCursor;
				}
				if (IsCastCursor(m_desiredCursor))
				{
					return CursorType.CastAbilityInvalid;
				}
				return m_uiCursor;
			}
			return m_desiredCursor;
		}
		set
		{
			m_desiredCursor = value;
		}
	}

	public static bool IsTargetCursor(CursorType type)
	{
		return IsAttackCursor(type) || IsCastCursor(type);
	}

	public static bool IsAttackCursor(CursorType type)
	{
		return type == CursorType.Attack || type == CursorType.SpecialAttack || type == CursorType.AttackAdvantage;
	}

	public static bool IsCastCursor(CursorType type)
	{
		return type == CursorType.CastAbility || type == CursorType.CastAbilityInvalid || type == CursorType.CastAbilityNoLOS || type == CursorType.CastAbilityFar || type == CursorType.SpecialAttack;
	}

	public static bool IsInteractCursor(CursorType type)
	{
		return type == CursorType.Examine || type == CursorType.Interact || type == CursorType.Talk || type == CursorType.Stealing || type == CursorType.StealingLocked || type == CursorType.CloseDoor || type == CursorType.OpenDoor || type == CursorType.LockedDoor || type == CursorType.Loot || type == CursorType.Disarm || type == CursorType.FieldInteraction;
	}

	public static bool IsInvalidCursor(CursorType type)
	{
		return type == CursorType.StealingLocked || type == CursorType.LockedDoor || type == CursorType.NoWalk || type == CursorType.CastAbilityInvalid || type == CursorType.CastAbilityNoLOS || type == CursorType.CastAbilityFar || type == CursorType.ContainerLocked;
	}

	public static bool IsInvalidAbilityCursor(CursorType type)
	{
		return type == CursorType.CastAbilityInvalid || type == CursorType.CastAbilityNoLOS;
	}

	private void Awake()
	{
		SDK.GameCursor.s_instance = this;
		m_activeCursor = CursorType.None;
		m_desiredCursor = CursorType.Normal;
		m_uiCursor = CursorType.None;
		CursorOverride = CursorType.None;
	}

	private void Start()
	{
		LoadCursorSet(DetermineCursorSetType());
		LockCursor = false;
	}

	protected override void OnDestroy()
	{
		base.OnDestroy();
		ComponentUtils.NullOutObjectReferences(this);
	}

	public string GetCursorDebugOutput()
	{
		string text = "-- Mouse Cursor Debug --";
		string text2 = text;
		text = text2 + "\nMouse Screen Pos: x = " + Input.mousePosition.x + ", y = " + Input.mousePosition.y + ", z = " + Input.mousePosition.z;
		text2 = text;
		text = text2 + "\nApprox. Global Pos: x = " + GameInput.GlobalMousePosition.x + ", y = " + GameInput.GlobalMousePosition.y + ", z = " + Input.mousePosition.z;
		text2 = text;
		text = text2 + "\nMouse Delta: x = " + GameInput.MouseDelta.x + ", y = " + GameInput.MouseDelta.y + ", z = " + GameInput.MouseDelta.z;
		text2 = text;
		text = text2 + "\nMouse World Pos: x = " + SDK.GameCursor.WorldPickPosition.x + ", y = " + SDK.GameCursor.WorldPickPosition.y + ", z = " + SDK.GameCursor.WorldPickPosition.z;
		text2 = text;
		text = text2 + "\nCursor: " + DesiredCursor.ToString() + ", UI Cursor: " + UiCursor;
		text = text + "\nGeneric Object Under Cursor: " + ((!SDK.GameCursor.GenericUnderCursor) ? "Null" : SDK.GameCursor.GenericUnderCursor.name);
		text = text + "\nCharacter Under Cursor: " + ((!SDK.GameCursor.CharacterUnderCursor) ? "Null" : SDK.GameCursor.CharacterUnderCursor.name);
		text = text + "\nUI Under Cursor: " + ((!UiObjectUnderCursor) ? "Null" : UiObjectUnderCursor.name);
		text = text + "\nCollider Under Cursor: " + ((!SDK.GameCursor.ColliderUnderCursor) ? "Null" : SDK.GameCursor.ColliderUnderCursor.name);
		return text + "\nUnusable Under Cursor: " + ((!SDK.GameCursor.UnusableUnderCursor) ? "Null" : SDK.GameCursor.UnusableUnderCursor.name);
	}

	private void DrawDebugCursorInfo()
	{
		UIDebug.Instance.SetText("Cursor Debug", GetCursorDebugOutput(), Color.cyan);
		UIDebug.Instance.SetTextPosition("Cursor Debug", 0.95f, 0.95f, UIWidget.Pivot.TopRight);
	}

	private void ValidateObjectsUnderCursors()
	{
		if (SDK.GameCursor.m_genericUnderCursor != null && !SDK.GameCursor.m_genericUnderCursor.activeInHierarchy)
		{
			SDK.GameCursor.m_genericUnderCursor = null;
		}
		if (SDK.GameCursor.m_characterUnderCursor != null && !SDK.GameCursor.m_characterUnderCursor.activeInHierarchy)
		{
			SDK.GameCursor.m_characterUnderCursor = null;
		}
		if (SDK.GameCursor.m_colliderUnderCursor != null && !SDK.GameCursor.m_colliderUnderCursor.enabled)
		{
			SDK.GameCursor.m_colliderUnderCursor = null;
		}
		if (UiObjectUnderCursor != null && !UiObjectUnderCursor.activeInHierarchy)
		{
			UiObjectUnderCursor = null;
		}
		if (SDK.GameCursor.OverrideCharacterUnderCursor != null && !SDK.GameCursor.OverrideCharacterUnderCursor.activeInHierarchy)
		{
			SDK.GameCursor.OverrideCharacterUnderCursor = null;
		}
		if (SDK.GameCursor.UnusableUnderCursor != null && !SDK.GameCursor.UnusableUnderCursor.gameObject.activeInHierarchy)
		{
			SDK.GameCursor.UnusableUnderCursor = null;
		}
	}

	private void Update()
	{
		if (CurrentCursorSet == null)
		{
			return;
		}
		if ((bool)SDK.GameCursor.UnusableUnderCursor && SDK.GameCursor.UnusableUnderCursor.IsUsable)
		{
			SDK.GameCursor.GenericUnderCursor = SDK.GameCursor.UnusableUnderCursor.gameObject;
			SDK.GameCursor.UnusableUnderCursor.NotifyMouseOver(state: true);
			SDK.GameCursor.UnusableUnderCursor = null;
		}
		ValidateObjectsUnderCursors();
		if (ShowDebug)
		{
			DrawDebugCursorInfo();
		}
		if (m_frameCount < 2)
		{
			m_frameCount++;
			return;
		}
		CursorType cursorType = DesiredCursor;
		if (m_loadedCursorSet != DetermineCursorSetType())
		{
			LoadCursorSet(DetermineCursorSetType());
			m_activeCursor = CursorType.None;
		}
		if (cursorType == CursorType.Normal || cursorType == CursorType.NormalHeld)
		{
			cursorType = ((!GameInput.GetMouseButton(0, setHandled: false)) ? CursorType.Normal : CursorType.NormalHeld);
		}
		if (cursorType == CursorType.Walk || cursorType == CursorType.WalkHeld)
		{
			cursorType = ((!GameInput.GetMouseButton(0, setHandled: false)) ? CursorType.Walk : CursorType.WalkHeld);
		}
		if (cursorType == CursorType.Disengage || cursorType == CursorType.DisengageHeld)
		{
			cursorType = ((!GameInput.GetMouseButton(0, setHandled: false)) ? CursorType.Disengage : CursorType.DisengageHeld);
		}
		if (!Cursor.visible || m_activeCursor == cursorType)
		{
			return;
		}
		switch (cursorType)
		{
		case CursorType.Normal:
		case CursorType.Deprecated1:
			SetCursor(CurrentCursorSet.NormalCursor, Vector2.zero);
			break;
		case CursorType.NormalHeld:
			SetCursor(CurrentCursorSet.NormalHeldCursor, Vector2.zero);
			break;
		case CursorType.Walk:
			SetCursor(CurrentCursorSet.WalkCursor, m_centerHotSpot);
			break;
		case CursorType.WalkHeld:
			SetCursor(CurrentCursorSet.WalkHeldCursor, m_centerHotSpot);
			break;
		case CursorType.Disengage:
			SetCursor(CurrentCursorSet.DisengageCursor, m_centerHotSpot);
			break;
		case CursorType.DisengageHeld:
			SetCursor(CurrentCursorSet.DisengageHeldCursor, m_centerHotSpot);
			break;
		case CursorType.NoWalk:
			SetCursor(CurrentCursorSet.NoWalkCursor, m_centerHotSpot);
			break;
		case CursorType.RotateFormation:
			SetCursor(CurrentCursorSet.RotateFormationCursor, m_centerHotSpot);
			break;
		case CursorType.Attack:
			SetCursor(CurrentCursorSet.AttackCursor, Vector2.zero);
			break;
		case CursorType.SpecialAttack:
			SetCursor(CurrentCursorSet.SpecialAttackCursor, Vector2.zero);
			break;
		case CursorType.StealingLocked:
			SetCursor(CurrentCursorSet.StealingLocked, Vector2.zero);
			break;
		case CursorType.OpenDoor:
			SetCursor(CurrentCursorSet.OpenDoorCursor, Vector2.zero);
			break;
		case CursorType.CloseDoor:
			SetCursor(CurrentCursorSet.CloseDoorCursor, Vector2.zero);
			break;
		case CursorType.LockedDoor:
			SetCursor(CurrentCursorSet.LockedDoorCursor, Vector2.zero);
			break;
		case CursorType.BarredDoor:
			SetCursor(CurrentCursorSet.BarredDoorCursor, Vector2.zero);
			break;
		case CursorType.AreaTransition:
			SetCursor(CurrentCursorSet.AreaTransition, Vector2.zero);
			break;
		case CursorType.Examine:
			SetCursor(CurrentCursorSet.ExamineCursor, Vector2.zero);
			break;
		case CursorType.Talk:
			SetCursor(CurrentCursorSet.TalkCursor, Vector2.zero);
			break;
		case CursorType.Interact:
			SetCursor(CurrentCursorSet.InteractCursor, Vector2.zero);
			break;
		case CursorType.CastAbility:
			if (m_castCursorValid && (bool)m_castCursor)
			{
				SetCursor(m_castCursor, Vector2.zero);
			}
			else
			{
				SetCursor(CurrentCursorSet.CastAbility, Vector2.zero);
			}
			break;
		case CursorType.CastAbilityInvalid:
			if (m_castCursorValid && (bool)m_castCursorInvalid)
			{
				SetCursor(m_castCursorInvalid, Vector2.zero);
			}
			else
			{
				SetCursor(CurrentCursorSet.CastAbilityInvalid, Vector2.zero);
			}
			break;
		case CursorType.DoubleArrow_U_D:
			SetCursor(CurrentCursorSet.DoubleArrow_U_D, m_centerHotSpot);
			break;
		case CursorType.DoubleArrow_L_R:
			SetCursor(CurrentCursorSet.DoubleArrow_L_R, m_centerHotSpot);
			break;
		case CursorType.DoubleArrow_DL_UR:
			SetCursor(CurrentCursorSet.DoubleArrow_DL_UR, m_centerHotSpot);
			break;
		case CursorType.DoubleArrow_UL_DR:
			SetCursor(CurrentCursorSet.DoubleArrow_UL_DR, m_centerHotSpot);
			break;
		case CursorType.Disarm:
			SetCursor(CurrentCursorSet.DisarmCursor, Vector2.zero);
			break;
		case CursorType.CastAbilityNoLOS:
			if (m_castCursorValid && (bool)m_castCursorLoS)
			{
				SetCursor(m_castCursorLoS, Vector2.zero);
			}
			else
			{
				SetCursor(CurrentCursorSet.CastAbilityNoLOS, Vector2.zero);
			}
			break;
		case CursorType.CastAbilityFar:
			if (m_castCursorValid && (bool)m_castCursorMove)
			{
				SetCursor(m_castCursorMove, Vector2.zero);
			}
			else
			{
				SetCursor(CurrentCursorSet.CastAbilityFar, Vector2.zero);
			}
			break;
		case CursorType.Stealing:
			SetCursor(CurrentCursorSet.Stealing, Vector2.zero);
			break;
		case CursorType.Loot:
			SetCursor(CurrentCursorSet.LootCursor, Vector2.zero);
			break;
		case CursorType.AttackAdvantage:
			SetCursor(CurrentCursorSet.AttackAdvantageCursor, Vector2.zero);
			break;
		case CursorType.FieldInteraction:
			SetCursor(CurrentCursorSet.FieldInteraction, m_centerHotSpot);
			break;
		case CursorType.ContainerLocked:
			SetCursor(CurrentCursorSet.ContainerLocked, Vector2.zero);
			break;
		default:
			SetCursor(null, Vector2.zero);
			break;
		}
		m_activeCursor = cursorType;
	}

	private void LateUpdate()
	{
		UiCursor = CursorType.None;
		DesiredCursor = CursorType.Normal;
	}

	private CursorSetType DetermineCursorSetType()
	{
		if (GameState.Mode.GetOption(GameOption.BoolOption.HIGH_RES_CURSOR))
		{
			return CursorSetType.Normal64;
		}
		return CursorSetType.Normal;
	}

	private void SetCursor(Texture2D texture, Vector3 offset)
	{
		CursorMode cursorMode = CursorMode.Auto;
		Cursor.SetCursor(texture, offset * s_cursorScale, cursorMode);
	}

	private void LoadCursorSet(CursorSetType cursorSet)
	{
		string text = "Art/UI/CursorSets/";
		switch (cursorSet)
		{
		case CursorSetType.Normal:
			text += "Normal";
			s_cursorScale = 1f;
			break;
		case CursorSetType.Normal64:
			text += "Normal64";
			s_cursorScale = 2f;
			break;
		}
		if (CurrentCursorSet != null)
		{
			Resources.UnloadAsset(CurrentCursorSet);
		}
		CurrentCursorSet = Resources.Load<GameCursorSet>(text);
		m_loadedCursorSet = cursorSet;
	}

	public static void BeginCasting(GenericAbility abil)
	{
		//Discarded unreachable code: IL_02fa
		if ((bool)m_castCursor)
		{
			SDK.GameUtilities.Destroy(m_castCursor);
		}
		m_castCursor = new Texture2D(Instance.CurrentCursorSet.CastAbilityFrame.width, Instance.CurrentCursorSet.CastAbilityFrame.height, TextureFormat.RGBA32, mipmap: false);
		if ((bool)m_castCursorMove)
		{
			SDK.GameUtilities.Destroy(m_castCursorMove);
		}
		m_castCursorMove = new Texture2D(Instance.CurrentCursorSet.CastAbilityMoveFrame.width, Instance.CurrentCursorSet.CastAbilityMoveFrame.height, TextureFormat.RGBA32, mipmap: false);
		if ((bool)m_castCursorInvalid)
		{
			SDK.GameUtilities.Destroy(m_castCursorInvalid);
		}
		m_castCursorInvalid = new Texture2D(Instance.CurrentCursorSet.CastAbilityInvalidFrame.width, Instance.CurrentCursorSet.CastAbilityInvalidFrame.height, TextureFormat.RGBA32, mipmap: false);
		if ((bool)m_castCursorLoS)
		{
			SDK.GameUtilities.Destroy(m_castCursorLoS);
		}
		m_castCursorLoS = new Texture2D(Instance.CurrentCursorSet.CastAbilityLoSFrame.width, Instance.CurrentCursorSet.CastAbilityLoSFrame.height, TextureFormat.RGBA32, mipmap: false);
		if (Instance.CurrentCursorSet.CastAbilityFrameData == null)
		{
			Instance.CurrentCursorSet.CastAbilityFrameData = Instance.CurrentCursorSet.CastAbilityFrame.GetPixels();
		}
		if (Instance.CurrentCursorSet.CastAbilityInvalidFrameData == null)
		{
			Instance.CurrentCursorSet.CastAbilityInvalidFrameData = Instance.CurrentCursorSet.CastAbilityInvalidFrame.GetPixels();
		}
		if (Instance.CurrentCursorSet.CastAbilityMoveFrameData == null)
		{
			Instance.CurrentCursorSet.CastAbilityMoveFrameData = Instance.CurrentCursorSet.CastAbilityMoveFrame.GetPixels();
		}
		if (Instance.CurrentCursorSet.CastAbilityLoSFrameData == null)
		{
			Instance.CurrentCursorSet.CastAbilityLoSFrameData = Instance.CurrentCursorSet.CastAbilityLoSFrame.GetPixels();
		}
		if (Instance.CurrentCursorSet.CastAbilityIconMaskData == null)
		{
			Instance.CurrentCursorSet.CastAbilityIconMaskData = Instance.CurrentCursorSet.CastAbilityIconMask.GetPixels();
		}
		try
		{
			Instance.CreateCastCursorForIcon(Instance.CurrentCursorSet.CastAbilityFrameData, abil.Icon, m_castCursor);
			Instance.CreateCastCursorForIcon(Instance.CurrentCursorSet.CastAbilityInvalidFrameData, abil.Icon, m_castCursorInvalid);
			Instance.CreateCastCursorForIcon(Instance.CurrentCursorSet.CastAbilityLoSFrameData, abil.Icon, m_castCursorLoS);
			Instance.CreateCastCursorForIcon(Instance.CurrentCursorSet.CastAbilityMoveFrameData, abil.Icon, m_castCursorMove);
			m_activeCursor = CursorType.Normal;
			m_castCursorValid = true;
		}
		catch (Exception exception)
		{
			Debug.LogException(exception);
			m_castCursorValid = false;
		}
	}

	private void CreateCastCursorForIcon(Color[] frameColorBuffer, Texture2D abilityIcon, Texture2D outputTexture)
	{
		if (m_castCursorBuffer == null || m_castCursorBuffer.Length != frameColorBuffer.Length)
		{
			m_castCursorBuffer = new Color[frameColorBuffer.Length];
		}
		frameColorBuffer.CopyTo(m_castCursorBuffer, 0);
		int width = Instance.CurrentCursorSet.CastAbilityIconMask.width;
		int height = Instance.CurrentCursorSet.CastAbilityIconMask.height;
		for (int i = 0; i < width; i++)
		{
			for (int j = 0; j < height; j++)
			{
				int num = i + j * width;
				if (!(Instance.CurrentCursorSet.CastAbilityIconMaskData[num].a <= 0f))
				{
					Color color = ((!(abilityIcon == null)) ? abilityIcon.GetPixelBilinear((float)i / (float)width, (float)j / (float)height) : Color.white);
					Color color2 = frameColorBuffer[num];
					color.r = color2.r * color2.a + color.a * color.r * (1f - color2.a);
					color.g = color2.g * color2.a + color.a * color.g * (1f - color2.a);
					color.b = color2.b * color2.a + color.a * color.b * (1f - color2.a);
					color.a = color2.a + (1f - color2.a) * Instance.CurrentCursorSet.CastAbilityIconMaskData[num].a;
					m_castCursorBuffer[num] = color;
				}
			}
		}
		outputTexture.SetPixels(m_castCursorBuffer);
		outputTexture.Apply();
	}

	public static void EndCasting()
	{
		m_castCursorValid = false;
	}
}

