445				}
446			}
447			if (s_ReturningToMainMenuFromError)
448			{
449				UIWindowManager.ShowMessageBox(UIMessageBox.UIDialogButtons.OK, SDK.GUIUtils.GetText(4417), SDK.GUIUtils.GetText(4418));
450				s_ReturningToMainMenuFromError = false;
451			}
452			Time.timeScale = 1f;
453			if (m_refreshMenuButtons)
454			{
455				UIMainMenuClickHandler[] componentsInChildren = GetComponentsInChildren<UIMainMenuClickHandler>(includeInactive: true);
456				UIMainMenuClickHandler[] array = componentsInChildren;
457				foreach (UIMainMenuClickHandler uIMainMenuClickHandler in array)
458				{
459					uIMainMenuClickHandler.RefreshState();
460				}
461				m_refreshMenuButtons = false;
462			}
463			if (MusicManager.Instance != null && m_needsToPlayMenuMusic)
464			{
465				MusicManager.FadeParams fadeParams = new MusicManager.FadeParams();
466				fadeParams.FadeInDuration = 0f;
467				fadeParams.FadeOutDuration = 0f;
468				MusicManager.Instance.PlayMusic(Music, fadeParams, loop: true);
469				m_needsToPlayMenuMusic = false;
470			}
471			if (Screen.width != m_lastScreenWidth || Screen.height != m_lastScreenHeight)
472			{
473				float num = Screen.height;
474				float num2 = Screen.width;
475				UIRoot uIRoot = NGUITools.FindInParents<UIRoot>(MaxScreenSize.gameObject);
476				if (uIRoot != null)
477				{
478					num = Mathf.Min(num, uIRoot.maximumHeight);
479				}
480				float num3 = Mathf.Min((float)Screen.width / (float)Screen.height, 2.0833333f);
481				num2 = num3 * num;
482				Vector3 localScale = MaxScreenSize.transform.localScale;
483				localScale.x = num2;
484				localScale.y = num;
485				MaxScreenSize.transform.localScale = localScale;
486				m_lastScreenHeight = Screen.height;
487				m_lastScreenWidth = Screen.width;
488			}
489			if (m_Active)
490			{
491				if (m_Locked)
492				{
493					UIPanel[] menuPanels = MenuPanels;
494					foreach (UIPanel uIPanel in menuPanels)
495					{
496						uIPanel.alpha = 0f;
497					}
498					return;
499				}
500				HandleWaitForSaveCachingDisplay();
501				HandleDebugInput();
502				UIPanel[] menuPanels2 = MenuPanels;
503				foreach (UIPanel uIPanel2 in menuPanels2)
504				{
505					uIPanel2.alpha = Mathf.Min(1f, uIPanel2.alpha + 2f * Time.deltaTime);
506				}
507			}
508			else
509			{
510				UIPanel[] menuPanels3 = MenuPanels;
511				foreach (UIPanel uIPanel3 in menuPanels3)
512				{
513					uIPanel3.alpha = Mathf.Max(0f, uIPanel3.alpha - 2f * Time.deltaTime);
514				}
515			}
516		}
517	}
