	private void HandleWaitForSaveCachingDisplay()
	{
		if (m_loadingSaveCacheWidgets == null)
		{
			return;
		}
		for (int i = 0; i < m_loadingSaveCacheWidgets.Length; i++)
		{
			UIWidget uIWidget = m_loadingSaveCacheWidgets[i];
			if (!SaveGameInfo.SaveCachingComplete())
			{
				UIAnchor component = uIWidget.GetComponent<UIAnchor>();
				if ((bool)component && component.widgetContainer != null)
				{
					GuiStringLabelOverride component2 = component.widgetContainer.GetComponent<GuiStringLabelOverride>();
					if ((bool)component2)
					{
						component2.BeginOverride();
					}
				}
				uIWidget.alpha = Mathf.Min(0.5f, uIWidget.alpha + Time.deltaTime * 2f);
			}
			else
			{
				UIAnchor component3 = uIWidget.GetComponent<UIAnchor>();
				if ((bool)component3 && component3.widgetContainer != null)
				{
					GuiStringLabelOverride component4 = component3.widgetContainer.GetComponent<GuiStringLabelOverride>();
					if ((bool)component4)
					{
						component4.EndOverride();
					}
				}
				uIWidget.alpha = Mathf.Max(0f, uIWidget.alpha - Time.deltaTime * 2f);
			}
			if (uIWidget.alpha > 0f && uIWidget is UISprite)
			{
				uIWidget.transform.rotation = Quaternion.Euler(uIWidget.transform.rotation.eulerAngles.x, uIWidget.transform.rotation.eulerAngles.y, uIWidget.transform.rotation.eulerAngles.z - 190f * Time.deltaTime);
			}
		}
	}

	public static void StartingGame()
	{
		if (s_instance != null)
		{
			MusicManager.Instance.FadeOutAreaMusic(s_instance.MusicFadeOutDuration);
			if (GlobalAudioPlayer.Instance != null && s_instance.StartGameSFx != null && MusicManager.Instance != null)
			{
				GlobalAudioPlayer.Instance.StartCoroutine(Coroutine_PlayNewGameStinger());
			}
		}
	}

	private static IEnumerator Coroutine_PlayNewGameStinger()
	{
		if (GlobalAudioPlayer.Instance == null || MusicManager.Instance == null || s_instance.StartGameSFx == null)
		{
			yield break;
		}
		GameObject newObj = Object.Instantiate(AudioBank.DefaultSource);
		if (!newObj)
		{
			yield break;
		}
		AudioSource newAudio = newObj.GetComponent<AudioSource>();
		if (newAudio != null)
		{
			newObj.transform.parent = GlobalAudioPlayer.Instance.transform;
			AudioClip stingerToPlay = s_instance.StartGameSFx;
			newObj.name = stingerToPlay.name;
			newAudio.clip = stingerToPlay;
			VolumeAsCategory volCat = newAudio.GetComponent<VolumeAsCategory>();
			if (volCat == null)
			{
				volCat = newAudio.gameObject.AddComponent<VolumeAsCategory>();
			}
			volCat.Category = MusicManager.SoundCategory.MUSIC;
			volCat.IgnoreAllButMusicAudioFade = true;
			volCat.UpdateVolume();
			newAudio.ignoreListenerPause = true;
			newAudio.ignoreListenerVolume = true;
			newAudio.spatialBlend = 0f;
			newAudio.Play();
			while (newAudio.isPlaying)
			{
				yield return null;
			}
			SDK.GameUtilities.Destroy(newObj);
		}
	}

	private void HandleDeviceRecreated()
	{
		Debug.Log("MainMenuManager::HandleDeviceRecreated() - Reloading main menu after device lost.");
		SceneManager.LoadScene("MainMenu", LoadSceneMode.Single);
	}

	private string GetLegalLanguageCode()
	{
		string empty = string.Empty;
		return m_legalLanguage switch
		{
			LegalLanguageType.LLT_Chosen => Thread.CurrentThread.CurrentCulture.TwoLetterISOLanguageName, 
			_ => "en", 
		};
	}

	private void LegalDocumentsCallback(ICollection<PopsApiWrapper.LegalDocumentListEntry> documentsList)
	{
		Debug.Log("Legal Documents Query took: " + (Time.realtimeSinceStartup - m_legalDocumentsStartTime));
		foreach (PopsApiWrapper.LegalDocumentListEntry documents in documentsList)
		{
			if (documents.Type == m_legalDocumentType && documents.Title == m_legalDocumentTitle)
			{
				m_legalDocumentsStartTime = Time.realtimeSinceStartup;
				Game.OnlineServicesManager.Instance.GetLegalDocument(GDPRDocumentCallback, m_legalDocumentType, m_legalDocumentTitle, GetLegalLanguageCode());
				return;
			}
		}
		m_Locked = false;
	}

	private void GDPRDocumentCallback(PopsApiWrapper.LegalDocument document, bool success, string msg)
	{
		if (success)
		{
			Debug.Log("GDPR Document Query took: " + (Time.realtimeSinceStartup - m_legalDocumentsStartTime));
			m_legalDocumentsStartTime = Time.realtimeSinceStartup;
			ParadoxGDPR.Show(document.Raw, document.Title);
			Debug.Log("GDPR Show took: " + (Time.realtimeSinceStartup - m_legalDocumentsStartTime));
		}
		else if (msg.Contains("bad-input") && m_legalLanguage == LegalLanguageType.LLT_Chosen)
		{
			m_legalLanguage = LegalLanguageType.LLT_ForceEnglish;
			Game.OnlineServicesManager.Instance.GetLegalDocument(GDPRDocumentCallback, document.Title, document.Type, GetLegalLanguageCode());
		}
		else
		{
			m_Locked = false;
		}
	}

	private void Update()
	{
		if (!m_handledLegalDocuments)
		{
			m_handledLegalDocuments = true;
			if (!PlayerPrefs.HasKey("HasShownGDPR"))
			{
				m_Locked = true;
				m_legalDocumentsStartTime = Time.realtimeSinceStartup;
				Game.OnlineServicesManager.Instance.GetLegalDocument(GDPRDocumentCallback, m_legalDocumentType, m_legalDocumentTitle, GetLegalLanguageCode());
			}
		}
		if (s_ReturningToMainMenuFromError)
		{
			UIWindowManager.ShowMessageBox(UIMessageBox.UIDialogButtons.OK, SDK.GUIUtils.GetText(4417), SDK.GUIUtils.GetText(4418));
			s_ReturningToMainMenuFromError = false;
		}
		Time.timeScale = 1f;
		if (m_refreshMenuButtons)
		{
			UIMainMenuClickHandler[] componentsInChildren = GetComponentsInChildren<UIMainMenuClickHandler>(includeInactive: true);
			UIMainMenuClickHandler[] array = componentsInChildren;
			foreach (UIMainMenuClickHandler uIMainMenuClickHandler in array)
			{
				uIMainMenuClickHandler.RefreshState();
			}
			m_refreshMenuButtons = false;
		}
		if (MusicManager.Instance != null && m_needsToPlayMenuMusic)
		{
			MusicManager.FadeParams fadeParams = new MusicManager.FadeParams();
			fadeParams.FadeInDuration = 0f;
			fadeParams.FadeOutDuration = 0f;
			MusicManager.Instance.PlayMusic(Music, fadeParams, loop: true);
			m_needsToPlayMenuMusic = false;
		}
		if (Screen.width != m_lastScreenWidth || Screen.height != m_lastScreenHeight)
		{
			float num = Screen.height;
			float num2 = Screen.width;
			UIRoot uIRoot = NGUITools.FindInParents<UIRoot>(MaxScreenSize.gameObject);
			if (uIRoot != null)
			{
				num = Mathf.Min(num, uIRoot.maximumHeight);
			}
			float num3 = Mathf.Min((float)Screen.width / (float)Screen.height, 2.0833333f);
			num2 = num3 * num;
			Vector3 localScale = MaxScreenSize.transform.localScale;
			localScale.x = num2;
			localScale.y = num;
			MaxScreenSize.transform.localScale = localScale;
			m_lastScreenHeight = Screen.height;
			m_lastScreenWidth = Screen.width;
		}
		if (m_Active)
		{
			if (m_Locked)
			{
				UIPanel[] menuPanels = MenuPanels;
				foreach (UIPanel uIPanel in menuPanels)
				{
					uIPanel.alpha = 0f;
				}
				return;
			}
			HandleWaitForSaveCachingDisplay();
			HandleDebugInput();
			UIPanel[] menuPanels2 = MenuPanels;
			foreach (UIPanel uIPanel2 in menuPanels2)
			{
				uIPanel2.alpha = Mathf.Min(1f, uIPanel2.alpha + 2f * Time.deltaTime);
			}
		}
		else
		{
			UIPanel[] menuPanels3 = MenuPanels;
			foreach (UIPanel uIPanel3 in menuPanels3)
			{
				uIPanel3.alpha = Mathf.Max(0f, uIPanel3.alpha - 2f * Time.deltaTime);
			}
		}
	}
}

