using System;
using System.Collections;
using System.Collections.Generic;
using SDK;
using UnityEngine;
using UnityEngine.SceneManagement;

namespace Game;

[AddComponentMenu("Edict/Edict Manager")]
public class EdictManager : MonoBehaviour
{
	public static EdictManager Instance;

	[Tooltip("An array of all the edicts that can be called in the game.")]
	public EdictPackage[] EdictPackages;

	[Persistent]
	private List<EdictPackage> m_KnownEdictPackages = new List<EdictPackage>();

	private EdictToggle[] EdictToggles;

	[Persistent]
	private SerializableDictionary<Region, Edict> m_ActiveEdicts = new SerializableDictionary<Region, Edict>();

	[Persistent]
	private bool m_InitializedRegions;

	public EdictPackage LastEdictPackageActivated { get; private set; }

	public static event EventHandler EdictPreActivated;

	public static event EventHandler EdictPostActivated;

	public static event EventHandler EdictPreDeactivated;

	public static event EventHandler EdictPostDeactivated;

	private void Awake()
	{
		Instance = this;
		SDK.GameState.LevelUnload += GameState_LevelUnload;
		SDK.GameState.LevelLoaded += GameState_LevelLoaded;
	}

	private void Start()
	{
		InitializeRegions();
	}

	private void OnDestroy()
	{
		if (Instance == this)
		{
			Instance = null;
		}
		SDK.GameState.LevelUnload -= GameState_LevelUnload;
		SDK.GameState.LevelLoaded -= GameState_LevelLoaded;
		ComponentUtils.NullOutObjectReferences(this);
	}

	private void InitializeRegions()
	{
		if (m_InitializedRegions)
		{
			return;
		}
		List<Region> allRegions = WorldMap.Instance.AllRegions;
		for (int i = 0; i < allRegions.Count; i++)
		{
			if (allRegions[i].StartingEdict != null)
			{
				ActivateEdict(allRegions[i], allRegions[i].StartingEdict);
			}
		}
		m_InitializedRegions = true;
	}

	private void GameState_LevelUnload(object sender, EventArgs e)
	{
		if (GameState.Instance.CurrentRegion != null && m_ActiveEdicts.ContainsKey(GameState.Instance.CurrentRegion))
		{
			Edict edict = m_ActiveEdicts[GameState.Instance.CurrentRegion];
			if ((bool)edict)
			{
				edict.Deactivate();
			}
		}
	}

	private void GameState_LevelLoaded(object sender, EventArgs e)
	{
		if (GameState.Instance.CurrentRegion != null && m_ActiveEdicts.ContainsKey(GameState.Instance.CurrentRegion))
		{
			Edict edict = m_ActiveEdicts[GameState.Instance.CurrentRegion];
			StartCoroutine(ActivateEdictAfterLoading(edict));
		}
		EdictToggles = UnityEngine.Object.FindObjectsOfType<EdictToggle>();
		UpdateGameObjectStatus();
		SetActiveStartupGameobjects(enabled: false);
	}

	private IEnumerator ActivateEdictAfterLoading(Edict edict)
	{
		if ((bool)edict)
		{
			while (SDK.GameState.IsLoading || SDK.GameState.IsRestoredLevel)
			{
				yield return null;
			}
			if (!edict)
			{
				Debug.LogError("EdictManager.ActivateEdictAfterLoading() - Unable to activate edict after loading.");
			}
			else
			{
				edict.Activate();
			}
		}
	}

	public void OnCharacterSpawned(CharacterStats newCharacter)
	{
		if (!SDK.GameState.IsLoading && !SDK.GameState.IsRestoredLevel)
		{
			Edict activeEdict = GetActiveEdict();
			if ((bool)activeEdict && !SDK.GameState.IsTransitionInProgress)
			{
				activeEdict.OnCharacterSpawned(newCharacter);
			}
		}
	}

	public void LearnEdictPackage(string edictPackageTag)
	{
		EdictPackage edictPackageByTag = GetEdictPackageByTag(edictPackageTag);
		if (!edictPackageByTag)
		{
			Debug.LogError("Attempted to learn an edict package that could not be found: " + edictPackageTag + ".");
		}
		else
		{
			LearnEdictPackage(edictPackageByTag);
		}
	}

	public void LearnEdictPackage(EdictPackage epackage)
	{
		if (epackage != null && !IsEdictPackageKnown(epackage))
		{
			m_KnownEdictPackages.Add(epackage);
			Console.AddMessage("Learned Edict: " + epackage.Tag + ".", Console.ConsoleState.DEBUG);
		}
	}

	public void SetActiveStartupGameobjects(bool enabled)
	{
		if (SceneManager.GetActiveScene().name.Equals(MapType.AR_0001_Stronghold_01.ToString()))
		{
			StrongholdEdictStartupVFX[] array = UnityEngine.Object.FindObjectsOfType<StrongholdEdictStartupVFX>();
			for (int i = 0; i < array.Length; i++)
			{
				array[i].Evaluate(enabled);
			}
		}
	}

	public void UpdateGameObjectStatus()
	{
		if (EdictToggles == null)
		{
			return;
		}
		EdictToggle edictToggle = null;
		for (int i = 0; i < EdictToggles.Length; i++)
		{
			edictToggle = EdictToggles[i];
			if (edictToggle.GetActiveStatus(GameState.Instance.CurrentRegion))
			{
				if (!edictToggle.gameObject.activeSelf)
				{
					edictToggle.gameObject.SetActive(value: true);
				}
			}
			else if (edictToggle.gameObject.activeSelf)
			{
				edictToggle.gameObject.SetActive(value: false);
			}
		}
	}

	public void ActivateEdictPackage(Region region, EdictPackage epackage)
	{
		if (!region)
		{
			Debug.LogWarning("Could not activate an edict: invalid region.");
			return;
		}
		if (!epackage)
		{
			Debug.LogWarning("Could not activate an edict: EdictPackage does not exist.");
			return;
		}
		if (region.ActiveEdict != null)
		{
			Debug.LogWarning("Could not activate an edict: an edict is already in effect in this region.");
			return;
		}
		Edict edictForRegion = epackage.GetEdictForRegion(region);
		if (!edictForRegion)
		{
			Debug.LogWarning("Could not activate an edict: edict does not exist.");
			return;
		}
		LastEdictPackageActivated = epackage;
		ActivateEdict(region, edictForRegion);
	}

	public void ActivateEdictPackage(string regionTag, string edictPackageTag)
	{
		ActivateEdictPackage(WorldMap.Instance.GetRegionByTag(regionTag), edictPackageTag);
	}

	public void ActivateEdictPackage(Region region, string edictPackageTag)
	{
		ActivateEdictPackage(region, GetEdictPackageByTag(edictPackageTag));
	}

	private void ActivateEdict(Region region, Edict edict)
	{
		if (!(region == null) && !(edict == null) && !(region.ActiveEdict != null))
		{
			m_ActiveEdicts[region] = edict;
			if ((bool)region && region.Equals(GameState.Instance.CurrentRegion))
			{
				OnEdictPreActivated(edict, EventArgs.Empty);
				edict.Activate();
				OnEdictPostActivated(edict, EventArgs.Empty);
			}
			UpdateGameObjectStatus();
			SetActiveStartupGameobjects(enabled: true);
		}
	}

	public void DeactivateEdict(string regionTag)
	{
		DeactivateEdict(WorldMap.Instance.GetRegionByTag(regionTag));
	}

	public void DeactivateEdict(Region region)
	{
		if ((bool)region && !(region.ActiveEdict == null))
		{
			OnEdictPreDeactivated(region.ActiveEdict, EventArgs.Empty);
			region.ActiveEdict.Deactivate();
			m_ActiveEdicts[region] = null;
			OnEdictPostDeactivated(null, EventArgs.Empty);
			UpdateGameObjectStatus();
			SetActiveStartupGameobjects(enabled: false);
		}
	}

	public Edict GetEdictByTag(string tag)
	{
		for (int i = 0; i < EdictPackages.Length; i++)
		{
			if (string.Compare(tag, EdictPackages[i].DefaultEdict.Tag, ignoreCase: true) == 0)
			{
				return EdictPackages[i].DefaultEdict;
			}
			for (int j = 0; j < EdictPackages[i].OverrideData.Count; j++)
			{
				if (EdictPackages[i].OverrideData[j].OverrideEdict != null && string.Compare(tag, EdictPackages[i].OverrideData[j].OverrideEdict.Tag, ignoreCase: true) == 0)
				{
					return EdictPackages[i].OverrideData[j].OverrideEdict;
				}
			}
		}
		return null;
	}

	public EdictPackage GetEdictPackageByTag(string tag)
	{
		for (int i = 0; i < EdictPackages.Length; i++)
		{
			if (string.Compare(tag, EdictPackages[i].Tag, ignoreCase: true) == 0)
			{
				return EdictPackages[i];
			}
		}
		return null;
	}

	public bool IsEdictPackageActiveForRegion(EdictPackage epackage, Region region)
	{
		if (!region || region.ActiveEdict == null || epackage == null)
		{
			return false;
		}
		Edict edictForRegion = epackage.GetEdictForRegion(region);
		if (edictForRegion != null && string.Compare(edictForRegion.Tag, region.ActiveEdict.Tag) == 0)
		{
			return true;
		}
		return false;
	}

	public bool IsEdictPackageActiveForRegion(string edictPackageTag, string regionTag)
	{
		return IsEdictPackageActiveForRegion(GetEdictPackageByTag(edictPackageTag), WorldMap.Instance.GetRegionByTag(regionTag));
	}

	public bool IsEdictPackageActive(string edictPackageTag)
	{
		return IsEdictPackageActiveForRegion(GetEdictPackageByTag(edictPackageTag), GameState.Instance.CurrentRegion);
	}

	public Edict GetActiveEdict()
	{
		if (!GameState.Instance)
		{
			return null;
		}
		Region currentRegion = GameState.Instance.CurrentRegion;
		return GetActiveEdict(currentRegion);
	}

	public Edict GetActiveEdict(Region region)
	{
		if (!region)
		{
			return null;
		}
		Edict value = null;
		m_ActiveEdicts.TryGetValue(region, out value);
		return value;
	}

	public bool IsFromActiveEdict(Affliction affliction)
	{
		Edict activeEdict = GetActiveEdict();
		if (activeEdict != null)
		{
			return activeEdict.IsFromEdict(affliction);
		}
		return false;
	}

	public EdictPackage GetEdictPackage(Edict edict)
	{
		if (edict != null)
		{
			for (int i = 0; i < EdictPackages.Length; i++)
			{
				if (EdictPackages[i].DefaultEdict != null && string.Compare(edict.Tag, EdictPackages[i].DefaultEdict.Tag) == 0)
				{
					return EdictPackages[i];
				}
				for (int j = 0; j < EdictPackages[i].OverrideData.Count; j++)
				{
					if (EdictPackages[i].OverrideData[j].OverrideEdict != null && string.Compare(edict.Tag, EdictPackages[i].OverrideData[j].OverrideEdict.Tag) == 0)
					{
						return EdictPackages[i];
					}
				}
			}
		}
		return null;
	}

	public bool IsEdictPackageKnown(string edictPackageTag)
	{
		return IsEdictPackageKnown(GetEdictPackageByTag(edictPackageTag));
	}

	public bool IsEdictPackageKnown(EdictPackage epackage)
	{
		if (epackage != null)
		{
			for (int i = 0; i < m_KnownEdictPackages.Count; i++)
			{
				if (m_KnownEdictPackages[i] != null && string.Compare(epackage.Tag, m_KnownEdictPackages[i].Tag) == 0)
				{
					return true;
				}
			}
		}
		return false;
	}

	protected static void OnEdictPreActivated(object sender, EventArgs e)
	{
		EdictManager.EdictPreActivated?.Invoke(sender, e);
	}

	protected static void OnEdictPostActivated(object sender, EventArgs e)
	{
		EdictManager.EdictPostActivated?.Invoke(sender, e);
	}

	protected static void OnEdictPreDeactivated(object sender, EventArgs e)
	{
		EdictManager.EdictPreDeactivated?.Invoke(sender, e);
	}

	protected static void OnEdictPostDeactivated(object sender, EventArgs e)
	{
		EdictManager.EdictPostDeactivated?.Invoke(sender, e);
	}
}

