using System.Collections.Generic;
using Game;
using SDK;
using UnityEngine;
using UnityEngine.SceneManagement;

public class UINewGameScreen : MonoBehaviour
{
	public UIPanel PanelNewGame;

	public TweenAlpha NewGameTween;

	public UIMultiSpriteImageButton NewGameAcceptButton;

	public UIMultiSpriteImageButton NewGameCancelButton;

	public UIRadioButtonGroup DifficultyRadioButtonGroup;

	public UILabel TooltipLabel;

	public UIWidget MaxTooltipSizer;

	public UIAnchor BackgroundPosition;

	public UIOptionsTag ExpertMode;

	public UIOptionsTag TrialOfIron;

	public UIOptionsTag LegacyMode;

	private float m_initialBackgroundOffsetY = -1f;

	private GameMode m_GameMode;

	private void Start()
	{
		UIMultiSpriteImageButton newGameCancelButton = NewGameCancelButton;
		newGameCancelButton.onClick = (UIEventListener.VoidDelegate)Delegate.Combine(newGameCancelButton.onClick, new UIEventListener.VoidDelegate(OnCancelClick));
		UIMultiSpriteImageButton newGameAcceptButton = NewGameAcceptButton;
		newGameAcceptButton.onClick = (UIEventListener.VoidDelegate)Delegate.Combine(newGameAcceptButton.onClick, new UIEventListener.VoidDelegate(OnAcceptClick));
		UILegacyLoadSaveManager legacyLoadSaveManager = UIMainMenuManager.Instance.LegacyLoadSaveManager;
		legacyLoadSaveManager.OnWindowHidden = (UIHudWindow.WindowHiddenDelegate)Delegate.Combine(legacyLoadSaveManager.OnWindowHidden, new UIHudWindow.WindowHiddenDelegate(OpenScreen));
	}

	private void OnDestroy()
	{
		UIMultiSpriteImageButton newGameCancelButton = NewGameCancelButton;
		newGameCancelButton.onClick = (UIEventListener.VoidDelegate)Delegate.Remove(newGameCancelButton.onClick, new UIEventListener.VoidDelegate(OnCancelClick));
		UIMultiSpriteImageButton newGameAcceptButton = NewGameAcceptButton;
		newGameAcceptButton.onClick = (UIEventListener.VoidDelegate)Delegate.Remove(newGameAcceptButton.onClick, new UIEventListener.VoidDelegate(OnAcceptClick));
		UILegacyLoadSaveManager legacyLoadSaveManager = UIMainMenuManager.Instance.LegacyLoadSaveManager;
		legacyLoadSaveManager.OnWindowHidden = (UIHudWindow.WindowHiddenDelegate)Delegate.Remove(legacyLoadSaveManager.OnWindowHidden, new UIHudWindow.WindowHiddenDelegate(OpenScreen));
	}

	private void Awake()
	{
		m_GameMode = new GameMode();
	}

	private void Update()
	{
		if (PanelNewGame.gameObject.activeInHierarchy && PanelNewGame.alpha > 0.99f && Input.GetKeyDown(KeyCode.Escape))
		{
			OnCancelClick(NewGameCancelButton.gameObject);
		}
	}

	public void OpenScreen()
	{
		if (!SDK.GameState.LegacyItemSelect)
		{
			m_GameMode.CopyFrom(Game.GameState.Mode);
			m_GameMode.Difficulty = GameDifficulty.Normal;
			ExpertMode.Checkbox.isChecked = m_GameMode.Expert;
			ExpertMode.Background.SetTintColors(UIGlobalColor.Instance.Get(UIGlobalColor.ColorLookupID.BUTTON_DEFAULT_NORMAL));
			TrialOfIron.Checkbox.isChecked = m_GameMode.TrialOfIron;
			TrialOfIron.Background.SetTintColors(UIGlobalColor.Instance.Get(UIGlobalColor.ColorLookupID.BUTTON_DEFAULT_NORMAL));
			Game.GameState.Instance.NewGamePlusIteration = 0;
			Game.GameState.Instance.NewGamePlusSaveFilepath = string.Empty;
			LegacyMode.Checkbox.isChecked = m_GameMode.LegacyMode;
			bool flag = SaveGameInfo.GetLegacyModeEligableSaves().Count > 0 || Game.CommandLine.S_LEGACYMODE_ALLOW_ALL_SAVES;
			LegacyMode.Checkbox.enabled = flag;
			LegacyMode.Background.SetTintColors(UIGlobalColor.Instance.Get((!flag) ? UIGlobalColor.ColorLookupID.DISABLED_GRAY : UIGlobalColor.ColorLookupID.BUTTON_DEFAULT_NORMAL));
			DifficultyRadioButtonGroup.Reinitialize();
			UIOptionsTag currentSelectedRadioButton = GetCurrentSelectedRadioButton();
			if ((bool)currentSelectedRadioButton)
			{
				UIOptionsTooltip.Show(currentSelectedRadioButton.TooltipString.GetText());
			}
			NewGameTween.Play(forward: true);
			StartCoroutine(Coroutine_DetermineMaxTextSize());
		}
	}

	public void OnAcceptClick(GameObject go)
	{
		UIWindowManager.EnableWindowVisibilityHandling();
		UIOptionsTag currentSelectedRadioButton = GetCurrentSelectedRadioButton();
		if (currentSelectedRadioButton != null)
		{
			m_GameMode.Difficulty = currentSelectedRadioButton.Difficulty;
		}
		m_GameMode.TrialOfIron = TrialOfIron.Checkbox.isChecked;
		m_GameMode.Expert = ExpertMode.Checkbox.isChecked;
		m_GameMode.LegacyMode = LegacyMode.Checkbox.isChecked;
		Game.GameState.Mode.CopyFrom(m_GameMode);
		Game.GameState.Mode.SaveToPrefs();
		if (!m_GameMode.LegacyMode)
		{
			StartIntro();
			return;
		}
		NewGameTween.Play(forward: false);
		StartCoroutine(TurnOnLegacyLoadSave(NewGameTween.delay));
	}

	private void OnCancelClick(GameObject go)
	{
		NewGameTween.Play(forward: false);
		StartCoroutine(TurnOnMainMenu(NewGameTween.delay));
	}

	private UIOptionsTag GetCurrentSelectedRadioButton()
	{
		return DifficultyRadioButtonGroup.Selected.GetComponent<UIOptionsTag>();
	}

	private IEnumerator Coroutine_DetermineMaxTextSize()
	{
		while (TooltipLabel.font == null)
		{
			yield return null;
		}
		float size = FindTallestStringForDifficulties();
		Vector3 maxSize = MaxTooltipSizer.transform.localScale;
		maxSize.y = size;
		MaxTooltipSizer.transform.localScale = maxSize;
		if (m_initialBackgroundOffsetY < 0f)
		{
			m_initialBackgroundOffsetY = BackgroundPosition.pixelOffset.y;
		}
		BackgroundPosition.pixelOffset.y = m_initialBackgroundOffsetY + size / 2f;
	}

	private IEnumerator TurnOnMainMenu(float time)
	{
		yield return new WaitForSeconds(time);
		UIMainMenuManager.Instance.MenuActive = true;
	}

	private IEnumerator TurnOnLegacyLoadSave(float time)
	{
		yield return new WaitForSeconds(time);
		UIMainMenuManager.Instance.LegacyLoadSaveManager.OpenScreen();
	}

	private float FindTallestStringForDifficulties()
	{
		if (TooltipLabel == null || TooltipLabel.font == null)
		{
			return 0f;
		}
		float num = -1f;
		List<UIOptionsTag> list = new List<UIOptionsTag>(DifficultyRadioButtonGroup.GetComponentsInChildren<UIOptionsTag>(includeInactive: true));
		list.Add(ExpertMode);
		list.Add(TrialOfIron);
		list.Add(LegacyMode);
		for (int i = 0; i < list.Count; i++)
		{
			UIOptionsTag uIOptionsTag = list[i];
			if (uIOptionsTag != null)
			{
				TooltipLabel.text = uIOptionsTag.TooltipString.GetText();
				float num2 = TooltipLabel.relativeSize.y * TooltipLabel.transform.localScale.y;
				if (num2 > num)
				{
					num = num2;
				}
			}
		}
		UIOptionsTag currentSelectedRadioButton = GetCurrentSelectedRadioButton();
		if ((bool)currentSelectedRadioButton)
		{
			UIOptionsTooltip.Show(currentSelectedRadioButton.TooltipString.GetText());
		}
		return num;
	}

	private void StartIntro()
	{
		if (!PlayerPrefs.HasKey("GamesStarted"))
		{
			PlayerPrefs.SetInt("GamesStarted", 1);
			PlayerPrefs.Save();
			SDK.GameState.FirstPlaythrough = true;
		}
		else
		{
			PlayerPrefs.SetInt("GamesStarted", PlayerPrefs.GetInt("GamesStarted") + 1);
			PlayerPrefs.Save();
		}
		Game.GameState.Instance.PlaythroughGUID = Guid.NewGuid();
		SDK.GameState.NewGame = true;
		UIMainMenuManager.StartingGame();
		UILoadingScreen.CreateInstanceIfNeeded();
		UILoadingScreen.Show(MapData.LoadingScreenType.Character_Creation, HandleNewGameLoadingScreenShowing, playLoadingMusic: true);
	}

	private void HandleNewGameLoadingScreenShowing()
	{
		SceneManager.LoadScene("LifePath", LoadSceneMode.Single);
	}
}

