			AfflictionEdictMod component = GetComponent<AfflictionEdictMod>();
			if ((bool)component)
			{
				return component.Icon;
			}
			return null;
		}
	}

	public virtual void Activate()
	{
		Component[] components = base.gameObject.GetComponents(typeof(EdictMod));
