		Component[] array = components;
		foreach (Component component in array)
		{
			(component as EdictMod).OnActivated(levelObjectGuid);
		}
		m_dayNightMod = base.gameObject.GetComponent<DayNightEdictMod>();
		if (m_dayNightMod != null && !m_dayNightMod.UseTimeOfDayColor)
		{
			PE_DayNightRender.GetOverrideColor = GetDayNightColor;
			PE_DayNightRender.GetOverrideIntensity = GetDayNightIntensity;
			PE_DayNightRender.GetOverrideGrade = GetDayNightGrade;
		}
		PE_StreamTile.GetLevelNameSuffix = GetFlipperSuffix;
	}

	public virtual void Deactivate()
	{
		Component[] components = base.gameObject.GetComponents(typeof(EdictMod));
		Guid levelObjectGuid = GetLevelObjectGuid();
		Component[] array = components;
		foreach (Component component in array)
		{
			(component as EdictMod).OnDeactivated(levelObjectGuid);
		}
		m_dayNightMod = base.gameObject.GetComponent<DayNightEdictMod>();
		if (m_dayNightMod != null && !m_dayNightMod.UseTimeOfDayColor)
		{
			PE_DayNightRender.GetOverrideColor = GetDayNightColorDefault;
			PE_DayNightRender.GetOverrideIntensity = GetDayNightIntensityDefault;
			PE_DayNightRender.GetOverrideGrade = GetDayNightGradeDefault;
		}
		PE_StreamTile.GetLevelNameSuffix = GetFlipperSuffixDefault;
	}

	public void OnCharacterSpawned(CharacterStats newCharacter)
