		TileFlipperEdictMod component = GetComponent<TileFlipperEdictMod>();
		if (component != null && component.Frame > 0)
		{
			return "_f" + Console.Format("{0:000}", component.Frame);
		}
		return GetFlipperSuffixDefault();
	}

	public string GetFlipperSuffixDefault()
	{
		return string.Empty;
	}

	public Color GetDayNightColor()
	{
		if (m_dayNightMod != null)
		{
			return m_dayNightMod.LightColor;
		}
		return GetDayNightColorDefault();

