322		private void UpdateTimeScale(bool prevPausedState)
323		{
324			UpdateTimeScale();
325			if (prevPausedState == (m_PlayerPaused || m_UiPaused))
326			{
327				return;
328			}
329			if (m_PlayerPaused || m_UiPaused)
330			{
331				AudioSource[] array = UnityEngine.Object.FindObjectsOfType<AudioSource>();
332				m_sourcesPaused.Clear();
333				for (int i = 0; i < array.Length; i++)
334				{
335					if ((bool)array[i].clip && array[i].isPlaying && !IsAudioSourceExcemptFromPause(array[i]))
336					{
337						array[i].Pause();
338						m_sourcesPaused.Add(array[i]);
339					}
340				}
341			}
342			else
343			{
344				HashSet<AudioSource>.Enumerator enumerator = m_sourcesPaused.GetEnumerator();
345				while (enumerator.MoveNext())
346				{
347					AudioSource current = enumerator.Current;
348					if (current != null)
349					{
350						if (!current.enabled)
351						{
352							current.enabled = true;
353						}
354						current.UnPause();
355					}
356				}
357				m_sourcesPaused.Clear();
358			}
359			if (this.PauseChanged != null)
360			{
361				this.PauseChanged(m_PlayerPaused);
362			}
363		}
364	}
