187		private void Save(string filename)
188		{
189			BinaryWriter binaryWriter = null;
190			try
191			{
192				binaryWriter = new BinaryWriter(File.Open(filename, FileMode.Create));
193			}
194			catch (Exception ex)
195			{
196				Debug.LogError("FAILED TO SAVE GLOBALVARIABLES Error = " + ex.Message);
197			}
198			if (binaryWriter != null)
199			{
200				binaryWriter.Write(1);
201				int count = m_data.Count;
202				binaryWriter.Write(count);
203				IDictionaryEnumerator enumerator = m_data.GetEnumerator();
204				int num = 0;
205				while (enumerator.MoveNext())
206				{
207					DictionaryEntry dictionaryEntry = (DictionaryEntry)enumerator.Current;
208					binaryWriter.Write((string)dictionaryEntry.Key);
209					binaryWriter.Write((int)dictionaryEntry.Value);
210					num++;
211				}
212				if (num != count)
213				{
214					Debug.LogError("NUMBER OF GLOBALS SAVED DOES NOT MATCH HASH TABLE COUNT! Saved = " + num + ", Table Count = " + count);
215				}
216				binaryWriter.Close();
217			}
218		}
