220		private void Load(string filename)
221		{
222			BinaryReader binaryReader = null;
223			if (!File.Exists(filename))
224			{
225				return;
226			}
227			try
228			{
229				binaryReader = new BinaryReader(File.Open(filename, FileMode.Open));
230			}
231			catch (Exception ex)
232			{
233				Debug.LogError("FAILED TO GLOBALVARIABLES Error = " + ex.Message);
234			}
235			if (binaryReader == null)
236			{
237				return;
238			}
239			m_data.Clear();
240			int num = binaryReader.ReadInt32();
241			if (num == 1)
242			{
243				int num2 = binaryReader.ReadInt32();
244				for (int i = 0; i < num2; i++)
245				{
246					string key = binaryReader.ReadString();
247					int num3 = binaryReader.ReadInt32();
248					m_data.Add(key, num3);
249				}
250			}
251			binaryReader.Close();
252		}
