296		{
297			//Discarded unreachable code: IL_0580
298			if (string.IsNullOrEmpty(command) || command.ToLower() == "runcommand")
299			{
300				return;
301			}
302			List<string> list = new List<string>();
303			if (command.Contains(","))
304			{
305				list.AddRange(command.Split(','));
306			}
307			else
308			{
309				list.Add(command);
310			}
311			foreach (string item in list)
312			{
313				List<string> list2 = new List<string>();
314				list2.AddRange(item.Split(' '));
315				bool flag = false;
316				string typeName = GameUtilities.Instance.TextHelper_GetAssemblyQualifiedName(GameUtilities.AssemblyQualifiedNameType.AQN_Game_CommandLine);
317				Type type = Type.GetType(typeName, throwOnError: true);
318				string typeName2 = GameUtilities.Instance.TextHelper_GetAssemblyQualifiedName(GameUtilities.AssemblyQualifiedNameType.AQN_Game_Scripts);
319				Type type2 = Type.GetType(typeName2, throwOnError: true);
320				IEnumerable<MethodInfo> methods;
321				if (GameState.CheatsEnabled)
322				{
323					methods = type.GetMethods(BindingFlags.Static | BindingFlags.Public | BindingFlags.FlattenHierarchy);
324					methods = methods.Concat(type2.GetMethods(BindingFlags.Static | BindingFlags.Public | BindingFlags.FlattenHierarchy));
325				}
326				else
327				{
328					methods = type.GetMethods(BindingFlags.Static | BindingFlags.Public | BindingFlags.FlattenHierarchy);
329				}
330				foreach (MethodInfo item2 in methods)
331				{
332					if (flag)
333					{
334						break;
335					}
336					if ((item2.GetCustomAttributes(typeof(CheatAttribute), inherit: true).Length > 0 && !GameState.CheatsEnabled) || string.Compare(item2.Name.ToLower(), list2[0].ToLower(), ignoreCase: true) != 0)
337					{
338						continue;
339					}
340					ParameterInfo[] parameters = item2.GetParameters();
341					if (parameters == null || parameters.Length != list2.Count - 1)
342					{
343						continue;
344					}
345					object[] array = new object[parameters.Length];
346					for (int i = 0; i < parameters.Length; i++)
347					{
348						Type type3 = GameUtilities.Instance.ScriptHelper_GetScriptAttributeType(i);
349						object[] customAttributes = item2.GetCustomAttributes(type3, inherit: false);
350						BrowserType browserType = BrowserType.None;
351						if (customAttributes.Length > 0)
352						{
353							browserType = (BrowserType)(int)type3.GetProperty("Browser").GetValue(customAttributes[0], null);
354						}
355						ParameterInfo parameterInfo = parameters[i];
356						if (parameterInfo.ParameterType.IsEnum)
357						{
358							try
359							{
360								array[i] = Enum.Parse(parameterInfo.ParameterType, list2[i + 1], ignoreCase: true);
361							}
362							catch
363							{
364								array[i] = Enum.GetValues(parameterInfo.ParameterType).GetValue(0);
365							}
366							continue;
367						}
368						if (browserType == BrowserType.ObjectGuid || parameterInfo.ParameterType == typeof(Guid))
369						{
370							try
371							{
