373							}
374							catch
375							{
376								GameObject gameObject = GameObject.Find(list2[i + 1]);
377								if ((bool)gameObject)
378								{
379									InstanceID component = gameObject.GetComponent<InstanceID>();
380									if ((bool)component)
381									{
382										array[i] = component.Guid;
383									}
384									else
385									{
386										array[i] = Guid.Empty;
387									}
388								}
389								else
390								{
391									array[i] = Guid.Empty;
392								}
393							}
394							continue;
395						}
396						switch (browserType)
397						{
398						case BrowserType.Quest:
399						{
400							List<string> list4 = QuestManager.Instance.FindLoadedQuests(list2[i + 1]);
401							if (list4.Count == 0)
402							{
403								array[i] = list2[i + 1];
404								continue;
405							}
406							if (list4.Count == 1)
407							{
408								array[i] = list4[0];
409								continue;
410							}
411							bool flag2 = false;
412							Console.AddMessage("Multiple quests matched search '" + list2[i + 1] + "':", Color.yellow);
413							foreach (string item3 in list4)
414							{
415								if (Path.GetFileNameWithoutExtension(item3).ToLower().Equals(list2[i + 1].ToLower()))
416								{
417									flag2 = true;
418									array[i] = item3;
419								}
420								Console.AddMessage(Path.GetFileNameWithoutExtension(item3), Color.yellow);
421							}
