426							}
427							return;
428						}
429						case BrowserType.Conversation:
430						{
431							List<string> list3 = ConversationManager.Instance.FindConversations(list2[i + 1]);
432							if (list3.Count == 0)
433							{
434								array[i] = list2[i + 1];
