461								return;
462							}
463						}
464						else
465						{
466							array[i] = list2[i + 1];
467						}
468					}
469					item2.Invoke(null, array);
470					flag = true;
471					break;
472				}
473				if (!flag)
474				{
475					Console.AddMessage("No command or script '" + list2[0] + "' accepting " + (list2.Count - 1) + " parameters exists.", Color.yellow);
476				}
477			}
478		}
